BANK = [{"name": "bk_batch_processing_nhieu", "when": "Batch Processing nhiều tập. Khi podcast có nhiều tập hay về cùng một t", "code": "ctx.save();const cx=W/2,cy=cursorY+420;\nconst tg=ctx.createLinearGradient(cx-300,0,cx+300,0);tg.addColorStop(0,'#38bdf8');tg.addColorStop(1,'#a855f7');\nctx.fillStyle=tg;ctx.font='bold 50px \"Inter\",sans-serif';ctx.textAlign='center';\nctx.save();ctx.shadowColor='rgba(56,189,248,0.4)';ctx.shadowBlur=16;\nctx.fillText('Batch Processing',cx,cursorY+110);ctx.restore();\nctx.fillStyle='rgba(56,189,248,0.8)';ctx.font='bold 28px monospace';\nctx.fillText('N episodes → parallel → merge → 1 skill',cx,cursorY+168);\nctx.strokeStyle='rgba(56,189,248,0.25)';ctx.lineWidth=1.5;\nctx.beginPath();ctx.moveTo(MX,cursorY+196);ctx.lineTo(W-MX,cursorY+196);ctx.stroke();\n// 4 episodes → merge\nconst eps=[{n:'Ep 301',guest:'Sam Altman',c:'#38bdf8'},{n:'Ep 302',guest:'Karpathy',c:'#a855f7'},{n:'Ep 319',guest:'Ilya Sutskever',c:'#22c55e'},{n:'Ep 331',guest:'Geoffrey Hinton',c:'#f472b6'}];\nconst er=200;\nfor(let i=0;i<4;i++){const e=eps[i];const ea=i*Math.PI*2/4-Math.PI/2;const ex=cx-200+Math.cos(ea)*er;const ey=cy+Math.sin(ea)*er*0.7;\n// Particle to center\nfor(let p=0;p<4;p++){const pt=((time*0.6+i*0.15+p/4)%1);const ppx=ex+(cx-200-ex)*pt;const ppy=ey+(cy-ey)*pt;const pa=Math.sin(pt*Math.PI)*0.85;ctx.fillStyle=`${e.c}${Math.floor(pa*255).toString(16).padStart(2,'0')}`;ctx.save();ctx.shadowColor=e.c;ctx.shadowBlur=9;ctx.beginPath();ctx.arc(ppx,ppy,4,0,Math.PI*2);ctx.fill();ctx.restore();}\nconst eg=ctx.createRadialGradient(ex,ey,0,ex,ey,52);eg.addColorStop(0,e.c+'20');eg.addColorStop(1,'rgba(8,15,35,0.97)');\nctx.fillStyle=eg;ctx.strokeStyle=e.c;ctx.lineWidth=2.5;\nctx.save();ctx.shadowColor=e.c;ctx.shadowBlur=18;\nctx.beginPath();ctx.arc(ex,ey,50,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=e.c;ctx.font='bold 20px monospace';ctx.textAlign='center';ctx.fillText(e.n,ex,ey+4);\nctx.fillStyle='rgba(148,163,184,0.65)';ctx.font='16px monospace';ctx.fillText(e.guest,ex,ey+26);}\n// Merge node\nfor(let r=0;r<3;r++){const rp=(time*0.8+r*0.33)%1;ctx.strokeStyle=`rgba(168,85,247,${0.35*(1-rp)})`;ctx.lineWidth=2;ctx.beginPath();ctx.arc(cx-200,cy,56+rp*48,0,Math.PI*2);ctx.stroke();}\nconst mg=ctx.createRadialGradient(cx-200,cy,0,cx-200,cy,56);mg.addColorStop(0,'rgba(168,85,247,0.22)');mg.addColorStop(1,'rgba(5,12,35,0.98)');\nctx.fillStyle=mg;ctx.strokeStyle='#a855f7';ctx.lineWidth=3.5;\nctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=28;\nctx.beginPath();ctx.arc(cx-200,cy,54,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();\nctx.font='38px sans-serif';ctx.textAlign='center';ctx.fillText('🔗',cx-200,cy+14);\nctx.fillStyle='#a855f7';ctx.font='bold 20px monospace';ctx.fillText('MERGE',cx-200,cy+50);\n// Output skill\nconst oa=0.7+0.3*Math.sin(time*2);\nctx.fillStyle='rgba(12,22,44,0.97)';ctx.strokeStyle=`rgba(34,197,94,${oa})`;ctx.lineWidth=3;\nctx.save();ctx.shadowColor=`rgba(34,197,94,${oa*0.4})`;ctx.shadowBlur=18;\nctx.beginPath();ctx.roundRect(cx+50,cy-70,340,140,14);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('green');ctx.font='bold 22px monospace';\nctx.fillText('📋 skill/lex_ai_series',cx+220,cy-32);\nctx.fillStyle='rgba(200,200,200,0.8)';ctx.font='20px monospace';\nctx.fillText('4 episodes merged',cx+220,cy-4);\nctx.fillText('31 unique insights',cx+220,cy+24);\nctx.fillStyle='rgba(148,163,184,0.65)';ctx.font='18px monospace';\nctx.fillText('deduped: 8 removed',cx+220,cy+50);\nctx.restore();return 1100;"},
    {"name": "bk_duc_ket_module", "when": "Đúc kết Bài 14 và Module 4. Monitoring: 5 health signals hàng ngày, dr", "code": "const logoPath='/api/v1/edu_video/gallery/file/logo_tubecreate.png';\nif(typeof window!=='undefined'&&typeof _loadPreviewImage==='function'){_loadPreviewImage(logoPath);}\nctx.save();ctx.beginPath();ctx.rect(0,cursorY,W,580);ctx.clip();\nconst cx=W/2;\n// Celebration: rainbow particles\nfor(let i=0;i<36;i++){const a=i*Math.PI*2/36+time*0.4;const r2=260+Math.sin(time*0.7+i)*70;const sx=cx+Math.cos(a)*r2;const sy=cursorY+260+Math.sin(a)*170;const hue=(i*10+time*30)%360;const sa=0.1+0.12*Math.abs(Math.sin(time*0.5+i*0.618));ctx.fillStyle=`hsla(${hue},80%,65%,${sa})`;ctx.beginPath();ctx.arc(sx,sy,2+Math.sin(time+i)*0.8,0,Math.PI*2);ctx.fill();}\nconst weightY=cursorY+255;\nlet scale=0;\nif(stepProgress<0.45){const t=stepProgress/0.45;scale=1-Math.pow(1-t,3.5)*Math.cos(t*Math.PI*2.8);}else{scale=1+0.015*Math.sin(time*2.5);}\nconst img=(typeof window!=='undefined'&&window._PREVIEW_IMG_CACHE&&window._PREVIEW_IMG_CACHE[logoPath])||(typeof global!=='undefined'&&global.IMAGE_CACHE&&global.IMAGE_CACHE[logoPath]);\nif(img){ctx.save();ctx.translate(cx,weightY-50);ctx.scale(scale,scale);ctx.drawImage(img,-90,-90,180,180);ctx.restore();}\nlet ta=Math.min(1,Math.max(0,(stepProgress-0.4)*3.5));\nconst tg2=ctx.createLinearGradient(cx-220,0,cx+220,0);tg2.addColorStop(0,'#22c55e');tg2.addColorStop(0.33,'#38bdf8');tg2.addColorStop(0.66,'#a855f7');tg2.addColorStop(1,'#f472b6');\nctx.font='bold 48px \"Outfit\",\"Inter\",sans-serif';ctx.fillStyle=tg2;ctx.textAlign='center';\nctx.save();ctx.globalAlpha=ta;ctx.shadowColor='rgba(34,197,94,0.7)';ctx.shadowBlur=20;\nctx.fillText('TubeCreate',cx,weightY+80);ctx.shadowBlur=0;ctx.restore();\nconst ta2=Math.min(1,Math.max(0,(stepProgress-0.6)*4));\nif(ta2>0){ctx.save();ctx.globalAlpha=ta2;\nctx.fillStyle='rgba(8,16,36,0.95)';ctx.lineWidth=2;\nctx.save();ctx.shadowColor='rgba(34,197,94,0.3)';ctx.shadowBlur=16;\nconst borderG3=ctx.createLinearGradient(cx-300,0,cx+300,0);borderG3.addColorStop(0,'rgba(22,197,94,0.7)');borderG3.addColorStop(0.33,'rgba(56,189,248,0.7)');borderG3.addColorStop(0.66,'rgba(168,85,247,0.7)');borderG3.addColorStop(1,'rgba(244,114,182,0.7)');\nctx.strokeStyle=borderG3;\nctx.beginPath();ctx.roundRect(cx-300,weightY+110,600,108,16);ctx.fill();ctx.stroke();ctx.restore();\nconst tBg=ctx.createLinearGradient(cx-280,0,cx+280,0);tBg.addColorStop(0,'rgba(22,197,94,0.12)');tBg.addColorStop(0.5,'rgba(56,189,248,0.12)');tBg.addColorStop(1,'rgba(244,114,182,0.12)');\nctx.fillStyle=tBg;ctx.beginPath();ctx.roundRect(cx-300,weightY+110,600,108,16);ctx.fill();\nctx.fillStyle='rgba(148,163,184,0.75)';ctx.font='bold 18px monospace';ctx.textAlign='center';\nctx.fillText('✅ MODULE 4 COMPLETE',cx,weightY+138);\nconst mdG=ctx.createLinearGradient(cx-260,0,cx+260,0);mdG.addColorStop(0,'#22c55e');mdG.addColorStop(0.5,'#38bdf8');mdG.addColorStop(1,'#f472b6');\nctx.fillStyle=mdG;ctx.font='bold 22px monospace';\nctx.fillText('Module 5: Advanced Extraction Techniques',cx,weightY+168);\nctx.fillStyle='rgba(148,163,184,0.65)';ctx.font='18px monospace';\nctx.fillText('Video, podcast, slide deck — extract không chỉ từ sách',cx,weightY+196);\nctx.restore();}\nctx.restore();"},
    {"name": "bk_stage_hinh_ngon", "when": "Stage 3: mô hình ngôn ngữ lớn Extract — trái tim của pipeline. Mỗi chu", "code": "ctx.save();const cx=W/2,cy=cursorY+480;const tg=ctx.createLinearGradient(cx-300,0,cx+300,0);tg.addColorStop(0,'#eab308');tg.addColorStop(1,'#ef4444');ctx.fillStyle=tg;ctx.font='bold 28px monospace';ctx.textAlign='center';ctx.fillText('STAGE 3',cx,cursorY+55);ctx.fillStyle='#fff';ctx.font='bold 50px \"Inter\",sans-serif';ctx.save();ctx.shadowColor='rgba(234,179,8,0.4)';ctx.shadowBlur=16;ctx.fillText('LLM Extract',cx,cursorY+118);ctx.restore();ctx.fillStyle='#eab308';ctx.font='bold 28px monospace';ctx.fillText('Parallel × 4 — structured output',cx,cursorY+172);ctx.strokeStyle='rgba(234,179,8,0.25)';ctx.lineWidth=1.5;ctx.beginPath();ctx.moveTo(MX,cursorY+196);ctx.lineTo(W-MX,cursorY+196);ctx.stroke();for(let r=0;r<4;r++){const rp=(time*0.8+r*0.25)%1;const rR=50+rp*70;const rA=0.4*(1-rp);const hue=(r*90+time*40)%360;ctx.strokeStyle=`hsla(${hue},80%,60%,${rA})`;ctx.lineWidth=2.5;ctx.beginPath();ctx.arc(cx,cy,rR,0,Math.PI*2);ctx.stroke();}const bg=ctx.createRadialGradient(cx,cy,0,cx,cy,70);bg.addColorStop(0,'rgba(40,20,80,0.98)');bg.addColorStop(1,'rgba(10,5,25,0.98)');ctx.fillStyle=bg;ctx.strokeStyle='#eab308';ctx.lineWidth=4;ctx.save();ctx.shadowColor='#eab308';ctx.shadowBlur=32;ctx.beginPath();ctx.arc(cx,cy,66,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();ctx.font='52px sans-serif';ctx.textAlign='center';ctx.fillText('🧠',cx,cy+18);ctx.fillStyle=tg;ctx.font='bold 24px monospace';ctx.fillText('LLM',cx,cy+60);const chunkAngles=[-Math.PI*0.95,-Math.PI*0.8,-Math.PI*0.65,-Math.PI*0.5];const chunkCols=['#38bdf8','#a855f7','#22c55e','#f472b6'];for(let i=0;i<4;i++){const a=chunkAngles[i];const sx=cx+Math.cos(a)*340;const sy=cy+Math.sin(a)*180;ctx.fillStyle='rgba(12,22,44,0.97)';ctx.strokeStyle=chunkCols[i];ctx.lineWidth=2;ctx.save();ctx.shadowColor=chunkCols[i];ctx.shadowBlur=10;ctx.beginPath();ctx.roundRect(sx-70,sy-32,140,64,10);ctx.fill();ctx.stroke();ctx.restore();ctx.fillStyle=chunkCols[i];ctx.font='bold 20px monospace';ctx.fillText('Chunk '+String.fromCharCode(65+i),sx,sy+6);const pt=(time*1.2+i*0.25)%1;const dotX=sx+(cx-sx)*pt;const dotY=sy+(cy-sy)*pt;const da=Math.sin(pt*Math.PI)*0.9;ctx.fillStyle=`${chunkCols[i]}${Math.floor(da*255).toString(16).padStart(2,'0')}`;ctx.save();ctx.shadowColor=chunkCols[i];ctx.shadowBlur=14;ctx.beginPath();ctx.arc(dotX,dotY,6,0,Math.PI*2);ctx.fill();ctx.restore();}const outAngles=[-Math.PI*0.05,Math.PI*0.1,Math.PI*0.25,Math.PI*0.4];for(let i=0;i<4;i++){const a=outAngles[i];const sx=cx+Math.cos(a)*340;const sy=cy+Math.sin(a)*180;const pt=((time*1.2+i*0.25)%1);if(pt>0.5){const pa=Math.sin((pt-0.5)*Math.PI*2)*0.9;const odx=cx+(sx-cx)*(pt-0.5)*2;const ody=cy+(sy-cy)*(pt-0.5)*2;ctx.fillStyle=`rgba(34,197,94,${pa})`;ctx.save();ctx.shadowColor='rgba(34,197,94,0.6)';ctx.shadowBlur=10;ctx.beginPath();ctx.arc(odx,ody,5,0,Math.PI*2);ctx.fill();ctx.restore();}ctx.fillStyle='rgba(12,22,44,0.97)';ctx.strokeStyle='rgba(34,197,94,0.5)';ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(sx-70,sy-32,140,64,10);ctx.fill();ctx.stroke();ctx.fillStyle=rc('green');ctx.font='bold 18px monospace';ctx.textAlign='center';ctx.fillText('ch'+('0'+(i+1)).slice(-2)+'.extracted',sx,sy-8);ctx.fillStyle='rgba(148,163,184,0.6)';ctx.font='16px monospace';ctx.fillText('✓ structured',sx,sy+14);}ctx.fillStyle='rgba(234,179,8,0.7)';ctx.font='bold 26px monospace';ctx.textAlign='center';ctx.fillText('4× parallel — rate-limited để tránh throttle',cx,cy+240);ctx.restore();return 1100;"},
    {"name": "bk_chot_lai_dinh", "when": "Chốt lại, Định tuyến và Khóa phiên là bộ khung giúp OpenClaw vận hành ", "code": "ctx.save();\nctx.beginPath();ctx.rect(0,cursorY,W,650);ctx.clip();\nconst cx=W/2,cy=cursorY+310;\nfor(let y=cursorY;y<cursorY+650;y+=3){ctx.fillStyle='rgba(0,0,0,0.04)';ctx.fillRect(0,y,W,1);}\nfor(let i=0;i<20;i++){const sx=cx+Math.sin(time*0.3+i*1.7)*(W*0.45);const sy=cursorY+((time*10+i*30)%650);const c=i%3===0?'255,215,0':i%3===1?'34,211,238':'167,139,250';ctx.fillStyle=`rgba(${c},${0.1+0.2*Math.sin(time*2+i)})`;ctx.fillRect(sx,sy,4,4);}\n// Summary Reactor Core (Center)\nctx.fillStyle='rgba(15,23,42,0.98)';ctx.strokeStyle='#10b981';ctx.lineWidth=3.5;\nctx.shadowColor='#10b981';ctx.shadowBlur=32;\nctx.beginPath();ctx.arc(cx,cy-30,75,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.shadowBlur=0;\n// Glowing Shield inside\nctx.strokeStyle='#10b981';ctx.lineWidth=2.5;ctx.beginPath();ctx.arc(cx,cy-30,55,0,Math.PI*2);ctx.stroke();\nconst rot=time*0.5;\nctx.fillStyle='#10b981'+'30';\nctx.beginPath();ctx.moveTo(cx+Math.cos(rot)*55,cy-30+Math.sin(rot)*55);\nctx.lineTo(cx+Math.cos(rot+Math.PI*2/3)*55,cy-30+Math.sin(rot+Math.PI*2/3)*55);\nctx.lineTo(cx+Math.cos(rot+Math.PI*4/3)*55,cy-30+Math.sin(rot+Math.PI*4/3)*55);\nctx.closePath();ctx.fill();\nctx.font='bold 24px monospace';ctx.fillStyle='#10b981';ctx.textAlign='center';ctx.textBaseline='middle';\nctx.fillText('CORE',cx,cy-30);\n// Surrounding satellite modules\nconst items=[{label:'ROUTING',sub:'Định tuyến chuẩn',c:'#FFD700',a:-Math.PI/2-0.5},{label:'SESSIONS',sub:'Bảo mật cuộc gọi',c:'#22d3ee',a:-Math.PI/2+0.5},{label:'PIPELINE',sub:'Luồng mượt mà',c:'#a78bfa',a:Math.PI/2}];\nitems.forEach((it,idx)=>{\nconst nx=cx+Math.cos(it.a)*320;\nconst ny=cy-20+Math.sin(it.a)*210;\nctx.strokeStyle='rgba(255,255,255,0.06)';ctx.lineWidth=1.5;ctx.setLineDash([5,5]);\nctx.beginPath();ctx.moveTo(cx,cy-30);ctx.lineTo(nx,ny);ctx.stroke();ctx.setLineDash([]);\nconst dp=(time*0.2+idx*0.33)%1;\nconst dx2=cx+(nx-cx)*dp;const dy2=(cy-30)+(ny-(cy-30))*dp;\nctx.fillStyle=it.c;ctx.shadowColor=it.c;ctx.shadowBlur=12;\nctx.beginPath();ctx.arc(dx2,dy2,5,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0;\nctx.fillStyle='rgba(15,23,42,0.95)';ctx.strokeStyle=it.c;ctx.lineWidth=2.5;\nctx.shadowColor=it.c;ctx.shadowBlur=12;\nctx.beginPath();ctx.rect(nx-80,ny-50,160,100);ctx.fill();ctx.stroke();\nctx.shadowBlur=0;\nfor(let px=nx-74;px<nx+74;px+=9){for(let py=ny-44;py<ny+44;py+=9){ctx.fillStyle=it.c+'08';ctx.fillRect(px,py,5,5);}}\nctx.font='bold 18px monospace';ctx.fillStyle=it.c;ctx.textAlign='center';ctx.textBaseline='middle';\nctx.fillText(it.label,nx,ny-12);\nctx.font='13px monospace';ctx.fillStyle=it.c+'aa';\nctx.fillText(it.sub,nx,ny+20);\n});\nctx.shadowColor='#10b981';ctx.shadowBlur=22;\nctx.font='bold 24px monospace';ctx.fillStyle='#10b981';ctx.textAlign='center';\nctx.fillText('[ BÀI 6 HOÀN THÀNH - 100% ]',cx,cy+240);\nctx.shadowBlur=0;\nctx.font='15px monospace';ctx.fillStyle='#555';\nctx.fillText('NEXT BÀI 7: Channel Adapters',cx,cy+275);\nctx.restore();"},
    {"name": "bk_module_advanced_extraction", "when": "Module 5: Advanced Extraction Techniques. Sách không phải nguồn duy nh", "code": "ctx.save();const cx=W/2,cy=cursorY+420;\nconst tg=ctx.createLinearGradient(cx-400,0,cx+400,0);tg.addColorStop(0,'#ef4444');tg.addColorStop(0.33,'#f472b6');tg.addColorStop(0.66,'#a855f7');tg.addColorStop(1,'#38bdf8');\nctx.fillStyle='rgba(239,68,68,0.9)';ctx.font='bold 28px monospace';ctx.textAlign='center';\nctx.fillText('MODULE 5 — BÀI 15',cx,cursorY+55);\nctx.fillStyle=tg;ctx.font='bold 50px \"Inter\",sans-serif';\nctx.save();ctx.shadowColor='rgba(239,68,68,0.5)';ctx.shadowBlur=20;\nctx.fillText('Extract từ YouTube Video',cx,cursorY+118);ctx.restore();\nctx.fillStyle='rgba(148,163,184,0.85)';ctx.font='bold 28px monospace';\nctx.fillText('Transcript → Timestamps → Skill',cx,cursorY+174);\nctx.strokeStyle='rgba(239,68,68,0.25)';ctx.lineWidth=1.5;\nctx.beginPath();ctx.moveTo(MX,cursorY+196);ctx.lineTo(W-MX,cursorY+196);ctx.stroke();\n// YouTube-style player visual\nconst playerW=720,playerH=260,playerX=cx-playerW/2,playerY=cy-145;\nconst pg=ctx.createLinearGradient(playerX,playerY,playerX,playerY+playerH);pg.addColorStop(0,'rgba(20,20,30,0.99)');pg.addColorStop(1,'rgba(10,10,20,0.99)');\nctx.fillStyle=pg;ctx.strokeStyle='rgba(239,68,68,0.6)';ctx.lineWidth=3;\nctx.save();ctx.shadowColor='rgba(239,68,68,0.3)';ctx.shadowBlur=22;\nctx.beginPath();ctx.roundRect(playerX,playerY,playerW,playerH,16);ctx.fill();ctx.stroke();ctx.restore();\n// Play animation\nconst pa=0.7+0.3*Math.sin(time*2);\nctx.fillStyle=`rgba(239,68,68,${pa})`;\nctx.save();ctx.shadowColor='#ef4444';ctx.shadowBlur=28;\nctx.beginPath();ctx.moveTo(cx-28,playerY+playerH/2-34);ctx.lineTo(cx-28,playerY+playerH/2+34);ctx.lineTo(cx+40,playerY+playerH/2);ctx.closePath();ctx.fill();ctx.restore();\n// Video title\nctx.fillStyle='rgba(255,255,255,0.85)';ctx.font='bold 20px monospace';ctx.textAlign='left';\nctx.fillText('\"Attention Is All You Need\" — NeurIPS 2017',playerX+12,playerY+22);\nctx.fillStyle='rgba(148,163,184,0.65)';ctx.font='18px monospace';\nctx.fillText('Google Brain  •  1:07:34  •  2.4M views',playerX+12,playerY+46);\n// Progress bar\nconst prog=((time*0.05)%1);\nctx.fillStyle='rgba(255,255,255,0.1)';ctx.beginPath();ctx.roundRect(playerX+12,playerY+playerH-28,playerW-24,6,3);ctx.fill();\nctx.fillStyle='#ef4444';ctx.beginPath();ctx.roundRect(playerX+12,playerY+playerH-28,prog*(playerW-24),6,3);ctx.fill();\nctx.fillStyle='rgba(255,255,255,0.7)';ctx.font='16px monospace';\nconst m=Math.floor(prog*67),s=Math.floor((prog*67*60)%60);ctx.textAlign='right';\nctx.fillText(`${m}:${s.toString().padStart(2,'0')} / 1:07:34`,playerX+playerW-12,playerY+playerH-32);\n// 3 sources visual below\nconst srcs=[{n:'NeurIPS Talks',icon:'🎓',c:'#ef4444'},{n:'YouTube Edu',icon:'📺',c:'#f472b6'},{n:'Conference Vids',icon:'🎤',c:'#a855f7'}];\nfor(let i=0;i<3;i++){const s=srcs[i];const sx=cx-240+i*240;const sy=cy+120;\nconst sg=ctx.createRadialGradient(sx,sy,0,sx,sy,52);sg.addColorStop(0,s.c+'22');sg.addColorStop(1,'rgba(8,15,35,0.97)');\nctx.fillStyle=sg;ctx.strokeStyle=s.c+'80';ctx.lineWidth=2;\nctx.beginPath();ctx.arc(sx,sy,50,0,Math.PI*2);ctx.fill();ctx.stroke();\nctx.font='34px sans-serif';ctx.textAlign='center';ctx.fillText(s.icon,sx,sy+12);\nctx.fillStyle=s.c;ctx.font='bold 18px monospace';ctx.fillText(s.n,sx,sy+46);}\nconst qa=0.7+0.3*Math.sin(time*2);\nctx.fillStyle=`rgba(239,68,68,${qa})`;ctx.font='bold 24px monospace';\nctx.fillText('Best insights thường trong talks — không trong sách',cx,cy+240);\nctx.restore();return 1100;"},
    {"name": "bk_agent_nhan_user", "when": "Agent nhận user query — nhưng có 19 skills. Làm sao biết query này thu", "code": "ctx.save();const cx=W/2,cy=cursorY+420;\nconst tg=ctx.createLinearGradient(cx-400,0,cx+400,0);tg.addColorStop(0,'#06b6d4');tg.addColorStop(0.5,'#3b82f6');tg.addColorStop(1,'#8b5cf6');\nctx.fillStyle='rgba(6,182,212,0.9)';ctx.font='bold 28px monospace';ctx.textAlign='center';\nctx.fillText('MODULE 6 — BÀI 21',cx,cursorY+55);\nctx.fillStyle=tg;ctx.font='bold 50px \"Inter\",sans-serif';\nctx.save();ctx.shadowColor='rgba(6,182,212,0.5)';ctx.shadowBlur=20;\nctx.fillText('Query Routing & Skill Selection',cx,cursorY+118);ctx.restore();\nctx.fillStyle='rgba(148,163,184,0.85)';ctx.font='bold 28px monospace';\nctx.fillText('Classify → Route → Fetch exact skill',cx,cursorY+174);\nctx.strokeStyle='rgba(6,182,212,0.25)';ctx.lineWidth=1.5;\nctx.beginPath();ctx.moveTo(MX,cursorY+196);ctx.lineTo(W-MX,cursorY+196);ctx.stroke();\n// Before/after comparison\nconst ba1=0.6+0.4*Math.abs(Math.sin(time*1.5));\nctx.fillStyle='rgba(12,22,44,0.97)';ctx.strokeStyle=`rgba(239,68,68,${ba1})`;ctx.lineWidth=2;\nctx.beginPath();ctx.roundRect(cx-430,cy-145,400,220,14);ctx.fill();ctx.stroke();\nctx.fillStyle='rgba(239,68,68,0.8)';ctx.font='bold 24px monospace';ctx.textAlign='center';\nctx.fillText('❌ Without Routing',cx-230,cy-115);\nctx.fillStyle='rgba(200,200,200,0.7)';ctx.font='19px monospace';\nconst noRoute=['Load ALL 19 skills','Context: ~180K tokens','85% irrelevant content','Slow + expensive'];\nfor(let i=0;i<4;i++)ctx.fillText(noRoute[i],cx-230,cy-80+i*38);\n// With routing\nconst ba2=0.6+0.4*Math.abs(Math.sin(time*1.5+0.7));\nctx.fillStyle='rgba(12,22,44,0.97)';ctx.strokeStyle=`rgba(34,197,94,${ba2})`;ctx.lineWidth=2;\nctx.beginPath();ctx.roundRect(cx+32,cy-145,400,220,14);ctx.fill();ctx.stroke();\nctx.fillStyle='rgba(34,197,94,0.8)';ctx.font='bold 24px monospace';\nctx.fillText('✅ With Routing',cx+232,cy-115);\nconst withRoute=['Load 1-2 matched skills','Context: ~12K tokens','95% relevant content','Fast + cheap'];\nfor(let i=0;i<4;i++){ctx.fillStyle=i<3?rc('green'):'rgba(34,197,94,0.8)';ctx.font='bold 19px monospace';\nctx.fillText(withRoute[i],cx+232,cy-80+i*38);}\n// vs arrow\nconst va2=0.7+0.3*Math.sin(time*2);ctx.fillStyle=`rgba(234,179,8,${va2})`;ctx.font='bold 36px monospace';\nctx.fillText('VS',cx-6,cy-30);\n// Savings\nconst qa=0.7+0.3*Math.sin(time*2);\nconst sg6=ctx.createLinearGradient(cx-430,0,cx+430,0);sg6.addColorStop(0,'rgba(6,182,212,0.1)');sg6.addColorStop(1,'rgba(34,197,94,0.1)');\nctx.fillStyle='rgba(5,15,40,0.99)';ctx.strokeStyle=`rgba(34,197,94,${qa})`;ctx.lineWidth=2.5;\nctx.save();ctx.shadowColor=`rgba(34,197,94,${qa*0.4})`;ctx.shadowBlur=14;\nctx.beginPath();ctx.roundRect(cx-430,cy+94,860,80,14);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=sg6;ctx.beginPath();ctx.roundRect(cx-430,cy+94,860,80,14);ctx.fill();\nctx.fillStyle=rc('green');ctx.font='bold 28px monospace';\nctx.fillText('Routing: 180K → 12K tokens — 93% reduction in context cost',cx,cy+142);\nconst qa2=0.6+0.4*Math.sin(time*2.5);\nctx.fillStyle='rgba(148,163,184,0.7)';ctx.font='22px monospace';\nctx.fillText('Correct skill loaded: 97% accuracy with embedding-based routing',cx,cy+170);\nctx.restore();return 1100;"},
    {"name": "bk_chuong_duy_nen", "when": "Chào mừng các bạn đến với Chương 1: Tư duy nền tảng. Bài 1: Người phản", "code": "ctx.save();const cx=W/2,cy=cursorY+420;\nfor(let i=0;i<12;i++){const px=(Math.sin(i*9.7+time*.08)*.5+.5)*W,py=cursorY+((i*88+time*20)%1050);ctx.fillStyle=`rgba(255,255,255,${.08+.05*Math.sin(time+i)})`;ctx.beginPath();ctx.arc(px,py,1.2+Math.sin(time+i)*.6,0,Math.PI*2);ctx.fill();}\nctx.textAlign='center';ctx.fillStyle='rgba(147,197,253,.75)';ctx.font='bold 20px monospace';ctx.fillText('MODULE 1  ·  BÀI 1',cx,cursorY+60);\nctx.fillStyle='rgba(255,255,255,.98)';ctx.font='bold 56px sans-serif';ctx.save();ctx.shadowColor='rgba(147,197,253,.45)';ctx.shadowBlur=20;ctx.fillText('Reviewer Mindset',cx,cursorY+130);ctx.restore();\nctx.fillStyle='rgba(255,255,255,.52)';ctx.font='22px monospace';ctx.fillText('Nhìn bài báo từ phía người chấm điểm',cx,cursorY+172);\nctx.strokeStyle='rgba(255,255,255,.10)';ctx.lineWidth=1;ctx.beginPath();ctx.moveTo(cx-380,cursorY+196);ctx.lineTo(cx+380,cursorY+196);ctx.stroke();\n\nconst cenX=cx,cenY=cy+10;\nconst nodes=[\n  {n:'Đề tài thực tiễn',icon:'🔍',c:'#f472b6',x:cx-260,y:cy-110},\n  {n:'Giải pháp độc đáo',icon:'⚙',c:'#38bdf8',x:cx+260,y:cy-110},\n  {n:'Dẫn dắt thuyết phục',icon:'📖',c:'#eab308',x:cx-260,y:cy+130},\n  {n:'Trình bày chuyên nghiệp',icon:'🎨',c:'#22c55e',x:cx+260,y:cy+130}\n];\nconst actIdx=Math.floor(time*.75)%4;\n\nfor(let i=0;i<4;i++){\n  const nd=nodes[i];\n  ctx.strokeStyle=nd.c+'30';ctx.lineWidth=2;\n  ctx.beginPath();ctx.moveTo(cenX,cenY);ctx.lineTo(nd.x,nd.y);ctx.stroke();\n  const pt=(time*0.5+i*0.25)%1;\n  const px=cenX+(nd.x-cenX)*pt;\n  const py=cenY+(nd.y-cenY)*pt;\n  const pa=Math.sin(pt*Math.PI)*0.8;\n  ctx.fillStyle=nd.c;ctx.save();ctx.shadowColor=nd.c;ctx.shadowBlur=12;\n  ctx.beginPath();ctx.arc(px,py,6,0,Math.PI*2);ctx.fill();ctx.restore();\n}\n\nconst cr=58;\nfor(let r=0;r<2;r++){const rp=(time*0.7+r*0.5)%1;ctx.strokeStyle=`rgba(168,85,247,${0.3*(1-rp)})`;ctx.lineWidth=1.5;ctx.beginPath();ctx.arc(cenX,cenY,cr+rp*40,0,Math.PI*2);ctx.stroke();}\nconst cg=ctx.createRadialGradient(cenX,cenY,0,cenX,cenY,cr);cg.addColorStop(0,'rgba(168,85,247,0.3)');cg.addColorStop(1,'rgba(8,15,35,0.95)');\nctx.fillStyle=cg;ctx.strokeStyle='#a855f7';ctx.lineWidth=3.5;\nctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=24;\nctx.beginPath();ctx.arc(cenX,cenY,cr,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle='#fff';ctx.font='bold 22px monospace';ctx.textAlign='center';ctx.fillText('REVIEWER',cenX,cenY-6);ctx.fillStyle='rgba(255,255,255,0.7)';ctx.font='16px monospace';ctx.fillText('MINDSET',cenX,cenY+16);\n\nfor(let i=0;i<4;i++){\n  const nd=nodes[i];const isA=i===actIdx;\n  const sr=isA?65:55;\n  if(isA){\n    for(let r=0;r<2;r++){const rp=(time*0.9+r*0.5)%1;ctx.strokeStyle=`${nd.c}${Math.floor((0.3*(1-rp))*255).toString(16).padStart(2,'0')}`;ctx.lineWidth=2;ctx.beginPath();ctx.arc(nd.x,nd.y,sr+rp*44,0,Math.PI*2);ctx.stroke();}\n  }\n  const sg=ctx.createRadialGradient(nd.x,nd.y,0,nd.x,nd.y,sr);sg.addColorStop(0,nd.c+'20');sg.addColorStop(1,'rgba(8,15,35,0.96)');\n  ctx.fillStyle=sg;ctx.strokeStyle=isA?nd.c:nd.c+'60';ctx.lineWidth=isA?3.5:2;\n  ctx.save();if(isA){ctx.shadowColor=nd.c;ctx.shadowBlur=24;}\n  ctx.beginPath();ctx.arc(nd.x,nd.y,sr,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();\n  ctx.font='36px sans-serif';ctx.textAlign='center';ctx.fillText(nd.icon,nd.x,nd.y+11);\n  ctx.fillStyle=isA?'#fff':nd.c;ctx.font=isA?'bold 20px monospace':'18px monospace';ctx.fillText(nd.n,nd.x,nd.y+sr+28);\n}\nctx.textAlign='center';ctx.fillStyle='rgba(255,255,255,.32)';ctx.font='20px monospace';ctx.fillText('Thiếu bất kỳ trục nào → reject',cx,cy+265);\nctx.restore();return 1100;"},
    {"name": "bk_buc_tranh_toan", "when": "Bài này là bức tranh toàn cảnh. Bạn có một file PDF. Bốn mươi phút sau", "code": "ctx.save();const cx=W/2,cy=cursorY+420;const tg=ctx.createLinearGradient(cx-400,0,cx+400,0);tg.addColorStop(0,'#38bdf8');tg.addColorStop(0.25,'#a855f7');tg.addColorStop(0.5,'#eab308');tg.addColorStop(0.75,'#22c55e');tg.addColorStop(1,'#f472b6');ctx.fillStyle='#fff';ctx.font='bold 28px monospace';ctx.textAlign='center';ctx.fillText('MODULE 2 — BÀI 6',cx,cursorY+55);ctx.fillStyle=tg;ctx.font='bold 50px \"Inter\",sans-serif';ctx.save();ctx.shadowColor='rgba(56,189,248,0.5)';ctx.shadowBlur=20;ctx.fillText('End-to-End Pipeline',cx,cursorY+118);ctx.restore();ctx.fillStyle='rgba(148,163,184,0.8)';ctx.font='bold 28px monospace';ctx.fillText('PDF → Skill File trong 40 phút',cx,cursorY+174);ctx.strokeStyle='rgba(56,189,248,0.25)';ctx.lineWidth=1.5;ctx.beginPath();ctx.moveTo(MX,cursorY+196);ctx.lineTo(W-MX,cursorY+196);ctx.stroke();const stages=[{l:'PARSE',icon:'📄',c:'#38bdf8'},{l:'CHUNK',icon:'✂️',c:'#a855f7'},{l:'EXTRACT',icon:'⚡',c:'#eab308'},{l:'COMPILE',icon:'🔧',c:'#22c55e'},{l:'VALIDATE',icon:'✅',c:'#f472b6'}];const stW=110,stH=110,stSpacing=160;const sy=cy+60;for(let i=0;i<stages.length;i++){const s=stages[i];const sx=cx-(stages.length-1)*stSpacing/2+i*stSpacing;if(i<stages.length-1){const nx=sx+stW/2-10;const nnx=cx-(stages.length-1)*stSpacing/2+(i+1)*stSpacing-stW/2+10;ctx.strokeStyle=s.c+'40';ctx.lineWidth=3;ctx.beginPath();ctx.moveTo(nx,sy);ctx.lineTo(nnx,sy);ctx.stroke();for(let p=0;p<5;p++){const pt=((time*0.6+i/5+p/5)%1);const px=nx+(nnx-nx)*pt;const pa=Math.sin(pt*Math.PI)*0.95;ctx.fillStyle=`${s.c}${Math.floor(pa*255).toString(16).padStart(2,'0')}`;ctx.save();ctx.shadowColor=s.c;ctx.shadowBlur=12;ctx.beginPath();ctx.arc(px,sy,5,0,Math.PI*2);ctx.fill();ctx.restore();}}const isAct=Math.floor(time*0.5)%5===i;if(isAct){for(let r=0;r<3;r++){const rp=(time*1.5+r*0.33)%1;ctx.strokeStyle=`${s.c}${Math.floor((0.5*(1-rp))*255).toString(16).padStart(2,'0')}`;ctx.lineWidth=2;ctx.beginPath();ctx.arc(sx,sy,stH/2+rp*24,0,Math.PI*2);ctx.stroke();}}const ng=ctx.createRadialGradient(sx,sy,0,sx,sy,stH/2);ng.addColorStop(0,'rgba(15,25,50,0.97)');ng.addColorStop(1,'rgba(5,10,25,0.97)');ctx.fillStyle=ng;ctx.strokeStyle=isAct?s.c:s.c+'60';ctx.lineWidth=isAct?4:2;ctx.save();if(isAct){ctx.shadowColor=s.c;ctx.shadowBlur=30;}ctx.beginPath();ctx.arc(sx,sy,stH/2,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();ctx.font='38px sans-serif';ctx.textAlign='center';ctx.fillText(s.icon,sx,sy+12);ctx.fillStyle=isAct?s.c:'rgba(200,200,200,0.7)';ctx.font='bold 18px monospace';ctx.fillText(s.l,sx,sy+50);}const qa=0.8+0.2*Math.sin(time*2);ctx.fillStyle='rgba(5,20,40,0.97)';ctx.strokeStyle=`rgba(56,189,248,${qa})`;ctx.lineWidth=3;ctx.save();ctx.shadowColor=`rgba(56,189,248,${qa*0.5})`;ctx.shadowBlur=18;ctx.beginPath();ctx.roundRect(cx-200,cy+210,400,64,32);ctx.fill();ctx.stroke();ctx.restore();const badge=ctx.createLinearGradient(cx-180,0,cx+180,0);badge.addColorStop(0,'#38bdf8');badge.addColorStop(1,'#22c55e');ctx.fillStyle=badge;ctx.font='bold 30px monospace';ctx.textAlign='center';ctx.fillText('⏱ ~40 phút tự động',cx,cy+251);ctx.restore();return 1100;"},
    {"name": "bk_trinh_ngay_xay", "when": "Lộ trình 90 ngày để xây dựng micro-niche business. Tháng 1: Nghiên cứu", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 140;\nconst isPortrait = H > W;\n\nconst months = [\n  {\n    m: 'Tháng 1', subtitle: 'NGHIÊN CỨU', color: 'cyan',\n    tasks: ['Phỏng vấn 20 người trong target', 'Xác nhận nỗi đau thực sự tồn tại', 'Phân tích 3 đối thủ trong niche'],\n    icon: '🔍'\n  },\n  {\n    m: 'Tháng 2', subtitle: 'BUILD & VALIDATE', color: 'yellow',\n    tasks: ['Build MVP nhỏ nhất có thể', 'Bán cho 10 khách đầu tiên', 'Thu thập feedback chi tiết'],\n    icon: '🔧'\n  },\n  {\n    m: 'Tháng 3', subtitle: 'SCALE', color: 'green',\n    tasks: ['Tối ưu dựa trên feedback thực', 'Xây content channel trong niche', 'Mở rộng từng bước có kiểm soát'],\n    icon: '🚀'\n  },\n];\n\nconst colW = isPortrait ? Math.min(W - 60, 660) : Math.min((W - 80) / 3, 240);\nconst gapX = isPortrait ? 0 : 20;\nconst startX = isPortrait ? cx : cx - (colW * 3 + gapX * 2) / 2;\nconst startY = isPortrait ? cy - 140 : cy - 140;\n\nmonths.forEach((month, idx) => {\n  const show = stepProgress > idx * 0.28;\n  let bx, by;\n  if (isPortrait) { bx = cx; by = startY + idx * 100; }\n  else { bx = startX + idx * (colW + gapX) + colW/2; by = startY; }\n\n  const pulse = show ? 1 + 0.06 * Math.sin(time * 2 + idx) : 1;\n  ctx.fillStyle = show ? 'rgba(15,23,42,0.95)' : 'rgba(15,23,42,0.3)';\n  ctx.strokeStyle = show ? rc(month.color) : 'rgba(255,255,255,0.05)'; ctx.lineWidth = 3;\n  ctx.save(); if (show) { ctx.shadowColor = rc(month.color); ctx.shadowBlur = 14 * pulse; }\n  if (isPortrait) {\n    ctx.beginPath(); ctx.roundRect(bx - colW/2, by - 38, colW, 88, 10); ctx.fill(); ctx.stroke();\n    ctx.restore();\n    ctx.fillStyle = '#fff'; ctx.font = '22px sans-serif'; ctx.textAlign = 'left'; ctx.textBaseline = 'middle';\n    ctx.fillText(month.icon, bx - colW/2 + 14, by + 5);\n    ctx.fillStyle = show ? rc(month.color) : '#aaa'; ctx.font = 'bold 22px monospace';\n    ctx.fillText(month.m + ': ' + month.subtitle, bx - colW/2 + 46, by - 12);\n    month.tasks.slice(0,2).forEach((task, ti) => {\n      ctx.fillStyle = '#bbb'; ctx.font = '18px monospace';\n      ctx.fillText('• ' + task, bx - colW/2 + 46, by + 8 + ti * 24);\n    });\n  } else {\n    ctx.beginPath(); ctx.roundRect(bx - colW/2, by, colW, 280, 10); ctx.fill(); ctx.stroke();\n    ctx.restore();\n    ctx.font = '36px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText(month.icon, bx, by + 36);\n    ctx.fillStyle = show ? rc(month.color) : '#aaa'; ctx.font = 'bold 22px monospace'; ctx.textBaseline = 'alphabetic';\n    ctx.fillText(month.m, bx, by + 74);\n    ctx.font = 'bold 20px monospace';\n    ctx.fillText(month.subtitle, bx, by + 94);\n    month.tasks.forEach((task, ti) => {\n      ctx.fillStyle = show ? '#bbb' : 'rgba(255,255,255,0.1)'; ctx.font = '18px monospace';\n      const words = task.split(' ');\n      const lines2 = []; let cur = '';\n      words.forEach(w => { if ((cur+w).length > 18) { lines2.push(cur.trim()); cur = w+' '; } else cur += w+' '; });\n      if (cur.trim()) lines2.push(cur.trim());\n      lines2.forEach((line, li) => ctx.fillText(line, bx, by + 120 + ti * 44 + li * 24));\n    });\n  }\n});\n\nctx.restore();\nreturn 380;"},
    {"name": "bk_hieu_ung_ray", "when": "Hiệu ứng X-Ray động cơ. Hãy nhìn vào chiếc hộp đen của hệ thống. Lớp v", "code": "ctx.save();\nconst cx=W/2,cy=cursorY+150;\n// X-Ray: outer shell fading to reveal engines\nconst xrayT=0.5+0.5*Math.sin(time*0.5);\n// outer casing (semi-transparent)\nctx.fillStyle=`rgba(15,23,42,${0.3*xrayT})`;ctx.strokeStyle=`rgba(148,163,184,${0.4*xrayT})`;ctx.lineWidth=2;\nctx.beginPath();ctx.roundRect(cx-235,cy-120,470,240,18);ctx.fill();ctx.stroke();\n// X-ray scanlines\nfor(let i=0;i<20;i++){ctx.strokeStyle=`rgba(56,189,248,${0.03*(1-xrayT)})`;ctx.lineWidth=1;ctx.beginPath();ctx.moveTo(cx-235,cy-120+i*12);ctx.lineTo(cx+235,cy-120+i*12);ctx.stroke();}\n// Left engine @core\nctx.fillStyle='rgba(5,25,45,0.92)';ctx.strokeStyle=rc('cyan');ctx.lineWidth=2.5;\nctx.save();ctx.shadowColor=rc('cyan');ctx.shadowBlur=12;\nctx.beginPath();ctx.roundRect(cx-225,cy-110,195,220,12);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('cyan');ctx.font='bold 11px monospace';ctx.textAlign='center';ctx.fillText('@tubecreate/core',cx-128,cy-90);\n// spinning mechanism\nctx.save();ctx.translate(cx-128,cy+5);ctx.rotate(time);\nfor(let i=0;i<6;i++){const a=i*Math.PI/3;ctx.strokeStyle=rc('cyan');ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(Math.cos(a)*15,Math.sin(a)*15);ctx.lineTo(Math.cos(a)*30,Math.sin(a)*30);ctx.stroke();}ctx.strokeStyle=rc('cyan');ctx.lineWidth=2;ctx.beginPath();ctx.arc(0,0,12,0,Math.PI*2);ctx.stroke();\nctx.restore();\n// file inputs feeding in\nfor(let i=0;i<4;i++){const fy=(cy-70+(i*38)+(time*15)%40);\nif(fy>cy-70&&fy<cy+70){ctx.fillStyle='rgba(56,189,248,0.6)';ctx.font='14px monospace';ctx.textAlign='center';ctx.fillText(['.ts','.py','.go','.rs'][i],cx-210,fy);}}\n// crystals output\nfor(let i=0;i<3;i++){const a=time*0.5+i*2;const cx2=cx-128+Math.cos(a)*12;const cy2=cy+5+Math.sin(a)*10;\nctx.fillStyle='rgba(168,85,247,0.9)';ctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=8;ctx.beginPath();ctx.arc(cx2,cy2,4,0,Math.PI*2);ctx.fill();ctx.restore();}\n// Pipeline\nctx.fillStyle='rgba(15,23,42,0.8)';ctx.strokeStyle='rgba(168,85,247,0.6)';ctx.lineWidth=8;ctx.lineCap='round';\nctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=10;ctx.beginPath();ctx.moveTo(cx-33,cy);ctx.lineTo(cx+33,cy);ctx.stroke();ctx.restore();\n// packets flowing\nfor(let i=0;i<3;i++){const t=((time*0.7)+i*0.33)%1;const px=cx-30+t*60;ctx.fillStyle='rgba(168,85,247,0.9)';ctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=10;ctx.beginPath();ctx.arc(px,cy,4,0,Math.PI*2);ctx.fill();ctx.restore();}\n// Right engine @dashboard\nctx.fillStyle='rgba(35,20,5,0.92)';ctx.strokeStyle=rc('yellow');ctx.lineWidth=2.5;\nctx.save();ctx.shadowColor=rc('yellow');ctx.shadowBlur=12;\nctx.beginPath();ctx.roundRect(cx+30,cy-110,195,220,12);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('yellow');ctx.font='bold 11px monospace';ctx.textAlign='center';ctx.fillText('@tubecreate/dashboard',cx+128,cy-90);\n// React component cards exploding out\nconst cards=[{x:cx+75,y:cy-40,lbl:'AuthNode',col:rc('cyan')},{x:cx+160,y:cy-50,lbl:'ApiNode',col:rc('yellow')},{x:cx+155,y:cy+30,lbl:'DbNode',col:rc('green')},{x:cx+85,y:cy+45,lbl:'Edge',col:'#a855f7'}];\nfor(const c of cards){ctx.fillStyle='rgba(15,23,42,0.9)';ctx.strokeStyle=c.col;ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(c.x-24,c.y-12,48,24,4);ctx.fill();ctx.stroke();ctx.fillStyle='#fff';ctx.font='bold 8px monospace';ctx.textAlign='center';ctx.fillText(c.lbl,c.x,c.y+4);}\n// connections between cards\nctx.strokeStyle='rgba(56,189,248,0.3)';ctx.lineWidth=1;\nfor(let i=0;i<3;i++){ctx.beginPath();ctx.moveTo(cards[i].x,cards[i].y);ctx.lineTo(cards[3].x,cards[3].y);ctx.stroke();}\nctx.restore();return 380;"},
    {"name": "bk_nho_vao_can", "when": "Nhờ vào sự cân bằng nghệ thuật giữa Faucets và Sinks, nền kinh tế game", "code": "ctx.save();\n\nconst cx = W / 2;\nconst isPortrait = H > W;\nconst w = W - MX * 2;\nconst x = cx - w / 2;\nconst y = cursorY + 10;\nconst sc = isPortrait ? (W / 360) : (H / 600);\nconst frameH = isPortrait ? (340 * sc) : (200 * sc);\nconst cy = y + frameH / 2;\n\nconst drawGlowCard = function(ctx, sx, sy, cw, ch, color, label) {\n  ctx.save();\n  const scw = cw * sc;\n  const sch = ch * sc;\n  ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n  ctx.strokeStyle = color;\n  ctx.lineWidth = 2.5 * sc;\n  ctx.shadowColor = color;\n  ctx.shadowBlur = 15 * sc;\n  ctx.beginPath();\n  ctx.roundRect(sx - scw/2, sy - sch/2, scw, sch, 10 * sc);\n  ctx.fill();\n  ctx.stroke();\n  ctx.shadowBlur = 0;\n  ctx.fillStyle = color + '0a';\n  const gridSize = 8 * sc;\n  const dotSize = 3 * sc;\n  for (let gx = sx - scw/2 + 6*sc; gx < sx + scw/2; gx += gridSize) {\n    for (let gy = sy - sch/2 + 6*sc; gy < sy + sch/2; gy += gridSize) {\n      ctx.fillRect(gx, gy, dotSize, dotSize);\n    }\n  }\n  ctx.fillStyle = color;\n  ctx.fillRect(sx - scw/2, sy - sch/2, 22 * sc, 4 * sc);\n  if (label) {\n    ctx.font = 'bold ' + Math.round(11 * sc) + 'px monospace';\n    ctx.fillStyle = color;\n    ctx.textAlign = 'center';\n    ctx.textBaseline = 'top';\n    ctx.fillText(label, sx, sy - sch/2 + 10 * sc);\n  }\n  ctx.restore();\n};\n\nconst drawGlowCircle = function(ctx, sx, sy, r, color, label) {\n  ctx.save();\n  const sr = r * sc;\n  ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n  ctx.strokeStyle = color;\n  ctx.lineWidth = 2.5 * sc;\n  ctx.shadowColor = color;\n  ctx.shadowBlur = 15 * sc;\n  ctx.beginPath();\n  ctx.arc(sx, sy, sr, 0, Math.PI*2);\n  ctx.fill();\n  ctx.stroke();\n  ctx.shadowBlur = 0;\n  ctx.strokeStyle = color + '40';\n  ctx.lineWidth = 1.5 * sc;\n  ctx.beginPath();\n  ctx.arc(sx, sy, sr * 0.75, 0, Math.PI*2);\n  ctx.stroke();\n  ctx.strokeStyle = color;\n  ctx.lineWidth = 2 * sc;\n  const rot = time * 0.8;\n  ctx.beginPath();\n  ctx.moveTo(sx + Math.cos(rot)*sr, sy + Math.sin(rot)*sr);\n  ctx.lineTo(sx - Math.cos(rot)*sr, sy - Math.sin(rot)*sr);\n  ctx.moveTo(sx + Math.cos(rot + Math.PI/2)*sr, sy + Math.sin(rot + Math.PI/2)*sr);\n  ctx.lineTo(sx - Math.cos(rot + Math.PI/2)*sr, sy - Math.sin(rot + Math.PI/2)*sr);\n  ctx.stroke();\n  if (label) {\n    ctx.font = 'bold ' + Math.round(11 * sc) + 'px monospace';\n    ctx.fillStyle = color;\n    ctx.textAlign = 'center';\n    ctx.textBaseline = 'top';\n    ctx.fillText(label, sx, sy - sch/2 + 10 * sc);\n  }\n  ctx.restore();\n};\n\nctx.save();\nctx.fillStyle = '#22d3ee';\nctx.font = \"bold \" + Math.round(11 * sc) + \"px monospace\";\nctx.textAlign = \"left\";\nctx.fillText(\"⚡ [ HUD: ONLINE ]\", x + 15 * sc, y + 20 * sc);\nctx.textAlign = \"right\";\nctx.fillText(\"[ HUD METRICS ACTIVE ]\", x + w - 15 * sc, y + 20 * sc);\nctx.restore();\n\nctx.save();\nfor(let i=0; i<12; i++) {\n  const sx = x + 30 * sc + Math.sin(time*0.5+i*2.2)*(w - 60 * sc);\n  const sy = y + ((time*15 * sc + i*50 * sc) % frameH);\n  ctx.fillStyle = `rgba(34, 211, 238, ${0.06 + 0.08 * Math.sin(time*2.5+i)})`;\n  ctx.fillRect(sx, sy, 4 * sc, 4 * sc);\n}\nctx.restore();\n\nctx.save();\nfor(let sy=y; sy<y+frameH; sy+=3.5 * sc) {\n  ctx.fillStyle = 'rgba(0,0,0,0.035)';\n  ctx.fillRect(x, sy, w, 1);\n}\nctx.restore();\n\nctx.textAlign = 'center';\nctx.textBaseline = 'middle';\n\nctx.save(); ctx.strokeStyle = '#22d3ee'; ctx.lineWidth = 4 * sc; ctx.beginPath();\nctx.moveTo(cx - 70 * sc, cy + 20 * sc * Math.sin(time)); ctx.lineTo(cx + 70 * sc, cy - 20 * sc * Math.sin(time));\nctx.stroke(); drawGlowCircle(ctx, cx, cy, 14, '#10b981', \"BALANCE\"); ctx.restore();\n\nctx.restore();\nreturn frameH + 20;"},
    {"name": "bk_nang_trai_nghiem", "when": "Nâng trải nghiệm bằng streaming: thêm stream true khi gọi AI, kết quả ", "code": "var P=Math.max(0,Math.min(1,stepProgress*4));function RR(x,y,w,h,r){ctx.beginPath();ctx.roundRect(x,y,w,h,r);}function CL(v){return Math.max(0,Math.min(1,v));}function EZ(t){return 1-Math.pow(1-t,3);}function EB(t){var c1=1.70158,c3=c1+1;return 1+c3*Math.pow(t-1,3)+c1*Math.pow(t-1,2);}\nvar bx=W/2-270, by=cursorY+215;\nctx.save();\n// neural net: 3 layers\nvar L=[4,5,3], nodes=[];\nfor(var c=0;c<3;c++){var col=[];\n  for(var r=0;r<L[c];r++){col.push([bx-95+c*95, by-((L[c]-1)*54)/2+r*54]);}nodes.push(col);}\nfor(var c1=0;c1<2;c1++){\n  nodes[c1].forEach(function(a,ai){nodes[c1+1].forEach(function(b,bi){\n    var w=0.5+0.5*Math.sin(time*2.6-c1*1.4+ai+bi);\n    ctx.strokeStyle='rgba(34,211,238,'+(0.08+0.3*w)+')';ctx.lineWidth=1.4;\n    ctx.beginPath();ctx.moveTo(a[0],a[1]);ctx.lineTo(b[0],b[1]);ctx.stroke();});});}\nnodes.forEach(function(col,ci){col.forEach(function(n,ni){\n  var act=0.5+0.5*Math.sin(time*2.6-ci*1.4+ni);\n  ctx.fillStyle='rgba(34,211,238,'+(0.35+0.65*act)+')';\n  ctx.shadowColor=rc('cyan');ctx.shadowBlur=8*act;\n  ctx.beginPath();ctx.arc(n[0],n[1],7+act*3,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0;});});\n// flying tokens to bubble\nvar bubX=W/2+15, bubY=by-135, bubW=430, bubH=270;\nfor(var i=0;i<3;i++){var t=(time*0.7+i/3)%1;\n  var fx=bx+95+(bubX-bx-95)*t, fy=by+Math.sin(t*Math.PI)*-46;\n  ctx.globalAlpha=1-t*0.4;ctx.fillStyle=rc('title');\n  RR(fx-7,fy-7,14,14,4);ctx.fill();ctx.globalAlpha=1;}\n// chat bubble\nctx.fillStyle='rgba(255,255,255,0.05)';RR(bubX,bubY,bubW,bubH,22);ctx.fill();\nctx.strokeStyle='rgba(34,211,238,0.45)';ctx.lineWidth=2;RR(bubX,bubY,bubW,bubH,22);ctx.stroke();\nctx.beginPath();ctx.moveTo(bubX+2,by-16);ctx.lineTo(bubX-20,by);ctx.lineTo(bubX+2,by+16);\nctx.fillStyle='rgba(255,255,255,0.05)';ctx.fill();\n// AI chip\nctx.fillStyle='rgba(34,211,238,0.15)';RR(bubX+18,bubY+14,86,34,17);ctx.fill();\nctx.fillStyle=rc('cyan');ctx.font='bold 21px sans-serif';ctx.textAlign='left';ctx.textBaseline='middle';\nctx.fillText('🧠 AI',bubX+34,bubY+31);\n// streaming words\nvar TXT=\"Chữ chảy về từng chút như ChatGPT — không bắt người dùng chờ cả câu.\";var words=TXT.split(' ');\nvar n=Math.floor(words.length*CL(P*1.15));\nvar shown=words.slice(0,n).join(' ')+(n<words.length&&Math.floor(time*2.4)%2===0?' ▍':'');\nctx.fillStyle='rgba(230,237,243,0.92)';ctx.font='25px sans-serif';\nvar lines=wrapText(shown,bubW-44,'25px sans-serif');\nfor(var li=0;li<Math.min(lines.length,5);li++){ctx.fillText(lines[li],bubX+22,bubY+80+li*36);}\nctx.restore();"},
    {"name": "bk_tuong_chac_chan", "when": "Khi đã có một ý tưởng đủ chắc chắn, bước tiếp theo sẽ là xây dựng bản ", "code": "ctx.save();\nconst cx = W / 2;\nconst cy = cursorY + 140;\nconst w = Math.min(W - MX * 2, 800);\nconst h = 260;\nconst x = cx - w / 2;\nconst y = cursorY + 10;\n\nconst animProgress = Math.max(0, Math.min(1, (stepProgress - 0.3) * 2.5));\nconst opacity = animProgress;\nconst slideY = (1.0 - animProgress) * 40;\n\nif (animProgress > 0) {\n  ctx.save();\n  ctx.globalAlpha = opacity;\n  ctx.shadowColor = 'rgba(168, 85, 247, 0.4)';\n  ctx.shadowBlur = 18;\n  \n  const grad = ctx.createLinearGradient(x, y + slideY, x + w, y + slideY + h);\n  grad.addColorStop(0, 'rgba(30, 27, 75, 0.85)');\n  grad.addColorStop(1, 'rgba(15, 23, 42, 0.95)');\n  ctx.fillStyle = grad;\n  \n  ctx.strokeStyle = 'rgba(168, 85, 247, 0.35)';\n  ctx.lineWidth = 2;\n  ctx.beginPath();\n  ctx.roundRect(x, y + slideY, w, h, 20);\n  ctx.fill();\n  ctx.stroke();\n  ctx.restore();\n  \n  ctx.save();\n  ctx.globalAlpha = opacity;\n  \n  const badgeW = 160;\n  const badgeH = 28;\n  const badgeX = cx - badgeW / 2;\n  const badgeY = y + slideY + 20;\n  \n  ctx.fillStyle = 'rgba(168, 85, 247, 0.15)';\n  ctx.strokeStyle = 'rgba(168, 85, 247, 0.5)';\n  ctx.lineWidth = 1;\n  ctx.beginPath();\n  ctx.roundRect(badgeX, badgeY, badgeW, badgeH, 6);\n  ctx.fill();\n  ctx.stroke();\n  \n  ctx.font = 'bold 11px monospace';\n  ctx.fillStyle = '#c084fc';\n  ctx.textAlign = 'center';\n  ctx.textBaseline = 'middle';\n  ctx.fillText('⚡ BÀI HỌC TIẾP THEO ⚡', cx, badgeY + badgeH / 2 + 1);\n  \n  ctx.font = 'bold 26px \"Outfit\", \"Inter\", sans-serif';\n  ctx.fillStyle = '#ffffff';\n  ctx.textAlign = 'center';\n  ctx.fillText('Bài 4: Xây dựng', cx, y + slideY + 80);\n  ctx.fillText('bản mẫu sản phẩm', cx, y + slideY + 115);\n  \n  // Prototype wireframe icon\n  const iconY = y + slideY + 180;\n  const pulse = 1 + 0.08 * Math.sin(time * 3);\n  \n  // Wireframe box\n  ctx.strokeStyle = 'rgba(59, 130, 246, 0.6)';\n  ctx.lineWidth = 2;\n  ctx.beginPath();\n  ctx.roundRect(cx - 60, iconY - 35, 120, 70, 8);\n  ctx.stroke();\n  \n  // Header bar\n  ctx.fillStyle = 'rgba(59, 130, 246, 0.3)';\n  ctx.beginPath(); ctx.roundRect(cx - 55, iconY - 30, 110, 14, 4); ctx.fill();\n  \n  // Content lines\n  ctx.fillStyle = 'rgba(168, 85, 247, 0.4)';\n  ctx.beginPath(); ctx.roundRect(cx - 50, iconY - 8, 70, 6, 3); ctx.fill();\n  ctx.beginPath(); ctx.roundRect(cx - 50, iconY + 4, 50, 6, 3); ctx.fill();\n  \n  // Button\n  ctx.fillStyle = 'rgba(16, 185, 129, 0.5)';\n  ctx.beginPath(); ctx.roundRect(cx - 30, iconY + 18, 60, 12, 4); ctx.fill();\n  \n  // Pulsing dot\n  ctx.fillStyle = '#a855f7';\n  ctx.shadowColor = '#a855f7';\n  ctx.shadowBlur = 8 * pulse;\n  ctx.beginPath(); ctx.arc(cx + 50, iconY - 25, 4 * pulse, 0, Math.PI * 2); ctx.fill();\n  ctx.shadowBlur = 0;\n  \n  // Particles\n  for (let i = 0; i < 10; i++) {\n    const pTime = (time * 0.18 + i * 0.1) % 1.0;\n    const px = x + 20 + ((i * 83) % (w - 40));\n    const py = (y + slideY + h - 15) - pTime * (h - 30);\n    const size = (1.0 - pTime) * 3;\n    ctx.fillStyle = 'rgba(168, 85, 247, ' + (0.3 * (1.0 - pTime)) + ')';\n    ctx.beginPath(); ctx.arc(px, py, size, 0, Math.PI * 2); ctx.fill();\n  }\n  \n  ctx.restore();\n}\nctx.restore();\nreturn h + 20;"},
    {"name": "bk_lam_sao_biet", "when": "Làm sao để biết ý tưởng của bạn có thực sự đột phá hay không? Chúng tô", "code": "ctx.save();\nconst cx=W/2, cy=cursorY+440;\nfor(let i=0;i<22;i++){const sx=(Math.sin(i*63.1+time*.06)*.5+.5)*W;const sy=cursorY+((i*82+time*20)%1050);ctx.fillStyle=`rgba(234,179,8,${0.05+0.03*Math.sin(time+i)})`;ctx.beginPath();ctx.arc(sx,sy,1,0,Math.PI*2);ctx.fill();}\nctx.textAlign='center';\nctx.fillStyle='rgba(234,179,8,0.9)';ctx.font='bold 18px monospace';ctx.fillText('DISRUPTIVE CHECKLIST',cx,cursorY+58);\nctx.fillStyle='rgba(255,255,255,0.98)';ctx.font='bold 52px sans-serif';\nctx.save();ctx.shadowColor='rgba(234,179,8,0.5)';ctx.shadowBlur=26;ctx.fillText('3 Tiêu Chuẩn Vàng',cx,cursorY+122);ctx.restore();\nctx.fillStyle='rgba(255,255,255,0.5)';ctx.font='20px monospace';\nctx.fillText('Đạt cả 3 = Nghiên cứu mang tính cách mạng',cx,cursorY+164);\nctx.strokeStyle='rgba(255,255,255,0.1)';ctx.lineWidth=1;\nctx.beginPath();ctx.moveTo(cx-400,cursorY+188);ctx.lineTo(cx+400,cursorY+188);ctx.stroke();\n// Three criteria cards — light up sequentially\nconst criteria=[\n  {n:'1',title:'Định Nghĩa Lại Bài Toán',sub:'Thay đổi hoàn toàn cách nhìn vấn đề',icon:'🔄',color:'#38bdf8'},\n  {n:'2',title:'Giải Quyết Điều Bất Khả Thi',sub:'Phá vỡ giới hạn năng lực kỹ thuật cũ',icon:'🔓',color:'#a855f7'},\n  {n:'3',title:'Kiến Tạo Chuẩn So Sánh',sub:'Baseline mới cho cộng đồng nghiên cứu',icon:'🏆',color:'#22c55e'},\n];\nconst activeCard=Math.floor(time*0.6)%3;\nconst totalH=270, gap=22;\nconst startY=cy-30;\ncriteria.forEach((c,i)=>{\n  const cardY=startY+i*(totalH/3+gap);\n  const isActive=i===activeCard;\n  const alpha=isActive?1:0.4;\n  ctx.save();ctx.globalAlpha=alpha;\n  // Card\n  ctx.fillStyle=isActive?`rgba(15,23,42,0.98)`:'rgba(255,255,255,0.04)';\n  ctx.strokeStyle=isActive?c.color:'rgba(255,255,255,0.1)';\n  ctx.lineWidth=isActive?2.8:1;\n  if(isActive){ctx.shadowColor=c.color;ctx.shadowBlur=20;}\n  ctx.beginPath();ctx.roundRect(cx-380,cardY,760,80,14);ctx.fill();ctx.stroke();\n  ctx.shadowBlur=0;\n  // Checkmark circle on left\n  ctx.fillStyle=isActive?c.color:'rgba(255,255,255,0.15)';\n  ctx.beginPath();ctx.arc(cx-336,cardY+40,22,0,Math.PI*2);ctx.fill();\n  ctx.fillStyle=isActive?'#fff':'rgba(255,255,255,0.5)';ctx.font='bold 22px monospace';ctx.textAlign='center';\n  ctx.fillText(isActive?'✓':c.n,cx-336,cardY+48);\n  // Content\n  ctx.textAlign='left';\n  ctx.fillStyle=isActive?'#fff':'rgba(255,255,255,0.6)';ctx.font='bold 22px monospace';\n  ctx.fillText(c.icon+' '+c.title,cx-298,cardY+34);\n  ctx.fillStyle=isActive?'rgba(255,255,255,0.8)':'rgba(255,255,255,0.3)';ctx.font='17px monospace';\n  ctx.fillText(c.sub,cx-298,cardY+60);\n  // Score pill on right\n  if(isActive){\n    ctx.fillStyle=c.color;ctx.beginPath();ctx.roundRect(cx+270,cardY+24,88,34,17);ctx.fill();\n    ctx.fillStyle='#fff';ctx.font='bold 16px monospace';ctx.textAlign='center';\n    ctx.fillText('PASS ✓',cx+314,cardY+46);\n  }\n  ctx.globalAlpha=1;ctx.restore();\n});\n// Scanner line\nconst scanY=startY+230*Math.abs(Math.sin(time*1.4));\nctx.strokeStyle='rgba(234,179,8,0.3)';ctx.lineWidth=2.5;\nctx.beginPath();ctx.moveTo(cx-390,scanY);ctx.lineTo(cx+390,scanY);ctx.stroke();\n// Bottom CTA\nctx.fillStyle='rgba(234,179,8,0.15)';ctx.beginPath();ctx.roundRect(cx-300,startY+280+gap,600,58,12);ctx.fill();\nctx.strokeStyle='rgba(234,179,8,0.5)';ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(cx-300,startY+280+gap,600,58,12);ctx.stroke();\nctx.textAlign='center';ctx.fillStyle='rgba(255,255,255,0.9)';ctx.font='bold 20px monospace';\nctx.fillText('🏅 Đạt cả 3 = Đột phá thực sự',cx,startY+317+gap);\nctx.restore();return 1100;"},
    {"name": "bk_loai_thu_nhat", "when": "Loại thứ nhất là Hình Ý Tưởng, hay còn gọi là Conceptual Figure. Đây l", "code": "ctx.save();const cx=W/2,cy=cursorY+450;ctx.textAlign='center';ctx.fillStyle='rgba(56,189,248,0.8)';ctx.font='bold 20px monospace';ctx.fillText('LOẠI 1: HÌNH Ý TƯỞNG (CONCEPTUAL FIGURE)',cx,cursorY+58);ctx.fillStyle='rgba(255,255,255,0.95)';ctx.font='bold 38px sans-serif';ctx.save();ctx.shadowColor='rgba(56,189,248,0.5)';ctx.shadowBlur=20;ctx.fillText('Giải Thích Ý Tưởng & Kiến Trúc',cx,cursorY+114);ctx.restore();ctx.fillStyle='rgba(56,189,248,0.06)';ctx.strokeStyle='rgba(56,189,248,0.3)';ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(cx-400,cursorY+142,800,480,14);ctx.fill();ctx.stroke();ctx.fillStyle='rgba(56,189,248,0.5)';ctx.font='bold 14px monospace';ctx.textAlign='left';ctx.fillText('[ Ví dụ: Sơ đồ kiến trúc hệ thống ]',cx-380,cursorY+170);const boxes=[{x:-280,y:100,w:140,h:60,t:'Input',c:'#94a3b8'},{x:-60,y:100,w:140,h:60,t:'Model',c:'#38bdf8'},{x:160,y:100,w:140,h:60,t:'Output',c:'#22c55e'}];boxes.forEach(b=>{const bx=cx+b.x,by=cursorY+142+b.y;ctx.fillStyle='rgba(10,20,40,0.9)';ctx.strokeStyle=b.c;ctx.lineWidth=2;ctx.beginPath();ctx.roundRect(bx,by,b.w,b.h,8);ctx.fill();ctx.stroke();ctx.fillStyle=b.c;ctx.font='bold 18px sans-serif';ctx.textAlign='center';ctx.fillText(b.t,bx+b.w/2,by+36);});const arrowPulse=0.5+0.5*Math.abs(Math.sin(time*1.5));ctx.strokeStyle=`rgba(255,255,255,${arrowPulse})`;ctx.lineWidth=2.5;[[cx-140,cursorY+272,cx-60,cursorY+272],[cx+80,cursorY+272,cx+160,cursorY+272]].forEach(([x1,y1,x2,y2])=>{ctx.beginPath();ctx.moveTo(x1,y1);ctx.lineTo(x2,y2);ctx.stroke();ctx.beginPath();ctx.moveTo(x2-10,y1-7);ctx.lineTo(x2,y1);ctx.lineTo(x2-10,y1+7);ctx.fill();});const subs=[{t:'Encoder',c:'#a855f7'},{t:'Attention',c:'#f59e0b'},{t:'Decoder',c:'#38bdf8'}];subs.forEach((s,i)=>{const sx=cx-40+i*48,sy=cursorY+380;ctx.fillStyle='rgba(8,8,24,0.95)';ctx.strokeStyle=s.c;ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(sx,sy,40,30,5);ctx.fill();ctx.stroke();ctx.fillStyle=s.c;ctx.font='bold 9px monospace';ctx.textAlign='center';ctx.fillText(s.t,sx+20,sy+19);});const attrs=[{t:'Vị trí',v:'Giới Thiệu hoặc đầu Phương Pháp'},{t:'Mục đích',v:'Giải thích ý tưởng chính khác gì đối thủ'},{t:'Kỹ thuật',v:'Sơ đồ khối, sơ đồ luồng (Pipeline)'},{t:'Mẹo',v:'Dùng màu sắc để phân biệt các thành phần'}];attrs.forEach((a,i)=>{const ry=cursorY+652+i*60;ctx.fillStyle='rgba(255,255,255,0.04)';ctx.beginPath();ctx.roundRect(cx-380,ry,760,48,6);ctx.fill();ctx.fillStyle='rgba(56,189,248,0.8)';ctx.font='bold 14px monospace';ctx.textAlign='left';ctx.fillText(a.t+':',cx-360,ry+30);ctx.fillStyle='rgba(255,255,255,0.75)';ctx.font='15px sans-serif';ctx.fillText(a.v,cx-260,ry+30);});ctx.restore();"},
    {"name": "bk_toi_tubecreate_tam", "when": "Tôi là TubeCreate. Để vẽ một tấm bản đồ vĩ đại, bạn cần người thợ vẽ m", "code": "ctx.save();\nconst cx=W/2,cy=cursorY+150;\nconst pulse=1+0.04*Math.sin(time*2.5);\n// Left engine: @core (industrial dark)\nctx.fillStyle='rgba(5,25,45,0.94)';ctx.strokeStyle=rc('cyan');ctx.lineWidth=3;\nctx.save();ctx.shadowColor=rc('cyan');ctx.shadowBlur=18*pulse;\nctx.beginPath();ctx.roundRect(cx-230,cy-110,200,220,14);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('cyan');ctx.font='bold 12px monospace';ctx.textAlign='center';ctx.fillText('@core',cx-130,cy-88);\n// spinning gear inside\nctx.save();ctx.translate(cx-130,cy+10);ctx.rotate(time*0.7);\nconst teeth=8,gR=36;\nctx.strokeStyle=rc('cyan');ctx.lineWidth=2.5;ctx.beginPath();\nfor(let i=0;i<teeth*2;i++){const a=i*Math.PI/teeth;const r=i%2===0?gR:gR*0.73;ctx.lineTo(Math.cos(a)*r,Math.sin(a)*r);}ctx.closePath();ctx.stroke();\nctx.fillStyle='rgba(5,25,45,0.95)';ctx.beginPath();ctx.arc(0,0,gR*0.45,0,Math.PI*2);ctx.fill();ctx.restore();\n// data crystals in core\nfor(let i=0;i<5;i++){const a=time*0.4+i;const cx2=cx-130,cy2=cy+10;const rx=cx2+Math.cos(a)*22,ry=cy2+Math.sin(a)*16;ctx.fillStyle='#a855f7';ctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=8;ctx.beginPath();ctx.moveTo(rx,ry-5);ctx.lineTo(rx+4,ry);ctx.lineTo(rx,ry+5);ctx.lineTo(rx-4,ry);ctx.closePath();ctx.fill();ctx.restore();}\n// Pipeline pipe\nctx.strokeStyle='rgba(168,85,247,0.7)';ctx.lineWidth=6;ctx.lineCap='round';\nctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=12;\nctx.beginPath();ctx.moveTo(cx-30,cy);ctx.lineTo(cx+30,cy);ctx.stroke();ctx.restore();\n// flowing crystals\nfor(let i=0;i<4;i++){const t=((time*0.6)+i*0.25)%1;const px=cx-28+t*56;ctx.fillStyle='rgba(168,85,247,0.9)';ctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=10;ctx.beginPath();ctx.arc(px,cy,4,0,Math.PI*2);ctx.fill();ctx.restore();}\n// Right engine: @dashboard (warm)\nctx.fillStyle='rgba(35,20,5,0.94)';ctx.strokeStyle=rc('yellow');ctx.lineWidth=3;\nctx.save();ctx.shadowColor=rc('yellow');ctx.shadowBlur=18*pulse;\nctx.beginPath();ctx.roundRect(cx+30,cy-110,200,220,14);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('yellow');ctx.font='bold 12px monospace';ctx.textAlign='center';ctx.fillText('@dashboard',cx+130,cy-88);\n// monitor/screen inside right\nctx.strokeStyle=rc('yellow');ctx.lineWidth=2;ctx.beginPath();ctx.roundRect(cx+65,cy-40,80,55,5);ctx.stroke();\nctx.fillStyle='rgba(234,179,8,0.08)';ctx.fillRect(cx+66,cy-39,78,53);\nfor(let i=0;i<5;i++){const barH=15+Math.abs(Math.sin(time*2+i))*20;ctx.fillStyle=`rgba(56,189,248,${0.5+0.3*Math.sin(time+i)})`;ctx.fillRect(cx+70+i*13,cy-36+35-barH,10,barH);}\nctx.restore();return 380;"},
    {"name": "bk_module_khoa_hoc", "when": "Chào mừng các bạn đến với Module 4 của khóa học Nghiên Cứu Khoa Học th", "code": "ctx.save();const cx=W/2,cy=cursorY+480;const grad=ctx.createLinearGradient(0,cursorY,0,cursorY+1080);grad.addColorStop(0,'#0f0c29');grad.addColorStop(0.5,'#302b63');grad.addColorStop(1,'#24243e');ctx.fillStyle=grad;ctx.fillRect(0,cursorY,W,1080);for(let i=0;i<50;i++){const px=(Math.sin(i*73.1+time*.04)*.5+.5)*W,py=cursorY+((i*97+time*20)%1080);ctx.fillStyle=`rgba(99,102,241,${0.04+0.03*Math.sin(time+i*.7)})`;ctx.beginPath();ctx.arc(px,py,1.2,0,Math.PI*2);ctx.fill();}ctx.textAlign='center';ctx.fillStyle='rgba(99,102,241,0.7)';ctx.font='bold 18px monospace';ctx.fillText('MODULE 4 — VẼ HÌNH KH',cx,cursorY+70);ctx.fillStyle='rgba(255,255,255,0.98)';ctx.font='bold 52px sans-serif';ctx.save();ctx.shadowColor='rgba(99,102,241,0.6)';ctx.shadowBlur=28;ctx.fillText('Tại Sao Hình Minh Họa',cx,cursorY+148);ctx.restore();ctx.fillStyle='rgba(99,102,241,0.85)';ctx.font='bold 40px sans-serif';ctx.save();ctx.shadowColor='rgba(99,102,241,0.4)';ctx.shadowBlur=14;ctx.fillText('Quan Trọng?',cx,cursorY+202);ctx.restore();ctx.strokeStyle='rgba(255,255,255,0.08)';ctx.lineWidth=1;ctx.beginPath();ctx.moveTo(cx-400,cursorY+228);ctx.lineTo(cx+400,cursorY+228);ctx.stroke();const stats=[{v:'50%',l:'Reviewer nhìn hình trước khi đọc văn bản',c:'#f59e0b'},{v:'3x',l:'Bài báo có hình đẹp được trích dẫn nhiều hơn',c:'#22c55e'},{v:'8 giây',l:'Thời gian người đánh giá quyết định ban đầu',c:'#38bdf8'}];stats.forEach((s,i)=>{const sx=cx-320+i*320,sy=cy-100;const pulse=0.7+0.3*Math.sin(time*1.2+i*2.1);ctx.fillStyle='rgba(15,12,41,0.9)';ctx.strokeStyle=s.c;ctx.lineWidth=2*pulse;ctx.save();ctx.shadowColor=s.c;ctx.shadowBlur=20*pulse;ctx.beginPath();ctx.roundRect(sx-130,sy-70,260,140,14);ctx.fill();ctx.stroke();ctx.restore();ctx.fillStyle=s.c;ctx.font='bold 48px sans-serif';ctx.textAlign='center';ctx.fillText(s.v,sx,sy+10);ctx.fillStyle='rgba(255,255,255,0.7)';ctx.font='15px sans-serif';const words=s.l.split(' '),line1=words.slice(0,3).join(' '),line2=words.slice(3).join(' ');ctx.fillText(line1,sx,sy+44);if(line2)ctx.fillText(line2,sx,sy+64);});const qa=0.6+0.4*Math.sin(time*1.5);ctx.fillStyle='rgba(15,12,41,0.95)';ctx.strokeStyle=`rgba(99,102,241,${qa})`;ctx.lineWidth=2;ctx.beginPath();ctx.roundRect(cx-380,cy+110,760,72,12);ctx.fill();ctx.stroke();ctx.fillStyle='rgba(255,255,255,0.85)';ctx.font='italic 22px serif';ctx.textAlign='center';ctx.fillText('\"Một hình ảnh tốt hơn một trang chú thích dài dòng.\"',cx,cy+148);ctx.fillStyle='rgba(99,102,241,0.7)';ctx.font='16px monospace';ctx.fillText('— GS. Yuyu Luo, HKUST',cx,cy+174);ctx.restore();"},
    {"name": "bk_minh_cung_kham", "when": "Chào các bạn, trong bài này mình sẽ cùng các bạn khám phá vì sao một t", "code": "ctx.save();\nctx.beginPath();ctx.rect(0,cursorY,W,650);ctx.clip();\nconst cx=W/2,cy=cursorY+300;\n\n// Cyber background grid - Neon Purple\nctx.strokeStyle='rgba(167,139,250,0.03)';ctx.lineWidth=1;\nfor(let x=0;x<W;x+=40){ctx.beginPath();ctx.moveTo(x,cursorY);ctx.lineTo(x,cursorY+650);ctx.stroke();}\nfor(let y=cursorY;y<cursorY+650;y+=40){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}\n\nconst drawClaude = (ctx, x, y, scale, color, glowColor, angle = 0, opts = {}) => {\n    ctx.save();\n    ctx.translate(x, y); ctx.rotate(angle);\n    if (opts.lookLeft) ctx.scale(-scale, scale); else ctx.scale(scale, scale);\n    ctx.translate(-12, -10);\n    ctx.beginPath();\n    ctx.moveTo(20.998, 10.949); ctx.lineTo(24, 10.949); ctx.lineTo(24, 14.051); ctx.lineTo(21, 14.051);\n    ctx.lineTo(21, 17.079); ctx.lineTo(19.513, 17.079); ctx.lineTo(19.513, 20); ctx.lineTo(18, 20);\n    ctx.lineTo(18, 17.079); ctx.lineTo(16.513, 17.079); ctx.lineTo(16.513, 20); ctx.lineTo(15, 20);\n    ctx.lineTo(15, 17.079); ctx.lineTo(9, 17.079); ctx.lineTo(9, 20); ctx.lineTo(7.488, 20);\n    ctx.lineTo(7.488, 17.079); ctx.lineTo(6, 17.079); ctx.lineTo(6, 20); ctx.lineTo(4.487, 20);\n    ctx.lineTo(4.487, 17.079); ctx.lineTo(3, 17.079); ctx.lineTo(3, 14.05); ctx.lineTo(0, 14.05);\n    ctx.lineTo(0, 10.95); ctx.lineTo(3, 10.95); ctx.lineTo(3, 5); ctx.lineTo(20.998, 5);\n    ctx.lineTo(20.998, 10.949); ctx.closePath();\n    ctx.fillStyle = color || '#D97757';\n    if (glowColor) { ctx.shadowColor = glowColor; ctx.shadowBlur = 18; }\n    ctx.fill(); ctx.shadowBlur = 0;\n    ctx.fillStyle = '#fff';\n    ctx.fillRect(6, 8.102, 1.488, 2.847); ctx.fillRect(16.51, 8.102, 1.49, 2.847);\n    ctx.restore();\n};\n\n// Pulsing Memory Orbit - Gold color\nctx.strokeStyle = 'rgba(255,215,0,0.1)';ctx.lineWidth = 4;\nctx.beginPath();ctx.arc(cx, cy, 180, 0, Math.PI*2);ctx.stroke();\n\n// Memory Particles flying around Memory Orbit\nconst numMPoints = 4;\nfor (let i = 0; i < numMPoints; i++) {\n    const angle = time * 0.6 + i * (Math.PI * 2 / numMPoints);\n    const mx = cx + Math.cos(angle) * 180;\n    const my = cy + Math.sin(angle) * 180;\n    ctx.fillStyle = '#FFD700';ctx.shadowColor = '#FFD700';ctx.shadowBlur = 12;\n    ctx.beginPath();ctx.arc(mx, my, 6, 0, Math.PI*2);ctx.fill();ctx.shadowBlur = 0;\n    \n    // connection line to center\n    ctx.strokeStyle = 'rgba(255,215,0,0.06)';ctx.lineWidth = 1;\n    ctx.beginPath();ctx.moveTo(cx, cy);ctx.lineTo(mx, my);ctx.stroke();\n}\n\n// Pulsing State Orbit - Cyan color (elliptical, overlapping)\nctx.strokeStyle = 'rgba(34,211,238,0.1)';ctx.lineWidth = 4;\nctx.save();\nctx.translate(cx, cy); ctx.rotate(Math.PI / 4);\nctx.beginPath();ctx.ellipse(0, 0, 220, 100, 0, 0, Math.PI*2);ctx.stroke();\n\n// State checkpoints on orbit\nconst numSPoints = 3;\nfor (let i = 0; i < numSPoints; i++) {\n    const angle = -time * 0.8 + i * (Math.PI * 2 / numSPoints);\n    const sx = Math.cos(angle) * 220;\n    const sy = Math.sin(angle) * 100;\n    ctx.fillStyle = '#22d3ee';ctx.shadowColor = '#22d3ee';ctx.shadowBlur = 12;\n    ctx.beginPath();ctx.arc(sx, sy, 8, 0, Math.PI*2);ctx.fill();ctx.shadowBlur = 0;\n}\nctx.restore();\n\n// Floating Central Core Claude with gold and cyan dual glow\nconst bobY = cy + Math.sin(time * 2.5) * 15;\ndrawClaude(ctx, cx, bobY, 4.5, '#D97757', '#FFD700', Math.sin(time)*0.1);\n\nctx.font = 'bold 22px monospace';ctx.fillStyle = '#22d3ee';ctx.textAlign = 'center';\nctx.fillText('[ OPENCLAW COGNITIVE CORE ]', cx, cy + 180);\nctx.font = '15px monospace';ctx.fillStyle = '#FFD700';\nctx.fillText('HỆ THỐNG BỘ NHỚ & TRẠNG THÁI LIÊN KẾT BỀN VỮNG', cx, cy + 225);\nctx.restore();"},
    {"name": "bk_vay_tai_sao", "when": "Vậy tại sao sự kết hợp này lại quan trọng? Khi bộ nhớ và trạng thái ph", "code": "ctx.save();\nctx.beginPath();ctx.rect(0,cursorY,W,650);ctx.clip();\nconst cx=W/2,cy=cursorY+300;\n\n// Cyber background grid - Gold-Cyan dual overlay\nctx.strokeStyle='rgba(34,211,238,0.02)';ctx.lineWidth=1;\nfor(let x=0;x<W;x+=40){ctx.beginPath();ctx.moveTo(x,cursorY);ctx.lineTo(x,cursorY+650);ctx.stroke();}\nctx.strokeStyle='rgba(255,215,0,0.02)';\nfor(let y=cursorY;y<cursorY+650;y+=40){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}\n\nconst drawClaude = (ctx, x, y, scale, color, glowColor, angle = 0, opts = {}) => {\n    ctx.save();\n    ctx.translate(x, y); ctx.rotate(angle);\n    if (opts.lookLeft) ctx.scale(-scale, scale); else ctx.scale(scale, scale);\n    ctx.translate(-12, -10);\n    ctx.beginPath();\n    ctx.moveTo(20.998, 10.949); ctx.lineTo(24, 10.949); ctx.lineTo(24, 14.051); ctx.lineTo(21, 14.051);\n    ctx.lineTo(21, 17.079); ctx.lineTo(19.513, 17.079); ctx.lineTo(19.513, 20); ctx.lineTo(18, 20);\n    ctx.lineTo(18, 17.079); ctx.lineTo(16.513, 17.079); ctx.lineTo(16.513, 20); ctx.lineTo(15, 20);\n    ctx.lineTo(15, 17.079); ctx.lineTo(9, 17.079); ctx.lineTo(9, 20); ctx.lineTo(7.488, 20);\n    ctx.lineTo(7.488, 17.079); ctx.lineTo(6, 17.079); ctx.lineTo(6, 20); ctx.lineTo(4.487, 20);\n    ctx.lineTo(4.487, 17.079); ctx.lineTo(3, 17.079); ctx.lineTo(3, 14.05); ctx.lineTo(0, 14.05);\n    ctx.lineTo(0, 10.95); ctx.lineTo(3, 10.95); ctx.lineTo(3, 5); ctx.lineTo(20.998, 5);\n    ctx.lineTo(20.998, 10.949); ctx.closePath();\n    ctx.fillStyle = color || '#D97757';\n    if (glowColor) { ctx.shadowColor = glowColor; ctx.shadowBlur = 18; }\n    ctx.fill(); ctx.shadowBlur = 0;\n    ctx.fillStyle = '#fff';\n    ctx.fillRect(6, 8.102, 1.488, 2.847); ctx.fillRect(16.51, 8.102, 1.49, 2.847);\n    ctx.restore();\n};\n\n// Holographic Trinity Overlapping Shields (Consistency, Completion, Personalization)\nconst shields = [\n    { label: 'NHẤT QUÁN', c: '#22d3ee', a: -Math.PI/2 },\n    { label: 'HOÀN THÀNH', c: '#10b981', a: Math.PI/6 },\n    { label: 'CÁ NHÂN HÓA', c: '#a78bfa', a: 5*Math.PI/6 }\n];\n\nshields.forEach((sh, idx) => {\n    const radius = 120 + Math.sin(time*3 + idx)*10;\n    const sx = cx + Math.cos(sh.a) * radius;\n    const sy = cy - 20 + Math.sin(sh.a) * radius;\n    \n    // Draw shield circle\n    ctx.fillStyle = 'rgba(15, 23, 42, 0.4)';ctx.strokeStyle = sh.c;ctx.lineWidth = 3.5;\n    ctx.shadowColor = sh.c;ctx.shadowBlur = 15;\n    ctx.beginPath();ctx.arc(sx, sy, 75, 0, Math.PI*2);ctx.fill();ctx.stroke();ctx.shadowBlur = 0;\n    \n    // label\n    ctx.font = 'bold 12px monospace';ctx.fillStyle = sh.c;ctx.textAlign = 'center';\n    ctx.fillText(sh.label, sx, sy + 5);\n    \n    // connection lasers\n    ctx.strokeStyle = 'rgba(255, 255, 255, 0.08)';ctx.lineWidth = 1.5;\n    ctx.beginPath();ctx.moveTo(cx, cy - 20);ctx.lineTo(sx, sy);ctx.stroke();\n});\n\n// Central supercharged Claude (standard warm orange #D97757, intense gold glow)\nconst bobY = cy - 20 + Math.sin(time * 4) * 15;\ndrawClaude(ctx, cx, bobY, 4.8, '#D97757', '#FFD700', Math.sin(time)*0.1);\n\nctx.font = 'bold 22px monospace';ctx.fillStyle = '#FFD700';ctx.textAlign = 'center';\nctx.fillText('[ COGNITIVE FUSION SYNERGY ]', cx, cy + 180);\nctx.font = '14px monospace';ctx.fillStyle = '#64748b';\nctx.fillText('SỨC MẠNH TOÀN DIỆN: NHẤT QUÁN ➔ HOÀN THÀNH ➔ Độc ĐÁO', cx, cy + 220);\nctx.restore();"},
    {"name": "bk_openclaw_tro_kha", "when": "OpenClaw hỗ trợ khá nhiều lựa chọn. Nhóm quốc tế có OpenAI GPT, Anthro", "code": "ctx.save();\nconst cx = W / 2;\nconst cy = cursorY + 110;\nconst w = Math.min(W - MX * 2, 800);\nconst h = 200;\nconst x = cx - w / 2;\nconst y = cursorY + 10;\n\nctx.fillStyle = 'rgba(15, 23, 42, 0.9)';\nctx.beginPath();\nctx.roundRect(x, y, w, h, 16);\nctx.fill();\n\nctx.save();\nctx.shadowColor = '#22d3ee';\nctx.shadowBlur = 10;\nctx.strokeStyle = 'rgba(34, 211, 238, 0.35)';\nctx.lineWidth = 1.5;\nctx.stroke();\nctx.restore();\n\nconst arenaW = 320;\nconst arenaH = 140;\nconst arenaY = y + 42;\nconst gap = (w - arenaW * 2) / 3;\n\nconst leftX = x + gap;\nconst rightX = x + gap * 2 + arenaW;\n\nctx.fillStyle = 'rgba(255, 255, 255, 0.02)';\nctx.strokeStyle = 'rgba(99, 102, 241, 0.2)';\nctx.lineWidth = 1.5;\nctx.beginPath();\nctx.roundRect(leftX, arenaY, arenaW, arenaH, 12);\nctx.fill();\nctx.stroke();\n\nctx.fillStyle = 'rgba(255, 255, 255, 0.02)';\nctx.strokeStyle = 'rgba(34, 211, 238, 0.2)';\nctx.lineWidth = 1.5;\nctx.beginPath();\nctx.roundRect(rightX, arenaY, arenaW, arenaH, 12);\nctx.fill();\nctx.stroke();\n\nctx.fillStyle = '#22d3ee';\nctx.font = 'bold 15px monospace';\nctx.textAlign = 'center';\nctx.fillText(\"NHÓM QUỐC TẾ\", leftX + arenaW / 2, arenaY + 26);\n\nconst globNodes = [\n  { name: \"GPT-4o\", a: time * 1.1 },\n  { name: \"Claude 3.5\", a: time * 1.1 + Math.PI }\n];\nglobNodes.forEach(node => {\n  const nx = leftX + arenaW / 2 + Math.cos(node.a) * 90;\n  const ny = arenaY + arenaH / 2 + 10 + Math.sin(node.a) * 30;\n  \n  ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n  ctx.strokeStyle = '#22d3ee';\n  ctx.lineWidth = 1.5;\n  ctx.beginPath();\n  ctx.roundRect(nx - 45, ny - 15, 90, 30, 8);\n  ctx.fill();\n  ctx.stroke();\n  \n  ctx.fillStyle = '#22d3ee';\n  ctx.font = 'bold 12px monospace';\n  ctx.fillText(node.name, nx, ny + 5);\n});\n\nctx.fillStyle = '#22d3ee';\nctx.font = 'bold 15px monospace';\nctx.textAlign = 'center';\nctx.fillText(\"NHÓM CHÂU Á\", rightX + arenaW / 2, arenaY + 26);\n\nconst asiaNodes = [\n  { name: \"DeepSeek V3\", a: -time * 1.3 },\n  { name: \"Qwen / Kimi\", a: -time * 1.3 + Math.PI }\n];\nasiaNodes.forEach(node => {\n  const nx = rightX + arenaW / 2 + Math.cos(node.a) * 90;\n  const ny = arenaY + arenaH / 2 + 10 + Math.sin(node.a) * 30;\n  \n  ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n  ctx.strokeStyle = '#22d3ee';\n  ctx.lineWidth = 1.5;\n  ctx.beginPath();\n  ctx.roundRect(nx - 55, ny - 15, 110, 30, 8);\n  ctx.fill();\n  ctx.stroke();\n  \n  ctx.fillStyle = '#22d3ee';\n  ctx.font = 'bold 12px monospace';\n  ctx.fillText(node.name, nx, ny + 5);\n});\n\nctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';\nctx.lineWidth = 1;\nctx.beginPath();\nctx.moveTo(cx, arenaY + 10);\nctx.lineTo(cx, arenaY + arenaH - 10);\nctx.stroke();\n\nctx.restore();"},
    {"name": "bk_toi_tubecreate_nen", "when": "Tôi là TubeCreate. Để vẽ nên một tấm bản đồ vĩ đại, bạn cần hai thứ: m", "code": "ctx.save();\nconst cx=W/2,cy=cursorY+150;\n// X-Ray engine room visualization\nconst pulse=1+0.04*Math.sin(time*2.5);\n// Outer casing\nctx.fillStyle='rgba(15,23,42,0.8)';ctx.strokeStyle='rgba(148,163,184,0.4)';ctx.lineWidth=2;\nctx.save();ctx.shadowColor='rgba(148,163,184,0.4)';ctx.shadowBlur=12;ctx.beginPath();ctx.roundRect(cx-220,cy-120,440,240,16);ctx.fill();ctx.stroke();ctx.restore();\n// Left engine: @core\nctx.fillStyle='rgba(5,30,50,0.9)';ctx.strokeStyle=rc('cyan');ctx.lineWidth=3;\nctx.save();ctx.shadowColor=rc('cyan');ctx.shadowBlur=18*pulse;ctx.beginPath();ctx.roundRect(cx-210,cy-110,190,220,12);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('cyan');ctx.font='bold 13px monospace';ctx.textAlign='center';ctx.fillText('@core',cx-115,cy-88);\nctx.fillStyle='rgba(148,163,184,0.7)';ctx.font='10px monospace';ctx.fillText('Engine',cx-115,cy-72);\n// spinning gear inside left engine\nctx.save();ctx.translate(cx-115,cy+10);ctx.rotate(time*0.8);\nconst teeth=8,gR=30;\nctx.strokeStyle=rc('cyan');ctx.lineWidth=2;ctx.beginPath();for(let i=0;i<teeth*2;i++){const a=i*Math.PI/teeth;const r=i%2===0?gR:gR*0.75;ctx.lineTo(Math.cos(a)*r,Math.sin(a)*r);}ctx.closePath();ctx.stroke();ctx.restore();\n// Right engine: @dashboard\nctx.fillStyle='rgba(30,20,5,0.9)';ctx.strokeStyle=rc('yellow');ctx.lineWidth=3;\nctx.save();ctx.shadowColor=rc('yellow');ctx.shadowBlur=18*pulse;ctx.beginPath();ctx.roundRect(cx+20,cy-110,190,220,12);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('yellow');ctx.font='bold 13px monospace';ctx.textAlign='center';ctx.fillText('@dashboard',cx+115,cy-88);\nctx.fillStyle='rgba(148,163,184,0.7)';ctx.font='10px monospace';ctx.fillText('Display',cx+115,cy-72);\n// monitor inside right engine\nctx.strokeStyle=rc('yellow');ctx.lineWidth=2;ctx.beginPath();ctx.roundRect(cx+80,cy-20,70,50,4);ctx.stroke();\nctx.fillStyle='rgba(234,179,8,0.15)';ctx.fillRect(cx+80,cy-20,70,50);\nfor(let i=0;i<4;i++){ctx.fillStyle=`rgba(56,189,248,${0.5+0.3*Math.sin(time*2+i)})`;ctx.fillRect(cx+84,cy-15+i*11,60,8);}\n// pipe between\nctx.strokeStyle='rgba(168,85,247,0.8)';ctx.lineWidth=4;\nctx.save();ctx.shadowColor='rgba(168,85,247,0.8)';ctx.shadowBlur=14;\nctx.beginPath();ctx.moveTo(cx-20,cy);ctx.lineTo(cx+20,cy);ctx.stroke();ctx.restore();\n// data pulse along pipe\nconst pipePos=((time*0.7)%1);\nconst px=cx-20+pipePos*40;ctx.fillStyle='#a855f7';\nctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=12;ctx.beginPath();ctx.arc(px,cy,5,0,Math.PI*2);ctx.fill();ctx.restore();\nctx.restore();return 380;"},
    {"name": "bk_ngay_hinh_mang", "when": "Ngay cả các mô hình mạng thần kinh nhân tạo AI phức tạp nhất hiện nay ", "code": "ctx.save();\nconst cx = W / 2;\nconst isPortrait = H > W;\nconst w = W - MX * 2;\nconst x = cx - w / 2;\nconst y = cursorY + 10;\nconst frameH = isPortrait ? 520 : 720;\n\nctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\nctx.strokeStyle = 'rgba(255,255,255,0.08)';\nctx.lineWidth = 2.5;\nctx.beginPath(); ctx.roundRect(x, y, w, frameH, 20); ctx.fill(); ctx.stroke();\n\nconst cy = y + frameH/2 - 20;\n\n// Draw neural network nodes layered\n// Layer 1 (Left): 3 nodes, Layer 2 (Center): 4 nodes, Layer 3 (Right): 2 nodes\nconst l1 = [cy - 60, cy, cy + 60];\nconst l2 = [cy - 90, cy - 30, cy + 30, cy + 90];\nconst l3 = [cy - 30, cy + 30];\n\n// Draw connections first\nctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';\nctx.lineWidth = 2.0;\n\nl1.forEach(y1 => {\n  l2.forEach(y2 => {\n    ctx.beginPath(); ctx.moveTo(cx - 150, y1); ctx.lineTo(cx, y2); ctx.stroke();\n  });\n});\n\nl2.forEach(y2 => {\n  l3.forEach(y3 => {\n    ctx.beginPath(); ctx.moveTo(cx, y2); ctx.lineTo(cx + 150, y3); ctx.stroke();\n  });\n});\n\n// Draw Nodes\nctx.lineWidth = 2.5;\n\nl1.forEach(y1 => {\n  ctx.fillStyle = '#0f172a'; ctx.strokeStyle = '#22d3ee';\n  ctx.beginPath(); ctx.arc(cx - 150, y1, 14, 0, Math.PI*2); ctx.fill(); ctx.stroke();\n});\n\nl2.forEach(y2 => {\n  ctx.fillStyle = '#0f172a'; ctx.strokeStyle = '#FFD700';\n  ctx.beginPath(); ctx.arc(cx, y2, 14, 0, Math.PI*2); ctx.fill(); ctx.stroke();\n});\n\nl3.forEach(y3 => {\n  ctx.fillStyle = '#0f172a'; ctx.strokeStyle = '#10b981';\n  ctx.beginPath(); ctx.arc(cx + 150, y3, 14, 0, Math.PI*2); ctx.fill(); ctx.stroke();\n});\n\nctx.restore();\nreturn frameH + 80;"},
    {"name": "bk_minh_cung_ket", "when": "Trong bài ba, mình cùng các bạn kết nối bộ não AI cho OpenClaw. Mục ti", "code": "ctx.save();\nconst cx = W / 2;\nconst cy = cursorY + 110;\nconst r = 60;\n\nctx.strokeStyle = 'rgba(34, 211, 238, 0.05)';\nctx.lineWidth = 1.5;\nfor (let i = 0; i < 8; i++) {\n  const angle = (i * Math.PI) / 4;\n  ctx.beginPath();\n  ctx.moveTo(cx + Math.cos(angle) * (r + 15), cy + Math.sin(angle) * (r + 15));\n  ctx.lineTo(cx + Math.cos(angle) * (r + 120), cy + Math.sin(angle) * (r + 120));\n  ctx.stroke();\n}\n\nconst waveCount = 3;\nfor (let i = 0; i < waveCount; i++) {\n  const waveProg = ((time * 0.15 + i / waveCount) % 1.0);\n  const waveR = r + waveProg * 100;\n  ctx.strokeStyle = `rgba(34, 211, 238, ${0.3 * (1 - waveProg)})`;\n  ctx.lineWidth = 2;\n  ctx.beginPath();\n  ctx.arc(cx, cy, waveR, 0, Math.PI * 2);\n  ctx.stroke();\n}\n\nconst providers = [\n  { name: \"OpenAI Cloud\", icon: \"🌐\", a: -Math.PI / 2, color: \"cyan\" },\n  { name: \"Claude Cloud\", icon: \"⚡\", a: Math.PI / 6, color: \"highlight\" },\n  { name: \"Ollama Local\", icon: \"💻\", a: (5 * Math.PI) / 6, color: \"green\" }\n];\n\nproviders.forEach((prov, idx) => {\n  const targetX = cx + Math.cos(prov.a) * 110;\n  const targetY = cy + Math.sin(prov.a) * 110;\n\n  ctx.strokeStyle = 'rgba(255, 255, 255, 0.12)';\n  ctx.lineWidth = 2.5;\n  ctx.beginPath();\n  ctx.moveTo(cx, cy);\n  ctx.lineTo(targetX, targetY);\n  ctx.stroke();\n\n  const pulseProg = (time * 0.25 + idx * 0.3) % 1.0;\n  const px = cx + (targetX - cx) * pulseProg;\n  const py = cy + (targetY - cy) * pulseProg;\n  ctx.fillStyle = rc(prov.color);\n  ctx.shadowColor = rc(prov.color);\n  ctx.shadowBlur = 10;\n  ctx.beginPath();\n  ctx.arc(px, py, 5, 0, Math.PI * 2);\n  ctx.fill();\n  ctx.shadowBlur = 0;\n\n  ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';\n  ctx.strokeStyle = rc(prov.color);\n  ctx.lineWidth = 1.5;\n  ctx.beginPath();\n  ctx.roundRect(targetX - 25, targetY - 25, 50, 50, 12);\n  ctx.fill();\n  ctx.stroke();\n\n  ctx.font = '24px sans-serif';\n  ctx.textAlign = 'center';\n  ctx.textBaseline = 'middle';\n  ctx.fillText(prov.icon, targetX, targetY - 2);\n\n  ctx.fillStyle = '#22d3ee';\n  ctx.font = 'bold 14px monospace';\n  ctx.fillText(prov.name, targetX, targetY + 40);\n});\n\nctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\nctx.strokeStyle = '#22d3ee';\nctx.lineWidth = 3;\nctx.shadowColor = '#22d3ee';\nctx.shadowBlur = 15;\nctx.beginPath();\nctx.roundRect(cx - 35, cy - 35, 70, 70, 18);\nctx.fill();\nctx.stroke();\nctx.shadowBlur = 0;\n\nconst brainPulse = 1 + 0.08 * Math.sin(time * 2);\nctx.font = `${Math.round(36 * brainPulse)}px sans-serif`;\nctx.textAlign = 'center';\nctx.textBaseline = 'middle';\nctx.fillText('🧠', cx, cy - 2);\n\nctx.restore();"},
    {"name": "bk_dieu_thu_tien", "when": "Điều thú vị là tiền trong Escrow không thực sự ngồi trong một tài khoả", "code": "ctx.save();\nconst cx = W/2, cy = cursorY + 140;\n\n// Wallet breakdown\nconst totalAmt = 500000;\nconst heldAmt = stepProgress > 0.4 ? 150000 : 0;\nconst availAmt = totalAmt - heldAmt;\n\n// Outer wallet\nctx.fillStyle = '#0f172a'; ctx.strokeStyle = '#6366f1'; ctx.lineWidth = 4;\nctx.beginPath(); ctx.roundRect(cx - 160, cy - 80, 320, 100, 14); ctx.fill(); ctx.stroke();\nctx.fillStyle = '#a78bfa'; ctx.font = 'bold 13px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'top';\nctx.fillText('💼 Tổng số dư: ' + totalAmt.toLocaleString('vi') + 'đ', cx, cy - 68);\n\n// Available bar\nconst barW = 280, barY = cy - 30;\nctx.fillStyle = '#1e293b'; ctx.strokeStyle = '#334155'; ctx.lineWidth = 2;\nctx.beginPath(); ctx.roundRect(cx - barW/2, barY, barW, 28, 6); ctx.fill(); ctx.stroke();\nconst availW = (availAmt / totalAmt) * barW;\nctx.fillStyle = '#10b981'; ctx.save(); ctx.shadowColor = '#10b981'; ctx.shadowBlur = 8;\nctx.beginPath(); ctx.roundRect(cx - barW/2, barY, availW, 28, 6); ctx.fill(); ctx.restore();\nctx.fillStyle = '#ffffff'; ctx.font = 'bold 11px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\nctx.fillText(`✅ Available: ${availAmt.toLocaleString('vi')}đ`, cx - barW/2 + availW/2, barY + 14);\n\nif (heldAmt > 0) {\n  const heldW = barW - availW;\n  ctx.fillStyle = '#fbbf24'; ctx.save(); ctx.shadowColor = '#fbbf24'; ctx.shadowBlur = 8;\n  ctx.beginPath(); ctx.roundRect(cx - barW/2 + availW, barY, heldW, 28, 6); ctx.fill(); ctx.restore();\n  ctx.fillStyle = '#0f172a'; ctx.font = 'bold 11px monospace';\n  ctx.fillText(`🔒 Held: ${heldAmt.toLocaleString('vi')}đ`, cx - barW/2 + availW + heldW/2, barY + 14);\n}\n\n// DB table\nif (stepProgress > 0.6) {\n  const tRows = [\n    ['u_4f2a', availAmt.toLocaleString('vi')+'đ', heldAmt.toLocaleString('vi')+'đ'],\n  ];\n  const thCols = ['user_id', 'available_balance', 'held_balance'];\n  const tw = 320, txStart = cx - tw/2;\n  ctx.fillStyle = '#1e293b'; ctx.strokeStyle = '#6366f1'; ctx.lineWidth = 2;\n  ctx.beginPath(); ctx.roundRect(txStart, cy + 50, tw, 32, [6,6,0,0]); ctx.fill(); ctx.stroke();\n  thCols.forEach((h,i) => {\n    ctx.fillStyle = '#a78bfa'; ctx.font = 'bold 9px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText(h, txStart + (tw/3)*i + tw/6, cy + 66);\n  });\n  ctx.fillStyle = 'rgba(15,23,42,0.9)'; ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;\n  ctx.beginPath(); ctx.roundRect(txStart, cy+82, tw, 36, [0,0,6,6]); ctx.fill(); ctx.stroke();\n  tRows[0].forEach((v,i) => {\n    ctx.fillStyle = i > 0 ? (i===1?'#10b981':'#fbbf24') : '#cbd5e1'; ctx.font = 'bold 10px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText(v, txStart + (tw/3)*i + tw/6, cy+100);\n  });\n}\n\nctx.restore();\nreturn 280;"},
    {"name": "bk_vuot_qua_gioi", "when": "Để vượt qua giới hạn cứng nhắc đó, các nhà khoa học đã lấy cảm hứng từ", "code": "ctx.save();\nconst cx = W / 2;\nconst y = cursorY + 10;\nconst frameH = 520;\nconst cy = y + frameH/2;\n\nconst p_intro = Math.min(1.0, stepProgress / 0.35);\n\n// Highly premium multi-layer network structure\nconst layers = [3, 4, 3]; // Input, Hidden, Output layers\nconst colSpacing = 160;\nconst rowSpacing = 85;\n\nconst nodeCoords = [];\n\nlayers.forEach((count, colIdx) => {\n  const colX = cx + (colIdx - 1) * colSpacing;\n  const startRowY = cy - ((count - 1) * rowSpacing) / 2;\n  const colNodes = [];\n  for (let rIdx = 0; rIdx < count; rIdx++) {\n    colNodes.push({x: colX, y: startRowY + rIdx * rowSpacing, col: colIdx});\n  }\n  nodeCoords.push(colNodes);\n});\n\n// Draw synapses / connecting links with glowing wave pulses\nctx.lineWidth = 2.5;\nfor (let c = 0; c < layers.length - 1; c++) {\n  const currentNodes = nodeCoords[c];\n  const nextNodes = nodeCoords[c+1];\n  currentNodes.forEach(n1 => {\n    nextNodes.forEach(n2 => {\n      const alpha = Math.min(1.0, Math.max(0, (p_intro - 0.2) * 2.0));\n      ctx.strokeStyle = `rgba(124, 58, 237, ${alpha * 0.35})`;\n      ctx.beginPath(); ctx.moveTo(n1.x, n1.y); ctx.lineTo(n2.x, n2.y); ctx.stroke();\n      \n      // Moving neural pulse signal\n      const pulseT = (time * 1.2 + n1.y * 0.005) % 1.0;\n      const px = n1.x + (n2.x - n1.x) * pulseT;\n      const py = n1.y + (n2.y - n1.y) * pulseT;\n      ctx.fillStyle = '#22d3ee'; ctx.shadowColor = '#22d3ee';\n      ctx.shadowBlur = 6;\n      ctx.beginPath(); ctx.arc(px, py, 4, 0, Math.PI*2); ctx.fill();\n      ctx.shadowBlur = 0;\n    });\n  });\n}\n\n// Draw neural nodes\nnodeCoords.forEach((col, cIdx) => {\n  col.forEach(n => {\n    ctx.save();\n    ctx.translate(n.x, n.y);\n    ctx.scale(Math.max(0.0001, p_intro), Math.max(0.0001, p_intro));\n    \n    ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n    ctx.strokeStyle = cIdx === 0 ? '#22d3ee' : (cIdx === 1 ? '#a78bfa' : '#facc15');\n    ctx.shadowColor = ctx.strokeStyle;\n    ctx.shadowBlur = 8;\n    ctx.lineWidth = 3;\n    ctx.beginPath(); ctx.arc(0, 0, 20, 0, Math.PI*2); ctx.fill(); ctx.stroke();\n    ctx.restore();\n  });\n});\n\nctx.restore();"},
    {"name": "bk_cam_doi_hoc", "when": "Cảm ơn các bạn đã theo dõi bài học hôm nay. TubeCreate - Nền tảng phát", "code": "const logoPath='/api/v1/edu_video/gallery/file/logo_tubecreate.png';if(typeof window!=='undefined'&&typeof _loadPreviewImage==='function'){_loadPreviewImage(logoPath);}ctx.save();ctx.beginPath();ctx.rect(0,cursorY,W,560);ctx.clip();const cx=W/2,weightY=cursorY+240;for(let i=0;i<30;i++){const sx=Math.sin(i*137.5)*W*.44+cx,sy=cursorY+150+Math.cos(i*137.5)*130;ctx.fillStyle=`rgba(255,255,255,${0.06+0.04*Math.sin(time*.5+i*.6)})`;ctx.beginPath();ctx.arc(sx,sy,1+Math.sin(time+i)*.5,0,Math.PI*2);ctx.fill();}const rGlow=ctx.createRadialGradient(cx,weightY-50,10,cx,weightY-50,300);rGlow.addColorStop(0,'rgba(99,102,241,0.14)');rGlow.addColorStop(1,'rgba(0,0,0,0)');ctx.fillStyle=rGlow;ctx.fillRect(0,cursorY,W,560);let scale=0;if(stepProgress<.45){const t=stepProgress/.45;scale=1-Math.pow(1-t,3.5)*Math.cos(t*Math.PI*2.8);}else{scale=1+.015*Math.sin(time*2.5);}const img=(typeof window!=='undefined'&&window._PREVIEW_IMG_CACHE&&window._PREVIEW_IMG_CACHE[logoPath])||(typeof global!=='undefined'&&global.IMAGE_CACHE&&global.IMAGE_CACHE[logoPath]);if(img){ctx.save();ctx.translate(cx,weightY-50);ctx.scale(scale,scale);ctx.shadowColor='rgba(99,102,241,0.7)';ctx.shadowBlur=40;ctx.drawImage(img,-90,-90,180,180);ctx.restore();}ctx.strokeStyle='rgba(99,102,241,0.25)';ctx.lineWidth=2;ctx.beginPath();ctx.arc(cx,weightY-50,114,0,Math.PI*2);ctx.stroke();const orbX=cx+114*Math.cos(time*0.8),orbY=weightY-50+114*Math.sin(time*0.8);ctx.fillStyle='rgba(99,102,241,0.9)';ctx.save();ctx.shadowColor='rgba(99,102,241,1)';ctx.shadowBlur=14;ctx.beginPath();ctx.arc(orbX,orbY,5,0,Math.PI*2);ctx.fill();ctx.restore();const ta=Math.min(1,Math.max(0,(stepProgress-.4)*3.5));ctx.font='bold 48px sans-serif';ctx.textAlign='center';ctx.fillStyle=`rgba(255,255,255,${ta})`;ctx.save();ctx.shadowColor='rgba(99,102,241,.7)';ctx.shadowBlur=20;ctx.fillText('TubeCreate',cx,weightY+80);ctx.restore();const ta2=Math.min(1,Math.max(0,(stepProgress-.6)*4));if(ta2>0){ctx.save();ctx.globalAlpha=ta2;ctx.fillStyle='rgba(8,14,36,.95)';ctx.strokeStyle='rgba(99,102,241,.45)';ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(cx-290,weightY+108,580,88,14);ctx.fill();ctx.stroke();ctx.fillStyle='rgba(255,255,255,.5)';ctx.font='bold 15px monospace';ctx.textAlign='center';ctx.fillText('BÀI TIẾP THEO',cx,weightY+134);ctx.fillStyle='rgba(99,102,241,.9)';ctx.font='bold 22px monospace';ctx.fillText('Bài 12 - 3 Loại Hình Trong Nghiên Cứu Khoa Học',cx,weightY+162);ctx.restore();}ctx.restore();"},
    {"name": "bk_output_quality_validation", "when": "Output quality validation. Sau khi mô hình ngôn ngữ lớn extract, scrip", "code": "ctx.save();const cx=W/2,cy=cursorY+420;\nctx.fillStyle='#fff';ctx.font='bold 50px \"Inter\",sans-serif';ctx.textAlign='center';\nctx.save();ctx.shadowColor='rgba(34,197,94,0.5)';ctx.shadowBlur=18;\nctx.fillText('Quality Validation',cx,cursorY+110);ctx.restore();\nctx.fillStyle=rc('green');ctx.font='bold 28px monospace';\nctx.fillText('4 auto-checks sau mỗi extraction',cx,cursorY+168);\nctx.strokeStyle='rgba(34,197,94,0.25)';ctx.lineWidth=1.5;\nctx.beginPath();ctx.moveTo(MX,cursorY+196);ctx.lineTo(W-MX,cursorY+196);ctx.stroke();\n// Circular quality meter\nconst score=Math.min(100,Math.floor(time*25)%110);\nconst scoreA=score/100;\nconst startA=-Math.PI*0.8,endA=Math.PI*0.8;\nconst sweepA=startA+(endA-startA)*scoreA;\n// Outer ring\nctx.strokeStyle='rgba(255,255,255,0.08)';ctx.lineWidth=18;\nctx.beginPath();ctx.arc(cx,cy-20,100,startA,endA);ctx.stroke();\n// Score arc\nconst arcG=ctx.createLinearGradient(cx-100,0,cx+100,0);\narcG.addColorStop(0,'#ef4444');arcG.addColorStop(0.5,'#eab308');arcG.addColorStop(1,'#22c55e');\nctx.strokeStyle=arcG;ctx.lineWidth=18;\nctx.save();ctx.shadowColor='rgba(34,197,94,0.5)';ctx.shadowBlur=18;\nctx.beginPath();ctx.arc(cx,cy-20,100,startA,sweepA);ctx.stroke();ctx.restore();\n// Score label\nconst scoreCol=score>=80?'#22c55e':score>=60?'#eab308':'#ef4444';\nctx.fillStyle=scoreCol;ctx.font='bold 52px \"Inter\",sans-serif';ctx.textAlign='center';\nctx.save();ctx.shadowColor=scoreCol;ctx.shadowBlur=20;\nctx.fillText(score+'%',cx,cy-6);ctx.restore();\nctx.fillStyle='rgba(148,163,184,0.7)';ctx.font='bold 22px monospace';\nctx.fillText('Quality Score',cx,cy+26);\n// 4 checks around the meter\nconst checks=[\n  {l:'Author attribution',s:score>30?'✓':'...',c:'#38bdf8',x:cx-300,y:cy-100},\n  {l:'Anti-patterns',s:score>55?'✓':'...',c:'#a855f7',x:cx+300,y:cy-100},\n  {l:'Concise sentences',s:score>75?'✓':'...',c:'#eab308',x:cx-300,y:cy+60},\n  {l:'Cross-references',s:score>90?'✓':'...',c:'#22c55e',x:cx+300,y:cy+60},\n];\nfor(const ch of checks){const isOk=ch.s==='✓';ctx.fillStyle='rgba(12,20,38,0.97)';ctx.strokeStyle=isOk?ch.c:ch.c+'40';ctx.lineWidth=2;\nctx.save();if(isOk){ctx.shadowColor=ch.c;ctx.shadowBlur=14;}\nctx.beginPath();ctx.roundRect(ch.x-110,ch.y-38,220,76,10);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=isOk?ch.c:'rgba(148,163,184,0.4)';ctx.font='bold 28px monospace';ctx.textAlign='center';\nctx.fillText(ch.s,ch.x,ch.y-2);ctx.fillStyle='rgba(148,163,184,0.7)';ctx.font='18px monospace';\nctx.fillText(ch.l,ch.x,ch.y+24);}\n// Threshold line\nconst thresh=0.8;const threshA=startA+(endA-startA)*thresh;\nctx.strokeStyle='rgba(255,255,255,0.4)';ctx.lineWidth=2;ctx.setLineDash([6,4]);\nctx.beginPath();ctx.moveTo(cx+Math.cos(threshA)*85,cy-20+Math.sin(threshA)*85);ctx.lineTo(cx+Math.cos(threshA)*118,cy-20+Math.sin(threshA)*118);ctx.stroke();ctx.setLineDash([]);\nctx.fillStyle='rgba(239,68,68,0.8)';ctx.font='bold 20px monospace';\nctx.fillText('80% threshold',cx+Math.cos(threshA)*132,cy-20+Math.sin(threshA)*132);\nctx.fillStyle=score<80?rc('red'):rc('green');ctx.font='bold 26px monospace';ctx.textAlign='center';\nctx.fillText(score<80?'→ Re-extract with stronger prompt':'→ Approved — compile to skill files!',cx,cy+270);\nctx.restore();return 1100;"},
    {"name": "bk_nguyen_duoc_goi", "when": "Nguyên lý này được gọi là Iteration — Lặp Cải Tiến. Bạn tìm một mô hìn", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 140;\n\n// Spiral iteration: v1 → v2 → v3 (expanding)\nconst center = {x: cx - 60, y: cy};\nconst spiralProgress = Math.min(1.0, stepProgress * 1.1);\n\n// Draw spiral\nctx.strokeStyle = rc('highlight'); ctx.lineWidth = 3;\nctx.beginPath();\nfor (let a = 0; a <= Math.PI * 5 * spiralProgress; a += 0.05) {\n  const r = 15 + a * 18;\n  const px = center.x + Math.cos(a) * r;\n  const py = center.y + Math.sin(a) * r * 0.5;\n  if (a < 0.01) ctx.moveTo(px, py); else ctx.lineTo(px, py);\n}\nctx.stroke();\n\n// Version labels at key points - Bigger\nconst versions = [\n  {angle: Math.PI * 1.5, r: 70, label: 'v1\\nCopied', color: 'cyan'},\n  {angle: Math.PI * 3.5, r: 140, label: 'v2\\n+UX Better', color: 'yellow'},\n  {angle: Math.PI * 5.5, r: 220, label: 'v3\\n+Price/Scale', color: 'green'},\n];\nversions.forEach((v, idx) => {\n  if (spiralProgress < (idx + 1) * 0.3) return;\n  const vx = center.x + Math.cos(v.angle) * v.r;\n  const vy = center.y + Math.sin(v.angle) * v.r * 0.5;\n  const pulse = 1 + 0.1 * Math.sin(time * 3 + idx);\n  ctx.fillStyle = rc(v.color); ctx.save(); ctx.shadowColor = rc(v.color); ctx.shadowBlur = 14;\n  ctx.beginPath(); ctx.arc(vx, vy, 18 * pulse, 0, Math.PI*2); ctx.fill();\n  ctx.restore();\n  ctx.fillStyle = '#fff'; ctx.font = 'bold 16px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText(idx + 1, vx, vy);\n  ctx.fillStyle = rc(v.color); ctx.font = 'bold 22px monospace'; ctx.textBaseline = 'alphabetic';\n  v.label.split('\\n').forEach((line, li) => {\n    ctx.fillText(line, vx + 28 * (Math.cos(v.angle) > 0 ? 1 : -1), vy - 8 + li * 24);\n  });\n});\n\n// Uber case on the right - Enlarge text\nif (spiralProgress > 0.6) {\n  const ux = cx + 180, uy = cy;\n  ctx.fillStyle = 'rgba(15,23,42,0.9)'; ctx.strokeStyle = rc('yellow'); ctx.lineWidth = 3;\n  ctx.beginPath(); ctx.roundRect(ux - 90, uy - 90, 180, 180, 12); ctx.fill(); ctx.stroke();\n  ctx.fillStyle = '#fff'; ctx.font = '36px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('🚗', ux, uy - 50);\n  ctx.fillStyle = rc('yellow'); ctx.font = 'bold 24px monospace'; ctx.textBaseline = 'alphabetic';\n  ctx.fillText('UBER', ux, uy - 8);\n  const adds = ['+GPS', '+No Cash', '+Rating'];\n  adds.forEach((a, i) => {\n    ctx.fillStyle = rc('green'); ctx.font = 'bold 20px monospace';\n    ctx.fillText(a, ux, uy + 18 + i * 26);\n  });\n}\n\nctx.restore();\nreturn 380;"},
    {"name": "bk_micro_niche_phan", "when": "Micro-Niche là một phân khúc thị trường cực kỳ cụ thể và hẹp — nhỏ đến", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 140;\n\n// Zooming drill-down from broad to micro\nconst levels = [\n  {label: 'Thị trường:\\nSức khỏe', r: 150, color: 'cyan', alpha: 0.08},\n  {label: 'Niche:\\nYoga', r: 100, color: 'yellow', alpha: 0.12},\n  {label: 'Sub-niche:\\nYoga phụ nữ', r: 60, color: 'highlight', alpha: 0.18},\n  {label: 'Micro:\\nYoga bầu T7', r: 26, color: 'green', alpha: 0.6},\n];\n\nconst drillProg = Math.min(1.0, stepProgress * 1.2);\n\nlevels.forEach((lv, idx) => {\n  const show = drillProg > idx * 0.2;\n  if (!show) return;\n  const pulse = idx === levels.length - 1 ? 1 + 0.1 * Math.sin(time * 3) : 1;\n  const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, lv.r * pulse);\n  grad.addColorStop(0, `rgba(15,23,42,${lv.alpha + 0.05})`);\n  grad.addColorStop(1, `rgba(15,23,42,0)`);\n  ctx.fillStyle = grad;\n  ctx.strokeStyle = show ? rc(lv.color) : 'rgba(255,255,255,0.05)'; ctx.lineWidth = idx === levels.length - 1 ? 3 : 1.5;\n  if (idx === levels.length - 1) { ctx.save(); ctx.shadowColor = rc(lv.color); ctx.shadowBlur = 22 * pulse; }\n  ctx.beginPath(); ctx.arc(cx, cy, lv.r * pulse, 0, Math.PI*2); ctx.fill(); ctx.stroke();\n  if (idx === levels.length - 1) ctx.restore();\n  // Label - Bigger\n  const lAngle = idx * 0.7 + 0.5;\n  const lr = lv.r + 24;\n  const labelX = cx + Math.cos(lAngle) * lr;\n  const labelY = cy + Math.sin(lAngle) * lr;\n  ctx.fillStyle = show ? rc(lv.color) : 'rgba(255,255,255,0.15)'; ctx.font = `bold ${idx === 3 ? 22 : 18}px monospace`; ctx.textAlign = 'center';\n  lv.label.split('\\n').forEach((line, li) => {\n    ctx.fillText(line, labelX + (idx % 2 === 0 ? 60 : -60), labelY - 8 + li * 24);\n  });\n});\n\n// Center: Micro label - Bigger\nconst cPulse = 1 + 0.12 * Math.sin(time * 4);\nctx.fillStyle = rc('green'); ctx.save(); ctx.shadowColor = rc('green'); ctx.shadowBlur = 18;\nctx.font = `bold ${Math.round(24 * cPulse)}px monospace`; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\nctx.fillText('MICRO', cx, cy);\nctx.restore();\n\n// Right side: comparison label - Bigger\nif (drillProg > 0.7) {\n  ctx.fillStyle = rc('green'); ctx.font = 'bold 24px sans-serif'; ctx.textAlign = 'center';\n  ctx.fillText('Càng cụ thể → CVR càng cao 🎯', cx, cy + 200);\n}\n\nctx.restore();\nreturn 380;"},
    {"name": "bk_hay_trung_tim", "when": "Hãy tập trung tìm kiếm các 'điểm nghẽn' trong quy trình sản xuất video", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 135;\n\n// Animated 24/7 clock with rotating elements\nconst clockRadius = 70;\n\n// Outer glow rings\nfor (let i = 0; i < 3; i++) {\n    const ringScale = 1 + i * 0.15 + 0.05 * Math.sin(time * 2 + i);\n    ctx.strokeStyle = rc('green');\n    ctx.lineWidth = 3 - i;\n    ctx.save();\n    ctx.globalAlpha = 0.3 - i * 0.1;\n    ctx.shadowColor = rc('green');\n    ctx.shadowBlur = 20;\n    ctx.beginPath();\n    ctx.arc(cx, cy - 20, clockRadius * ringScale, 0, Math.PI * 2);\n    ctx.stroke();\n    ctx.restore();\n}\n\n// Main clock circle\nctx.fillStyle = 'rgba(15,23,42,0.95)';\nctx.strokeStyle = rc('green');\nctx.lineWidth = 5;\nctx.save();\nctx.shadowColor = rc('green');\nctx.shadowBlur = 25;\nctx.beginPath();\nctx.arc(cx, cy - 20, clockRadius, 0, Math.PI * 2);\nctx.fill();\nctx.stroke();\nctx.restore();\n\n// Clock numbers\nctx.fillStyle = rc('cyan');\nctx.font = 'bold 16px monospace';\nctx.textAlign = 'center';\nfor (let i = 0; i < 12; i++) {\n    const angle = (i * Math.PI / 6) - Math.PI / 2;\n    const nx = cx + Math.cos(angle) * (clockRadius - 20);\n    const ny = cy - 20 + Math.sin(angle) * (clockRadius - 20) + 5;\n    const num = i === 0 ? 12 : i;\n    ctx.fillText(num, nx, ny);\n}\n\n// Animated clock hands\nconst hourAngle = (time * 0.5) % (Math.PI * 2) - Math.PI / 2;\nconst minuteAngle = (time * 2) % (Math.PI * 2) - Math.PI / 2;\nconst secondAngle = (time * 6) % (Math.PI * 2) - Math.PI / 2;\n\n// Hour hand\nctx.strokeStyle = rc('yellow');\nctx.lineWidth = 6;\nctx.save();\nctx.shadowColor = rc('yellow');\nctx.shadowBlur = 10;\nctx.beginPath();\nctx.moveTo(cx, cy - 20);\nctx.lineTo(cx + Math.cos(hourAngle) * 25, cy - 20 + Math.sin(hourAngle) * 25);\nctx.stroke();\nctx.restore();\n\n// Minute hand\nctx.strokeStyle = rc('cyan');\nctx.lineWidth = 4;\nctx.save();\nctx.shadowColor = rc('cyan');\nctx.shadowBlur = 10;\nctx.beginPath();\nctx.moveTo(cx, cy - 20);\nctx.lineTo(cx + Math.cos(minuteAngle) * 40, cy - 20 + Math.sin(minuteAngle) * 40);\nctx.stroke();\nctx.restore();\n\n// Second hand\nctx.strokeStyle = rc('red');\nctx.lineWidth = 2;\nctx.beginPath();\nctx.moveTo(cx, cy - 20);\nctx.lineTo(cx + Math.cos(secondAngle) * 50, cy - 20 + Math.sin(secondAngle) * 50);\nctx.stroke();\n\n// Center dot\nctx.fillStyle = '#fff';\nctx.beginPath();\nctx.arc(cx, cy - 20, 6, 0, Math.PI * 2);\nctx.fill();\n\n// 24/7 text with pulse\nconst textPulse = 1 + 0.1 * Math.sin(time * 3);\nctx.fillStyle = rc('yellow');\nctx.font = `bold ${Math.floor(40 * textPulse)}px monospace`;\nctx.textAlign = 'center';\nctx.save();\nctx.shadowColor = rc('yellow');\nctx.shadowBlur = 20;\nctx.fillText('24/7', cx, cy + 80);\nctx.restore();\n\n// Automation status\nctx.fillStyle = rc('green');\nctx.font = 'bold 18px monospace';\nctx.fillText('⚡ KHÔNG NGỪNG NGHỈ', cx, cy + 110);\n\nctx.restore();\nreturn 380;"},
    {"name": "bk_thong_phan_loai", "when": "Hệ thống phân loại sản phẩm trong Multi-vendor phức tạp hơn single-ven", "code": "ctx.save();\nconst cx = W/2, cy = cursorY + 135;\n\n// Global categories (top)\nconst globalCats = ['💻 Phần mềm', '🎨 Thiết kế', '🎵 Âm nhạc', '📚 Ebook'];\nctx.fillStyle = '#6366f1'; ctx.font = 'bold 12px monospace'; ctx.textAlign = 'center';\nctx.fillText('🌐 Global Categories (Platform)', cx, cy - 110);\nglobalCats.forEach((cat, i) => {\n  const gx = cx - 150 + i * 100;\n  const show = stepProgress > i * 0.12;\n  if (!show) return;\n  ctx.fillStyle = 'rgba(99,102,241,0.2)'; ctx.strokeStyle = '#6366f1'; ctx.lineWidth = 2;\n  ctx.beginPath(); ctx.roundRect(gx - 42, cy - 96, 84, 28, 6); ctx.fill(); ctx.stroke();\n  ctx.fillStyle = '#a78bfa'; ctx.font = '10px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText(cat, gx, cy - 82);\n});\n\n// Store tags (middle)\nif (stepProgress > 0.55) {\n  const tagGroups = [\n    {store: 'STR-A', tags: ['#plugin', '#figma', '#pro'], color: '#22d3ee'},\n    {store: 'STR-B', tags: ['#font', '#display', '#free'], color: '#f97316'},\n  ];\n  tagGroups.forEach((tg, gi) => {\n    ctx.fillStyle = tg.color; ctx.font = 'bold 11px monospace'; ctx.textAlign = 'center';\n    ctx.fillText(`🏪 ${tg.store} Tags`, cx - 130 + gi * 260, cy - 30);\n    tg.tags.forEach((tag, ti) => {\n      const tx = cx - 170 + gi * 260 + ti * 60, ty = cy;\n      ctx.fillStyle = `${tg.color}20`; ctx.strokeStyle = tg.color; ctx.lineWidth = 1.5;\n      ctx.beginPath(); ctx.roundRect(tx - 26, ty - 12, 52, 24, 12); ctx.fill(); ctx.stroke();\n      ctx.fillStyle = tg.color; ctx.font = '9px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n      ctx.fillText(tag, tx, ty);\n    });\n  });\n}\n\n// product_tags junction\nif (stepProgress > 0.75) {\n  ctx.fillStyle = '#1e293b'; ctx.strokeStyle = '#10b981'; ctx.lineWidth = 2;\n  ctx.beginPath(); ctx.roundRect(cx - 100, cy + 40, 200, 24, [6,6,0,0]); ctx.fill(); ctx.stroke();\n  ctx.fillStyle = '#6ee7b7'; ctx.font = 'bold 10px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('🔗 product_tags (junction)', cx, cy + 52);\n  ['product_id', 'tag_id'].forEach((c, i) => {\n    ctx.fillStyle = 'rgba(15,23,42,0.9)'; ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;\n    ctx.beginPath(); ctx.rect(cx - 100, cy + 64 + i*22, 200, 22); ctx.fill(); ctx.stroke();\n    ctx.fillStyle = '#fbbf24'; ctx.font = 'bold 9px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText('🔑 ' + c, cx, cy + 75 + i*22);\n  });\n}\n\nctx.restore();\nreturn 270;"},
    {"name": "bk_dang_app_len", "when": "Để đăng app lên Apple App Store với tư cách tổ chức hoặc doanh nghiệp,", "code": "ctx.save();\nconst cx = W/2, cy = cursorY + 145;\n\n// DUNS ID card\nconst cardW = 340, cardH = 160;\nconst cardX = cx - cardW/2, cardY = cy - 100;\nconst gradY = cardY;\nconst grd = ctx.createLinearGradient(cardX, gradY, cardX + cardW, gradY + cardH);\ngrd.addColorStop(0, '#1e3a5f'); grd.addColorStop(1, '#0f172a');\nctx.fillStyle = grd; ctx.strokeStyle = '#3b82f6'; ctx.lineWidth = 3;\nctx.save(); ctx.shadowColor = '#3b82f6'; ctx.shadowBlur = 20;\nctx.beginPath(); ctx.roundRect(cardX, cardY, cardW, cardH, 14); ctx.fill(); ctx.stroke(); ctx.restore();\n\n// D&B logo area\nctx.fillStyle = '#1d4ed8'; ctx.beginPath(); ctx.roundRect(cardX + 12, cardY + 12, 60, 28, 6); ctx.fill();\nctx.fillStyle = '#ffffff'; ctx.font = 'bold 11px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\nctx.fillText('D&B', cardX + 42, cardY + 26);\n\n// DUNS text\nctx.fillStyle = '#93c5fd'; ctx.font = 'bold 11px monospace'; ctx.textAlign = 'left'; ctx.textBaseline = 'top';\nctx.fillText('DATA UNIVERSAL NUMBERING SYSTEM', cardX + 16, cardY + 52);\n\nconst dunsNum = '123-456-789';\nctx.font = 'bold 34px monospace';\nctx.fillStyle = '#ffffff';\nctx.save(); ctx.shadowColor = '#60a5fa'; ctx.shadowBlur = 10;\nctx.fillText(dunsNum, cardX + 16, cardY + 70); ctx.restore();\n\nctx.fillStyle = '#64748b'; ctx.font = '10px monospace';\nctx.fillText('Entity: TUBECREATE TECHNOLOGY CO., LTD', cardX + 16, cardY + 112);\nctx.fillText('Country: VIETNAM | Status: ACTIVE', cardX + 16, cardY + 128);\n\n// Globe icon right\nctx.fillStyle = '#ffffff'; ctx.font = '36px sans-serif'; ctx.textAlign = 'right'; ctx.textBaseline = 'bottom';\nctx.fillText('🌐', cardX + cardW - 12, cardY + cardH - 10);\n\n// Stats below\nif (stepProgress > 0.5) {\n  const stats = [\n    {icon: '🌍', text: '200+ quốc gia công nhận', color: '#22d3ee'},\n    {icon: '🏢', text: 'Apple bắt buộc cho Organization', color: '#a78bfa'},\n    {icon: '📋', text: '9 chữ số định danh duy nhất', color: '#fbbf24'},\n  ];\n  stats.forEach((s, i) => {\n    const show = stepProgress > 0.5 + i * 0.1;\n    if (!show) return;\n    const sx = cx - 190 + i * 130, sy = cy + 82;\n    ctx.fillStyle = `${s.color}20`; ctx.strokeStyle = s.color; ctx.lineWidth = 1.5;\n    ctx.beginPath(); ctx.roundRect(sx - 60, sy - 22, 120, 44, 8); ctx.fill(); ctx.stroke();\n    ctx.fillStyle = '#ffffff'; ctx.font = '18px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText(s.icon, sx, sy - 7);\n    ctx.fillStyle = s.color; ctx.font = 'bold 8px monospace';\n    s.text.split(' ').slice(0,3).forEach((w, wi) => ctx.fillText(s.text, sx, sy + 10));\n    if (i === 0) ctx.fillText('200+ quốc gia', sx, sy + 9);\n    else if (i === 1) ctx.fillText('Bắt buộc từ Apple', sx, sy + 9);\n    else ctx.fillText('9 chữ số', sx, sy + 9);\n  });\n}\n\nctx.restore();\nreturn 290;"},
    {"name": "bk_diem_hay_openclaw", "when": "Một điểm hay của OpenClaw trong Track C là nó tự quản lý trạng thái kế", "code": "ctx.save();\nctx.beginPath(); ctx.rect(0, cursorY, W, 450); ctx.clip();\nconst cx = W / 2;\nconst cy = cursorY + 225;\nconst r = 52;\n\nctx.strokeStyle = 'rgba(16, 185, 129, 0.08)';\nctx.lineWidth = 1;\nctx.beginPath();\nctx.arc(cx, cy, r + 40, 0, Math.PI * 2);\nctx.stroke();\n\nconst waveCount = 3;\nfor (let i = 0; i < waveCount; i++) {\n  const waveProg = ((time * 0.12 + i / waveCount) % 1.0);\n  const waveR = r + waveProg * 90;\n  ctx.strokeStyle = `rgba(16, 185, 129, ${0.28 * (1 - waveProg)})`;\n  ctx.lineWidth = 2;\n  ctx.beginPath();\n  ctx.arc(cx, cy, waveR, 0, Math.PI * 2);\n  ctx.stroke();\n}\n\nconst channels = [\n  { name: \"Telegram Bot\", icon: \"✈️\", a: -Math.PI / 2, color: \"cyan\" },\n  { name: \"Zalo API\", icon: \"💬\", a: Math.PI / 6, color: \"highlight\" },\n  { name: \"Discord API\", icon: \"👾\", a: (5 * Math.PI) / 6, color: \"orange\" }\n];\n\nchannels.forEach((ch, idx) => {\n  const targetX = cx + Math.cos(ch.a) * 110;\n  const targetY = cy + Math.sin(ch.a) * 110;\n\n  ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';\n  ctx.lineWidth = 2.5;\n  ctx.setLineDash([4, 4]);\n  ctx.beginPath();\n  ctx.moveTo(cx, cy);\n  ctx.lineTo(targetX, targetY);\n  ctx.stroke();\n  ctx.setLineDash([]);\n\n  const pProg = (time * 0.22 + idx * 0.3) % 1.0;\n  const px = cx + (targetX - cx) * pProg;\n  const py = cy + (targetY - cy) * pProg;\n  ctx.fillStyle = rc(ch.color);\n  ctx.shadowColor = rc(ch.color);\n  ctx.shadowBlur = 10;\n  ctx.beginPath();\n  ctx.arc(px, py, 4.5, 0, Math.PI * 2);\n  ctx.fill();\n  ctx.shadowBlur = 0;\n\n  ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';\n  ctx.strokeStyle = rc(ch.color);\n  ctx.lineWidth = 1.5;\n  ctx.beginPath();\n  ctx.roundRect(targetX - 25, targetY - 25, 50, 50, 12);\n  ctx.fill();\n  ctx.stroke();\n\n  ctx.font = '24px ' + T.font;\n  ctx.fillStyle = rc(ch.color);\n  ctx.textAlign = 'center';\n  ctx.textBaseline = 'middle';\n  ctx.fillText(ch.icon, targetX, targetY - 2);\n\n  ctx.fillStyle = '#22d3ee';\n  ctx.font = 'bold 11px monospace';\n  ctx.fillText(ch.name, targetX, targetY + 38);\n});\n\nctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\nctx.strokeStyle = '#10b981';\nctx.lineWidth = 3;\nctx.shadowColor = '#10b981';\nctx.shadowBlur = 15;\nctx.beginPath();\nctx.roundRect(cx - 32, cy - 32, 64, 64, 16);\nctx.fill();\nctx.stroke();\nctx.shadowBlur = 0;\n\nconst pulse = 1 + 0.07 * Math.sin(time * 2.2);\nctx.font = `${Math.round(32 * pulse)}px ${T.font}`;\nctx.fillStyle = '#10b981';\nctx.textAlign = 'center';\nctx.textBaseline = 'middle';\ndrawEmoji(ctx, \"🧠\", cx, cy - 2, Math.round(32 * pulse));\n\nctx.restore();"},
    {"name": "bk_tuy_nhien_neu", "when": "Tuy nhiên, nếu không có các kênh giao tiếp, bạn sẽ phải luôn ngồi trướ", "code": "ctx.save();\nctx.beginPath(); ctx.rect(0, cursorY, W, 450); ctx.clip();\nconst cx = W / 2;\nconst cy = cursorY + 225;\n\nconst phoneX = cx - 180;\nconst phoneY = cy;\nctx.fillStyle = 'rgba(15, 23, 42, 0.9)';\nctx.strokeStyle = '#22d3ee';\nctx.lineWidth = 2.5;\nctx.beginPath();\nctx.roundRect(phoneX - 45, phoneY - 80, 90, 160, 16);\nctx.fill();\nctx.stroke();\n\nctx.fillStyle = 'rgba(34, 211, 238, 0.05)';\nctx.beginPath();\nctx.roundRect(phoneX - 38, phoneY - 70, 76, 140, 10);\nctx.fill();\n\nctx.font = '32px ' + T.font;\nctx.fillStyle = '#22d3ee';\nctx.textAlign = 'center';\nctx.textBaseline = 'middle';\ndrawEmoji(ctx, '📱', phoneX, phoneY - 10, 32);\n\nctx.font = 'bold 11px monospace';\nctx.fillStyle = '#22d3ee';\nctx.fillText('CHAT APP', phoneX, phoneY + 35);\n\nconst hubX = cx + 180;\nconst hubY = cy;\nctx.fillStyle = 'rgba(15, 23, 42, 0.9)';\nctx.strokeStyle = '#10b981';\nctx.lineWidth = 2.5;\nctx.beginPath();\nctx.roundRect(hubX - 55, hubY - 65, 110, 130, 18);\nctx.fill();\nctx.stroke();\n\nconst brainPulse = 1 + 0.06 * Math.sin(time * 2.5);\nctx.font = `${Math.round(40 * brainPulse)}px ${T.font}`;\nctx.fillStyle = '#10b981';\ndrawEmoji(ctx, '🧠', hubX, hubY - 15, Math.round(40 * brainPulse));\n\nctx.font = 'bold 12px monospace';\nctx.fillStyle = '#10b981';\nctx.fillText('AI HUB', hubX, hubY + 30);\n\nctx.strokeStyle = 'rgba(255, 255, 255, 0.08)';\nctx.lineWidth = 4;\nctx.beginPath();\nctx.moveTo(phoneX + 45, cy);\nctx.lineTo(hubX - 55, cy);\nctx.stroke();\n\nconst packetCount = 2;\nfor (let i = 0; i < packetCount; i++) {\n  const pProg = (time * 0.28 + i / packetCount) % 1.0;\n  const px = (phoneX + 45) + (hubX - 55 - (phoneX + 45)) * pProg;\n  ctx.fillStyle = '#22d3ee';\n  ctx.shadowColor = '#22d3ee';\n  ctx.shadowBlur = 8;\n  ctx.beginPath();\n  ctx.arc(px, cy, 5, 0, Math.PI * 2);\n  ctx.fill();\n  ctx.shadowBlur = 0;\n}\n\nconst apps = [\n  { icon: '💬', a: time * 0.35 },\n  { icon: '✈️', a: time * 0.35 + Math.PI / 2 },\n  { icon: '📞', a: time * 0.35 + Math.PI },\n  { icon: '👾', a: time * 0.35 + (3 * Math.PI) / 2 }\n];\napps.forEach(app => {\n  const ax = phoneX + Math.cos(app.a) * 75;\n  const ay = phoneY + Math.sin(app.a) * 75;\n  \n  ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n  ctx.strokeStyle = '#22d3ee';\n  ctx.lineWidth = 1.5;\n  ctx.beginPath();\n  ctx.roundRect(ax - 18, ay - 18, 36, 36, 8);\n  ctx.fill();\n  ctx.stroke();\n  \n  ctx.font = '18px ' + T.font;\n  ctx.fillStyle = '#22d3ee';\n  ctx.fillText(app.icon, ax, ay - 2);\n});\n\nctx.restore();"},
    {"name": "bk_inbound_route_duong", "when": "Inbound Route là đường vào: khi bạn nhắn tin cho Bot trên điện thoại, ", "code": "ctx.save();\nctx.beginPath(); ctx.rect(0, cursorY, W, 450); ctx.clip();\nconst cx = W / 2;\nconst cy = cursorY + 225;\n\nconst phoneX = cx - 200;\nconst gateX = cx;\nconst brainX = cx + 200;\n\nconst blockW = 100;\nconst blockH = 110;\n\nctx.fillStyle = 'rgba(15, 23, 42, 0.9)';\nctx.strokeStyle = '#22d3ee';\nctx.lineWidth = 2;\nctx.beginPath();\nctx.roundRect(phoneX - blockW/2, cy - blockH/2, blockW, blockH, 16);\nctx.fill();\nctx.stroke();\n\nctx.font = '36px ' + T.font;\nctx.fillStyle = '#22d3ee';\nctx.textAlign = 'center';\nctx.textBaseline = 'middle';\ndrawEmoji(ctx, '📱', phoneX, cy - 14, 36);\nctx.font = 'bold 12px monospace';\nctx.fillStyle = '#22d3ee';\nctx.fillText('PHONE', phoneX, cy + 28);\n\nctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\nctx.strokeStyle = '#22d3ee';\nctx.lineWidth = 2.5;\nctx.beginPath();\nctx.roundRect(gateX - blockW/2, cy - blockH/2, blockW, blockH, 16);\nctx.fill();\nctx.stroke();\n\nctx.font = '36px ' + T.font;\nctx.fillStyle = '#22d3ee';\ndrawEmoji(ctx, '📡', gateX, cy - 14, 36);\nctx.font = 'bold 12px monospace';\nctx.fillStyle = '#22d3ee';\nctx.fillText('GATEWAY', gateX, cy + 28);\n\nctx.fillStyle = 'rgba(15, 23, 42, 0.9)';\nctx.strokeStyle = '#10b981';\nctx.lineWidth = 2;\nctx.beginPath();\nctx.roundRect(brainX - blockW/2, cy - blockH/2, blockW, blockH, 16);\nctx.fill();\nctx.stroke();\n\nctx.font = '36px ' + T.font;\nctx.fillStyle = '#10b981';\ndrawEmoji(ctx, '🧠', brainX, cy - 14, 36);\nctx.font = 'bold 12px monospace';\nctx.fillStyle = '#22d3ee';\nctx.fillText('AI BRAIN', brainX, cy + 28);\n\nctx.strokeStyle = 'rgba(255, 255, 255, 0.08)';\nctx.lineWidth = 3.5;\nctx.beginPath();\nctx.moveTo(phoneX + blockW/2, cy);\nctx.lineTo(gateX - blockW/2, cy);\nctx.moveTo(gateX + blockW/2, cy);\nctx.lineTo(brainX - blockW/2, cy);\nctx.stroke();\n\nconst inProg = (time * 0.35) % 1.0;\nif (inProg < 0.5) {\n  const p1x = (phoneX + blockW/2) + (gateX - blockW/2 - (phoneX + blockW/2)) * (inProg / 0.5);\n  ctx.fillStyle = '#22d3ee';\n  ctx.shadowColor = '#22d3ee';\n  ctx.shadowBlur = 6;\n  ctx.beginPath(); ctx.arc(p1x, cy - 8, 4.5, 0, Math.PI * 2); ctx.fill();\n} else {\n  const p2x = (gateX + blockW/2) + (brainX - blockW/2 - (gateX + blockW/2)) * ((inProg - 0.5) / 0.5);\n  ctx.fillStyle = '#22d3ee';\n  ctx.shadowColor = '#22d3ee';\n  ctx.shadowBlur = 6;\n  ctx.beginPath(); ctx.arc(p2x, cy - 8, 4.5, 0, Math.PI * 2); ctx.fill();\n}\nctx.shadowBlur = 0;\n\nconst outProg = (time * 0.35 + 0.5) % 1.0;\nif (outProg < 0.5) {\n  const p1x = (brainX - blockW/2) - (brainX - blockW/2 - (gateX + blockW/2)) * (outProg / 0.5);\n  ctx.fillStyle = '#10b981';\n  ctx.shadowColor = '#10b981';\n  ctx.shadowBlur = 6;\n  ctx.beginPath(); ctx.arc(p1x, cy + 8, 4.5, 0, Math.PI * 2); ctx.fill();\n} else {\n  const p2x = (gateX - blockW/2) - (gateX - blockW/2 - (phoneX + blockW/2)) * ((outProg - 0.5) / 0.5);\n  ctx.fillStyle = '#10b981';\n  ctx.shadowColor = '#10b981';\n  ctx.shadowBlur = 6;\n  ctx.beginPath(); ctx.arc(p2x, cy + 8, 4.5, 0, Math.PI * 2); ctx.fill();\n}\nctx.shadowBlur = 0;\n\nctx.restore();"},
    {"name": "bk_agent_noi_chua", "when": "Agent là nơi chứa logic xử lý thông minh của hệ thống. Thành phần này ", "code": "ctx.save();\nctx.beginPath();ctx.rect(0,cursorY,W,650);ctx.clip();\nconst cx=W/2,cy=cursorY+325;\n\n// Glowing gear background rotating\nctx.save();\nctx.translate(cx, cy - 30);\nctx.rotate(time * 0.35);\nctx.strokeStyle = 'rgba(244,63,94,0.06)';ctx.lineWidth = 8;\nctx.beginPath();ctx.arc(0,0,130,0,Math.PI*2);ctx.stroke();\nfor(let i=0; i<12; i++) {\n  const a = i * Math.PI / 6;\n  ctx.beginPath();ctx.moveTo(Math.cos(a)*120, Math.sin(a)*120);\n  ctx.lineTo(Math.cos(a)*145, Math.sin(a)*145);ctx.stroke();\n}\nctx.restore();\n\n// Core processor box representing Agent Logic\nctx.fillStyle = 'rgba(15, 23, 42, 0.95)';ctx.strokeStyle = '#f43f5e';ctx.lineWidth = 3;\nctx.shadowColor = '#f43f5e';ctx.shadowBlur = 18;\nctx.beginPath();ctx.roundRect(cx - 95, cy - 125, 190, 190, 18);\nctx.fill();ctx.stroke();ctx.shadowBlur=0;\n\n// Rotating micro gears inside chip console\nctx.font = '54px sans-serif';ctx.textAlign = 'center';ctx.textBaseline = 'middle';\nctx.fillText('⚙️', cx - 35, cy - 30);\nctx.save();\nctx.translate(cx + 30, cy - 25);\nctx.rotate(-time * 1.5);\nctx.font = '36px sans-serif';\nctx.fillText('⚙️', 0, 0);\nctx.restore();\n\nctx.font = 'bold 15px monospace';ctx.fillStyle = '#f43f5e';\nctx.fillText('AGENT CORE', cx, cy + 35);\n\n// Dynamic floating logic tree signals\nconst branches = [\n  { label: '1. NHẬN NGỮ CẢNH', col: '#38bdf8', yOff: -110 },\n  { label: '2. LLM SUY NGHĨ', col: '#f59e0b', yOff: -50 },\n  { label: '3. GỌI CÔNG CỤ', col: '#a78bfa', yOff: 10 },\n  { label: '4. TRẢ LỜI', col: '#34d399', yOff: 70 }\n];\n\nbranches.forEach((b, idx) => {\n  const actIdx = Math.floor(time * 0.95) % 4;\n  const isAct = idx === actIdx;\n  const lx = cx - 290, rx = cx + 290;\n  const sideX = idx % 2 === 0 ? lx : rx;\n\n  ctx.strokeStyle = isAct ? b.col : 'rgba(255,255,255,0.06)';ctx.lineWidth = 2;\n  ctx.beginPath();ctx.moveTo(cx, cy - 30);\n  ctx.lineTo(sideX, cy - 30 + b.yOff);ctx.stroke();\n\n  ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';ctx.strokeStyle = isAct ? b.col : '#475569';ctx.lineWidth = isAct ? 2.5 : 1;\n  if (isAct) { ctx.shadowColor = b.col; ctx.shadowBlur = 12; }\n  ctx.beginPath();ctx.roundRect(sideX - 75, cy - 30 + b.yOff - 20, 150, 40, 8);\n  ctx.fill();ctx.stroke();ctx.shadowBlur=0;\n\n  ctx.font = 'bold 11px monospace';ctx.fillStyle = isAct ? '#fff' : '#64748b';\n  ctx.fillText(b.label, sideX, cy - 30 + b.yOff + 5);\n});\n\nctx.font = 'bold 18px monospace';ctx.fillStyle = '#f43f5e';\nctx.fillText('🧠 BỘ NÃO ĐIỀU PHỐI LOGIC THÔNG MINH', cx, cy + 185);\nctx.restore();"},
    {"name": "bk_cot_moc_thu", "when": "Cột mốc thứ tư là triển khai ứng dụng lên mạng internet thông qua Zeab", "code": "ctx.save();\nconst cx = W / 2;\nconst isPortrait = H > W;\nconst w = Math.min(W - MX * 2, isPortrait ? 600 : 780);\nconst x = cx - w / 2;\nconst y = cursorY + 10;\nconst frameH = isPortrait ? 400 : 260;\n\n// Solid dark card background\nctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\nctx.strokeStyle = '#22d3ee';\nctx.lineWidth = 2.5;\nctx.beginPath(); ctx.roundRect(x, y, w, frameH, 16); ctx.fill(); ctx.stroke();\n\n// Drawing scanning line going up/down\nconst scanY = y + 30 + (frameH - 60) * (0.5 + 0.5 * Math.sin(time * 2));\nctx.strokeStyle = 'rgba(34, 211, 238, ' + (0.4 + 0.2 * Math.sin(time * 6)) + ')';\nctx.lineWidth = 3;\nctx.shadowColor = '#22d3ee';\nctx.shadowBlur = 10;\nctx.beginPath(); ctx.moveTo(x + 15, scanY); ctx.lineTo(x + w - 15, scanY); ctx.stroke();\nctx.shadowBlur = 0;\n\n// Framework badges\nconst frameworks = [\n  { name: 'Next.js', emoji: '⚛️', color: 'cyan', rx: cx - (isPortrait ? 130 : 180), ry: y + (isPortrait ? 85 : 75) },\n  { name: 'Vue.js', emoji: '💚', color: 'green', rx: cx, ry: y + (isPortrait ? 85 : 75) },\n  { name: 'PHP App', emoji: '🐘', color: 'blue', rx: cx + (isPortrait ? 130 : 180), ry: y + (isPortrait ? 85 : 75) }\n];\n\nconst activeIdx = Math.floor(time * 0.8) % 3;\n\nfor (let i = 0; i < frameworks.length; i++) {\n  const fw = frameworks[i];\n  const isScanned = Math.abs(scanY - fw.ry) < 40;\n  const isCurrentActive = i === activeIdx;\n  \n  ctx.save();\n  ctx.translate(fw.rx, fw.ry);\n  \n  // Badge box\n  ctx.fillStyle = isCurrentActive ? 'rgba(255,255,255,0.06)' : 'rgba(255,255,255,0.02)';\n  ctx.strokeStyle = isCurrentActive ? rc(fw.color) : 'rgba(255,255,255,0.08)';\n  ctx.lineWidth = isCurrentActive ? 2.5 : 1.5;\n  if (isCurrentActive) {\n    ctx.shadowColor = rc(fw.color);\n    ctx.shadowBlur = 8;\n  }\n  ctx.beginPath(); ctx.roundRect(-55, -45, 110, 90, 12); ctx.fill(); ctx.stroke();\n  ctx.shadowBlur = 0;\n  \n  // Icon / Emoji\n  ctx.font = '38px sans-serif';\n  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText(fw.emoji, 0, -12);\n  \n  // Label text\n  ctx.font = 'bold 14px sans-serif';\n  ctx.fillStyle = isCurrentActive ? '#ffffff' : '#22d3ee';\n  ctx.fillText(fw.name, 0, 24);\n  \n  ctx.restore();\n}\n\n// Build Status console at the bottom\nconst consoleY = y + (isPortrait ? 180 : 155);\nconst consoleH = isPortrait ? 190 : 85;\nctx.fillStyle = 'rgba(0,0,0,0.2)';\nctx.beginPath(); ctx.roundRect(x + 20, consoleY, w - 40, consoleH, 8); ctx.fill();\n\nctx.font = isPortrait ? '16px monospace' : '12px monospace';\nctx.fillStyle = '#10b981';\nctx.textAlign = 'left';\n\nconst stepText = [\n  '👉 [Zeabur] Scanning project root directory...',\n  '💡 [Zeabur] Detected framework: ' + frameworks[activeIdx].name,\n  '📦 [Zeabur] Installing required dependencies... SUCCESS!',\n  '⚡ [Zeabur] Project build completed in 2.45s! Status: LIVE'\n];\n\nconst textShowCount = Math.min(4, Math.floor(time * 0.8) % 6 + 1);\nfor (let j = 0; j < textShowCount; j++) {\n  const lineY = consoleY + 22 + j * (isPortrait ? 38 : 17);\n  if (j === 3) {\n    ctx.fillStyle = '#22d3ee';\n  } else if (j === 2) {\n    ctx.fillStyle = '#ffffff';\n  } else {\n    ctx.fillStyle = '#10b981';\n  }\n  ctx.fillText(stepText[j], x + 35, lineY);\n}\n\nctx.restore();\nreturn frameH + 20;"},
    {"name": "bk_tuy_nhien_dieu", "when": "Tuy nhiên, một điều đáng ngạc nhiên: con lắc kép bảo toàn năng lượng. ", "code": "ctx.save();\nconst cx=W/2,cy=cursorY+150;\nconst timeArr=[];\nconst ke1=[],ke2=[],pe1=[],pe2=[],total=[];\nconst L1=0.85,L2=0.75,g=9.8,m1=1,m2=1,dt=0.02;\nlet th1=1.3,th2=2.0,w1=0.2,w2=-0.3;\nfor(let i=0;i<150;i++){const d=2*m1+m2-m2*Math.cos(2*th1-2*th2);\nconst a1=(-g*(2*m1+m2)*Math.sin(th1)-m2*g*Math.sin(th1-2*th2)-2*Math.sin(th1-th2)*m2*(w2*w2*L2+w1*w1*L1*Math.cos(th1-th2)))/(L1*d);\nconst a2=(2*Math.sin(th1-th2)*(w1*w1*L1*(m1+m2)+g*(m1+m2)*Math.cos(th1)+w2*w2*L2*m2*Math.cos(th1-th2)))/(L2*d);\nw1+=a1*dt;w2+=a2*dt;th1+=w1*dt;th2+=w2*dt;\nconst x1=L1*Math.sin(th1),y1=-L1*Math.cos(th1);\nconst kk1=0.5*m1*(w1*w1*L1*L1);const kk2=0.5*m2*((w1*L1*Math.cos(th1)+w2*L2*Math.cos(th2))*(w1*L1*Math.cos(th1)+w2*L2*Math.cos(th2))+(w1*L1*Math.sin(th1)+w2*L2*Math.sin(th2))*(w1*L1*Math.sin(th1)+w2*L2*Math.sin(th2)));\nconst pp=-(m1+m2)*g*L1*Math.cos(th1)-m2*g*L2*Math.cos(th2);\ntimeArr.push(i);ke1.push(kk1);ke2.push(kk2);pe1.push(pp);total.push(kk1+kk2+pp);}\nconst minE=Math.min(...total),maxE=Math.max(...total);const rangeE=maxE-minE||1;\nconst minKE=0,maxKE=Math.max(...ke1.map((k,i)=>k+ke2[i]));\nfunction plotLine(arr,col,bx,bw,bh,by,minV,maxV){ctx.strokeStyle=col;ctx.lineWidth=2;ctx.save();ctx.shadowColor=col;ctx.shadowBlur=8;\nctx.beginPath();for(let i=0;i<arr.length;i++){const px=bx+i/arr.length*bw;const py=by+bh-(arr[i]-minV)/(maxV-minV||1)*bh;if(i===0)ctx.moveTo(px,py);else ctx.lineTo(px,py);}ctx.stroke();ctx.restore();}\nconst bx=cx-210,bw=420,bh=100,by=cy-110;\nplotLine(ke1.map((k,i)=>k+ke2[i]),rc('yellow'),bx,bw,bh,by,0,maxKE+5);\nplotLine(total,rc('green'),bx,bw,bh,by,minE-2,maxE+2);\nctx.strokeStyle='rgba(148,163,184,0.3)';ctx.lineWidth=1;ctx.beginPath();ctx.roundRect(bx,by,bw,bh,4);ctx.stroke();\nctx.fillStyle=rc('yellow');ctx.font='bold 10px monospace';ctx.textAlign='left';ctx.fillText('KE (vàng)',bx+5,by+15);\nctx.fillStyle=rc('green');ctx.fillText('Tổng E (xanh, hằng số)',bx+5,by+30);\nctx.fillStyle=rc('cyan');ctx.font='italic bold 12px serif';ctx.textAlign='center';\nctx.fillText('Tổng năng lượng bảo toàn — dù hỗn loạn hoàn toàn',cx,cy+140);\nctx.restore();return 380;"},
    {"name": "bk_nam_thiet_giao", "when": "Chào mừng bạn đến với Bài năm: Thiết kế giao diện hiện đại. Trong bài ", "code": "ctx.save();\nconst isPortrait = H > W;\nconst scaleF = isPortrait ? 1.6 : 1.0;\nconst cx = W / 2;\nconst cy = cursorY + 140 * scaleF;\nconst pulse = 1 + 0.05 * Math.sin(time * 2.5);\n\n// Drawing solid background card first to block shadow glare bleed\nctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\nctx.beginPath();\nctx.roundRect(cx - 150 * scaleF, cy - 100 * scaleF, 300 * scaleF, 200 * scaleF, 16);\nctx.fill();\n\n// Glow border outline\nctx.strokeStyle = '#22d3ee';\nctx.lineWidth = 2 * scaleF;\nctx.shadowColor = '#22d3ee';\nctx.shadowBlur = 15 * pulse * scaleF;\nctx.beginPath();\nctx.roundRect(cx - 150 * scaleF, cy - 100 * scaleF, 300 * scaleF, 200 * scaleF, 16);\nctx.stroke();\nctx.shadowBlur = 0;\n\n// Rotating 3D glowing wireframe mesh\nctx.strokeStyle = 'rgba(34, 211, 238, 0.35)';\nctx.lineWidth = 1.2 * scaleF;\nconst pts = [\n  {x: -60, y: -45}, {x: 60, y: -45},\n  {x: 80, y: 35}, {x: -80, y: 35},\n  {x: 0, y: -75}, {x: 0, y: 65}\n];\n\nconst rotTime = time * 0.5;\nfor (let i = 0; i < pts.length; i++) {\n  for (let j = i + 1; j < pts.length; j++) {\n    const dist = Math.hypot(pts[i].x - pts[j].x, pts[i].y - pts[j].y);\n    if (dist < 130) {\n      const rx1 = pts[i].x * scaleF * Math.cos(rotTime) - pts[i].y * scaleF * Math.sin(rotTime) * 0.35;\n      const ry1 = pts[i].x * scaleF * Math.sin(rotTime) * 0.35 + pts[i].y * scaleF * Math.cos(rotTime);\n      const rx2 = pts[j].x * scaleF * Math.cos(rotTime) - pts[j].y * scaleF * Math.sin(rotTime) * 0.35;\n      const ry2 = pts[j].x * scaleF * Math.sin(rotTime) * 0.35 + pts[j].y * scaleF * Math.cos(rotTime);\n      ctx.beginPath();\n      ctx.moveTo(cx + rx1, cy + ry1);\n      ctx.lineTo(cx + rx2, cy + ry2);\n      ctx.stroke();\n    }\n  }\n}\n\n// Center emoji\nctx.font = isPortrait ? '96px sans-serif' : '64px sans-serif';\nctx.textAlign = 'center';\nctx.textBaseline = 'middle';\nctx.fillText('🎨', cx, cy - 10 + 5 * Math.sin(time * 2));\n\n// Sparks orbiting\nfor (let i = 0; i < 8; i++) {\n  const a = (i * Math.PI * 2) / 8 + time * 0.4;\n  const r = (100 + 15 * Math.cos(time * 3 + i)) * scaleF;\n  ctx.fillStyle = '#22d3ee';\n  ctx.beginPath();\n  ctx.arc(cx + Math.cos(a) * r, cy + Math.sin(a) * r, 3 * scaleF, 0, Math.PI * 2);\n  ctx.fill();\n}\nctx.restore();\nreturn isPortrait ? 420 : 280;"},
    {"name": "bk_xay_niem_tin", "when": "Khi bạn đã xây đủ niềm tin với cộng đồng — việc giới thiệu một sản phẩ", "code": "ctx.save();\nconst isPortrait = H > W;\nconst cx = W / 2;\nconst cy = cursorY + (isPortrait ? 200 : 150);\nconst r = 95;\n\nif (isPortrait) {\n  const ty = cy - 110;\n  const by = cy + 110;\n  \n  ctx.strokeStyle = 'rgba(255, 255, 255, 0.08)'; ctx.lineWidth = 6;\n  ctx.beginPath(); ctx.moveTo(cx, ty); ctx.lineTo(cx, by); ctx.stroke();\n  \n  ctx.fillStyle = rc('cyan'); ctx.save(); ctx.shadowColor = rc('cyan'); ctx.shadowBlur = 18;\n  ctx.beginPath(); ctx.arc(cx, ty, r, 0, Math.PI*2); ctx.fill(); ctx.restore();\n  ctx.fillStyle = '#fff'; ctx.font = '72px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('🎬', cx, ty - 4);\n  \n  ctx.fillStyle = rc('highlight'); ctx.save(); ctx.shadowColor = rc('highlight'); ctx.shadowBlur = 18;\n  ctx.beginPath(); ctx.arc(cx, by, r, 0, Math.PI*2); ctx.fill(); ctx.restore();\n  ctx.fillStyle = '#fff'; ctx.font = '72px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('👥', cx, by - 4);\n  \n  const trustActive = stepProgress > 0.45;\n  if (trustActive) {\n    const scale = Math.min(1.0, (stepProgress - 0.45) * 2);\n    const heartPulse = 1 + 0.12 * Math.sin(time * 4.5);\n    ctx.save(); ctx.translate(cx, cy); ctx.scale(scale * heartPulse, scale * heartPulse);\n    ctx.fillStyle = rc('red'); ctx.shadowColor = rc('red'); ctx.shadowBlur = 35;\n    ctx.font = '120px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText('❤️', 0, 0);\n    ctx.restore();\n    \n    const waveR = 70 + (time * 120) % 200;\n    const waveAlpha = Math.max(0, 1 - (waveR - 70) / 200);\n    ctx.strokeStyle = `rgba(239, 68, 68, ${waveAlpha * 0.45})`; ctx.lineWidth = 5;\n    ctx.beginPath(); ctx.arc(cx, cy, waveR, 0, Math.PI*2); ctx.stroke();\n  }\n} else {\n  const lx = cx - 250;\n  const rx = cx + 250;\n  \n  ctx.strokeStyle = 'rgba(255, 255, 255, 0.08)'; ctx.lineWidth = 6;\n  ctx.beginPath(); ctx.moveTo(lx, cy); ctx.lineTo(rx, cy); ctx.stroke();\n  \n  ctx.fillStyle = rc('cyan'); ctx.save(); ctx.shadowColor = rc('cyan'); ctx.shadowBlur = 18;\n  ctx.beginPath(); ctx.arc(lx, cy, r, 0, Math.PI*2); ctx.fill(); ctx.restore();\n  ctx.fillStyle = '#fff'; ctx.font = '64px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('🎬', lx, cy - 4);\n  \n  ctx.fillStyle = rc('highlight'); ctx.save(); ctx.shadowColor = rc('highlight'); ctx.shadowBlur = 18;\n  ctx.beginPath(); ctx.arc(rx, cy, r, 0, Math.PI*2); ctx.fill(); ctx.restore();\n  ctx.fillStyle = '#fff'; ctx.font = '64px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('👥', rx, cy - 4);\n  \n  const trustActive = stepProgress > 0.45;\n  if (trustActive) {\n    const scale = Math.min(1.0, (stepProgress - 0.45) * 2);\n    const heartPulse = 1 + 0.12 * Math.sin(time * 4.5);\n    ctx.save(); ctx.translate(cx, cy); ctx.scale(scale * heartPulse, scale * heartPulse);\n    ctx.fillStyle = rc('red'); ctx.shadowColor = rc('red'); ctx.shadowBlur = 35;\n    ctx.font = '96px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText('❤️', 0, 0);\n    ctx.restore();\n    \n    const waveR = 60 + (time * 95) % 150;\n    const waveAlpha = Math.max(0, 1 - (waveR - 60) / 150); \n    ctx.strokeStyle = `rgba(239, 68, 68, ${waveAlpha * 0.45})`; ctx.lineWidth = 4;\n    ctx.beginPath(); ctx.arc(cx, cy, waveR, 0, Math.PI*2); ctx.stroke();\n  }\n}\nctx.restore();\nreturn isPortrait ? 400 : 300;"},
    {"name": "bk_dong_hoa_khong", "when": "Tự động hóa không có nghĩa là biến mất hoàn toàn. Nó cho phép bạn rũ b", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 135;\n\n// Central brain with neural network\nconst brainRadius = 55;\nconst pulse = 1 + 0.1 * Math.sin(time * 2.5);\n\n// Neural connections radiating outward\nfor (let i = 0; i < 12; i++) {\n    const angle = (i / 12) * Math.PI * 2 + time * 0.5;\n    const dist = 80 + 20 * Math.sin(time * 2 + i);\n    const ex = cx + Math.cos(angle) * dist;\n    const ey = cy - 20 + Math.sin(angle) * dist;\n    \n    // Connection line with pulse\n    const lineAlpha = 0.3 + 0.2 * Math.sin(time * 3 + i * 0.5);\n    ctx.strokeStyle = rc('cyan');\n    ctx.save();\n    ctx.globalAlpha = lineAlpha;\n    ctx.lineWidth = 2;\n    ctx.beginPath();\n    ctx.moveTo(cx, cy - 20);\n    ctx.lineTo(ex, ey);\n    ctx.stroke();\n    ctx.restore();\n    \n    // End nodes\n    ctx.fillStyle = rc('yellow');\n    ctx.save();\n    ctx.shadowColor = rc('yellow');\n    ctx.shadowBlur = 10;\n    ctx.beginPath();\n    ctx.arc(ex, ey, 4, 0, Math.PI * 2);\n    ctx.fill();\n    ctx.restore();\n}\n\n// Main brain circle with layers\nfor (let i = 2; i >= 0; i--) {\n    const layerScale = pulse * (1 + i * 0.1);\n    const layerAlpha = 0.3 - i * 0.1;\n    \n    ctx.fillStyle = i === 0 ? 'rgba(15,23,42,0.95)' : rc('yellow');\n    ctx.strokeStyle = rc('yellow');\n    ctx.lineWidth = 5 - i;\n    ctx.save();\n    ctx.globalAlpha = i === 0 ? 1.0 : layerAlpha;\n    ctx.shadowColor = rc('yellow');\n    ctx.shadowBlur = 25 + i * 10;\n    ctx.beginPath();\n    ctx.arc(cx, cy - 20, brainRadius * layerScale, 0, Math.PI * 2);\n    if (i === 0) ctx.fill();\n    ctx.stroke();\n    ctx.restore();\n}\n\n// Brain emoji\nctx.fillStyle = '#fff';\nctx.font = '48px sans-serif';\nctx.textAlign = 'center';\nctx.fillText('🧠', cx, cy - 5);\n\n// Idea particles floating up\nfor (let i = 0; i < 5; i++) {\n    const t = (time * 0.6 + i * 0.2) % 1.0;\n    const px = cx + (Math.random() * 60 - 30);\n    const py = cy + 40 - t * 120;\n    const size = 8 * (1 - t);\n    \n    if (t < 0.9) {\n        ctx.fillStyle = rc('cyan');\n        ctx.save();\n        ctx.globalAlpha = 1 - t;\n        ctx.shadowColor = rc('cyan');\n        ctx.shadowBlur = 15;\n        ctx.font = `${size * 3}px sans-serif`;\n        ctx.fillText('💡', px, py);\n        ctx.restore();\n    }\n}\n\n// Strategic thinking indicators\nconst indicators = ['📊', '🎯', '🚀', '💎'];\nfor (let i = 0; i < indicators.length; i++) {\n    const angle = (i / indicators.length) * Math.PI * 2 + time;\n    const radius = 120;\n    const ix = cx + Math.cos(angle) * radius;\n    const iy = cy - 20 + Math.sin(angle) * radius;\n    \n    ctx.font = '24px sans-serif';\n    ctx.textAlign = 'center';\n    ctx.fillText(indicators[i], ix, iy);\n}\n\n// Title text\nctx.fillStyle = rc('cyan');\nctx.font = 'bold 22px monospace';\nctx.textAlign = 'center';\nctx.save();\nctx.shadowColor = rc('cyan');\nctx.shadowBlur = 15;\nctx.fillText('🎯 TƯ DUY CHIẾN LƯỢC', cx, cy + 90);\nctx.restore();\n\nctx.fillStyle = rc('green');\nctx.font = 'bold 18px monospace';\nctx.fillText('SÁNG TẠO × TỐI ƯU × TĂNG TRƯỞNG', cx, cy + 115);\n\nctx.restore();\nreturn 380;"},
    {"name": "bk_diem_mau_chot", "when": "Điểm mấu chốt của Multi-vendor là khái niệm Store — gian hàng. Mỗi ngư", "code": "ctx.save();\nconst cx = W/2, cy = cursorY + 140;\n\n// Single vendor table (wrong)\nconst sX = cx - 170, sY = cy - 100;\nctx.fillStyle = '#1e293b'; ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;\nctx.beginPath(); ctx.roundRect(sX, sY, 140, 28, [6,6,0,0]); ctx.fill(); ctx.stroke();\nctx.fillStyle = '#fca5a5'; ctx.font = 'bold 10px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\nctx.fillText('❌ Single Vendor', sX + 70, sY + 14);\n\n[['id','name','price'], ['1','Code Addon','99k'], ['2','Font Pack','49k']].forEach((row, ri) => {\n  const ry = sY + 28 + ri * 28;\n  ctx.fillStyle = ri === 0 ? '#1e293b' : 'rgba(15,23,42,0.9)'; ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;\n  ctx.beginPath(); ctx.rect(sX, ry, 140, 28); ctx.fill(); ctx.stroke();\n  row.forEach((cell, ci) => {\n    ctx.fillStyle = ri === 0 ? '#94a3b8' : '#e2e8f0'; ctx.font = ri === 0 ? 'bold 9px monospace' : '9px monospace';\n    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText(cell, sX + 47*ci + 24, ry + 14);\n  });\n});\nctx.fillStyle = '#ef4444'; ctx.font = '10px monospace'; ctx.textAlign = 'center';\nctx.fillText('Không biết ai bán!', sX + 70, sY + 118);\n\n// Multi vendor table (right)\nconst mX = cx + 30, mY = cy - 100;\nctx.fillStyle = '#1e293b'; ctx.strokeStyle = '#10b981'; ctx.lineWidth = 2;\nctx.beginPath(); ctx.roundRect(mX, mY, 185, 28, [6,6,0,0]); ctx.fill(); ctx.stroke();\nctx.fillStyle = '#6ee7b7'; ctx.font = 'bold 10px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\nctx.fillText('✅ Multi-vendor', mX + 92, mY + 14);\n\nconst mCols = ['id','store_id','name','price'];\nconst mRows = [mCols, ['1','STR-A','Code Addon','99k'], ['2','STR-B','Font Pack','49k']];\nmRows.forEach((row, ri) => {\n  const ry = mY + 28 + ri * 28;\n  ctx.fillStyle = ri === 0 ? '#1e293b' : (ri === 1 ? 'rgba(99,102,241,0.15)' : 'rgba(16,185,129,0.15)');\n  ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;\n  ctx.beginPath(); ctx.rect(mX, ry, 185, 28); ctx.fill(); ctx.stroke();\n  row.forEach((cell, ci) => {\n    const isStoreId = ci === 1 && ri > 0;\n    ctx.fillStyle = isStoreId ? '#fbbf24' : (ri === 0 ? '#94a3b8' : '#e2e8f0');\n    ctx.font = (ri === 0 || isStoreId) ? 'bold 9px monospace' : '9px monospace';\n    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText(cell, mX + 46*ci + 23, ry + 14);\n  });\n});\nctx.fillStyle = '#10b981'; ctx.font = '10px monospace'; ctx.textAlign = 'center';\nctx.fillText('Mỗi sản phẩm → gian hàng riêng!', mX + 92, mY + 118);\n\nctx.restore();\nreturn 280;"},
    {"name": "bk_dau_tien_thong", "when": "Đầu tiên là hệ thống bộ nhớ. Đây là thành phần giúp AI vượt qua giới h", "code": "ctx.save();\nctx.beginPath();ctx.rect(0,cursorY,W,650);ctx.clip();\nconst cx=W/2,cy=cursorY+300;\n\n// Cyber background grid - Neon Green\nctx.strokeStyle='rgba(16,185,129,0.03)';ctx.lineWidth=1;\nfor(let x=0;x<W;x+=40){ctx.beginPath();ctx.moveTo(x,cursorY);ctx.lineTo(x,cursorY+650);ctx.stroke();}\nfor(let y=cursorY;y<cursorY+650;y+=40){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}\n\nconst drawClaude = (ctx, x, y, scale, color, glowColor, angle = 0, opts = {}) => {\n    ctx.save();\n    ctx.translate(x, y); ctx.rotate(angle);\n    if (opts.lookLeft) ctx.scale(-scale, scale); else ctx.scale(scale, scale);\n    ctx.translate(-12, -10);\n    ctx.beginPath();\n    ctx.moveTo(20.998, 10.949); ctx.lineTo(24, 10.949); ctx.lineTo(24, 14.051); ctx.lineTo(21, 14.051);\n    ctx.lineTo(21, 17.079); ctx.lineTo(19.513, 17.079); ctx.lineTo(19.513, 20); ctx.lineTo(18, 20);\n    ctx.lineTo(18, 17.079); ctx.lineTo(16.513, 17.079); ctx.lineTo(16.513, 20); ctx.lineTo(15, 20);\n    ctx.lineTo(15, 17.079); ctx.lineTo(9, 17.079); ctx.lineTo(9, 20); ctx.lineTo(7.488, 20);\n    ctx.lineTo(7.488, 17.079); ctx.lineTo(6, 17.079); ctx.lineTo(6, 20); ctx.lineTo(4.487, 20);\n    ctx.lineTo(4.487, 17.079); ctx.lineTo(3, 17.079); ctx.lineTo(3, 14.05); ctx.lineTo(0, 14.05);\n    ctx.lineTo(0, 10.95); ctx.lineTo(3, 10.95); ctx.lineTo(3, 5); ctx.lineTo(20.998, 5);\n    ctx.lineTo(20.998, 10.949); ctx.closePath();\n    ctx.fillStyle = color || '#D97757';\n    if (glowColor) { ctx.shadowColor = glowColor; ctx.shadowBlur = 18; }\n    ctx.fill(); ctx.shadowBlur = 0;\n    ctx.fillStyle = '#fff';\n    ctx.fillRect(6, 8.102, 1.488, 2.847); ctx.fillRect(16.51, 8.102, 1.49, 2.847);\n    ctx.restore();\n};\n\n// Renders the glowing memory filing cabinets (Purple-blue holographic frames)\nctx.fillStyle = 'rgba(30, 41, 59, 0.4)';ctx.strokeStyle = '#a78bfa';ctx.lineWidth = 3;\nctx.beginPath();ctx.rect(cx - 240, cy - 140, 480, 260);ctx.fill();ctx.stroke();\n\n// Scan sweeping horizontal lines (Emerald Green laser scanner)\nconst scanY = cy - 140 + ((time * 120) % 260);\nctx.strokeStyle = 'rgba(16, 185, 129, 0.6)';ctx.lineWidth = 4;\nctx.shadowColor = '#10b981';ctx.shadowBlur = 15;\nctx.beginPath();ctx.moveTo(cx - 240, scanY);ctx.lineTo(cx + 240, scanY);ctx.stroke();ctx.shadowBlur = 0;\n\n// Draw 6 locked/unlocked storage nodes inside cabinets\nfor (let r = 0; r < 2; r++) {\n    for (let c = 0; c < 3; c++) {\n        const nx = cx - 160 + c * 160;\n        const ny = cy - 70 + r * 120;\n        const isUnlocked = Math.sin(time*2 + c + r) > 0;\n        \n        ctx.fillStyle = isUnlocked ? 'rgba(16, 185, 129, 0.15)' : 'rgba(167, 139, 250, 0.05)';\n        ctx.strokeStyle = isUnlocked ? '#10b981' : '#a78bfa';ctx.lineWidth = 1.5;\n        ctx.beginPath();ctx.rect(nx - 60, ny - 40, 120, 80);ctx.fill();ctx.stroke();\n        \n        ctx.font = 'bold 11px monospace';ctx.fillStyle = isUnlocked ? '#10b981' : '#a78bfaa8';\n        ctx.fillText(isUnlocked ? '🔓 ACCESSED' : '🔒 ARCHIVED', nx, ny - 10);\n        ctx.font = '9px monospace';ctx.fillStyle = '#fff';\n        ctx.fillText(isUnlocked ? 'SECURE_MEM_0' + (c+r*3) : 'SYSTEM_RESERVED', nx, ny + 15);\n    }\n}\n\n// Investigator Claude floating at the side holding scanner\nconst cX = cx - 320, cY = cy;\ndrawClaude(ctx, cX, cY + Math.sin(time*3.5)*12, 2.5, '#D97757', '#10b981', Math.sin(time)*0.1);\n\nctx.font = 'bold 18px monospace';ctx.fillStyle = '#a78bfa';ctx.textAlign = 'center';\nctx.fillText('HỆ THỐNG TRUY XUẤT CƠ SỞ BỘ NHỚ KHÔNG GIỚI HẠN', cx, cy + 180);\nctx.restore();"},
    {"name": "bk_quy_trinh_thuc", "when": "Quy trình thực chiến của chúng ta gồm có năm bước cốt lõi. Đầu tiên, t", "code": "ctx.save();\nconst cx = W / 2;\nconst isPortrait = H > W;\nconst frameH = isPortrait ? 450 : 250;\n\nif (isPortrait) {\n  const w = Math.min(W - MX * 2, 480);\n  const x = cx - w / 2;\n  const y = cursorY + 10;\n  const cardH = 75;\n  const gap = 12;\n\n  const stages = [\n    { name: \"1. UI Design to Code\", icon: \"🎨\", desc: \"Figma ➔ React/Next.js UI\", color: \"cyan\" },\n    { name: \"2. Database Schema\", icon: \"🗄️\", desc: \"Supabase tables & SQL triggers\", color: \"highlight\" },\n    { name: \"3. API Routings\", icon: \"🤖\", desc: \"Next.js ➔ LLM Router API\", color: \"orange\" },\n    { name: \"4. Stripe Checkout\", icon: \"💳\", desc: \"Thanh toán & Stripe Webhook\", color: \"green\" },\n    { name: \"5. Production CI/CD\", icon: \"☁️\", desc: \"Zeabur deployment & Custom DNS\", color: \"blue\" }\n  ];\n\n  for (let i = 0; i < stages.length; i++) {\n    const s = stages[i];\n    const cy_box = y + i * (cardH + gap) + 15;\n    \n    ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n    ctx.beginPath(); ctx.roundRect(x, cy_box, w, cardH, 10); ctx.fill();\n\n    ctx.strokeStyle = rc(s.color);\n    ctx.lineWidth = 2.0;\n    ctx.shadowColor = rc(s.color);\n    ctx.shadowBlur = 6;\n    ctx.beginPath(); ctx.roundRect(x, cy_box, w, cardH, 10); ctx.stroke();\n    ctx.shadowBlur = 0;\n\n    ctx.font = '28px sans-serif';\n    ctx.textAlign = 'left'; ctx.textBaseline = 'middle';\n    ctx.fillText(s.icon, x + 20, cy_box + cardH/2);\n\n    ctx.fillStyle = '#ffffff';\n    ctx.font = 'bold 15px sans-serif';\n    ctx.fillText(s.name, x + 65, cy_box + 24);\n\n    ctx.fillStyle = '#22d3ee';\n    ctx.font = '12px sans-serif';\n    ctx.fillText(s.desc, x + 65, cy_box + 48);\n  }\n  ctx.restore();\n  return 480;\n} else {\n  const w = Math.min(W - MX * 2, 800);\n  const x = cx - w / 2;\n  const y = cursorY + 20;\n  const cardW = (w - 80) / 5;\n  const cardH = 180;\n\n  const stages = [\n    { name: \"UI Code\", icon: \"🎨\", desc: \"Figma ➔ React\", color: \"cyan\" },\n    { name: \"Supabase\", icon: \"🗄️\", desc: \"SQL Schema\", color: \"highlight\" },\n    { name: \"API Route\", icon: \"🤖\", desc: \"LLM calling\", color: \"orange\" },\n    { name: \"Stripe\", icon: \"💳\", desc: \"Subscriptions\", color: \"green\" },\n    { name: \"Zeabur\", icon: \"☁️\", desc: \"Live domain\", color: \"blue\" }\n  ];\n\n  for (let i = 0; i < stages.length; i++) {\n    const s = stages[i];\n    const cx_box = x + i * (cardW + 15);\n\n    ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n    ctx.beginPath(); ctx.roundRect(cx_box, y, cardW, cardH, 12); ctx.fill();\n\n    ctx.strokeStyle = rc(s.color);\n    ctx.lineWidth = 2;\n    ctx.shadowColor = rc(s.color);\n    ctx.shadowBlur = 8;\n    ctx.beginPath(); ctx.roundRect(cx_box, y, cardW, cardH, 12); ctx.stroke();\n    ctx.shadowBlur = 0;\n\n    ctx.font = '40px sans-serif';\n    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText(s.icon, cx_box + cardW/2, y + 45);\n\n    ctx.fillStyle = '#ffffff';\n    ctx.font = 'bold 13px sans-serif';\n    ctx.fillText(s.name, cx_box + cardW/2, y + 100);\n\n    ctx.fillStyle = '#22d3ee';\n    ctx.font = '11px sans-serif';\n    ctx.fillText(s.desc, cx_box + cardW/2, y + 132);\n  }\n  ctx.restore();\n  return frameH + 80;\n}"},
    {"name": "bk_tam_hoc_xoay", "when": "Trọng tâm của bài học này xoay quanh bốn trụ cột lớn để kiến tạo nên m", "code": "ctx.save();\nconst cx = W / 2;\nconst isPortrait = H > W;\n\nif (isPortrait) {\n  const w = Math.min(W - MX * 2, 480);\n  const x = cx - w / 2;\n  const y = cursorY + 10;\n  const cardH = 95;\n  const gap = 18;\n\n  const pillars = [\n    { title: \"1. Tư Duy Giao Diện\", icon: \"🧠\", color: \"cyan\", desc: \"Bố cục lưới & Spacing\" },\n    { title: \"2. Làm Đẹp Bằng AI\", icon: \"🪄\", color: \"highlight\", desc: \"Tối ưu hóa Prompts\" },\n    { title: \"3. Component Libraries\", icon: \"🧩\", color: \"green\", desc: \"Shadcn & Reusable UI\" },\n    { title: \"4. Lovart & Nanobanana\", icon: \"🍌\", color: \"orange\", desc: \"Vẽ vector theo ý định\" }\n  ];\n\n  for (let i = 0; i < pillars.length; i++) {\n    const p = pillars[i];\n    const cy_box = y + i * (cardH + gap) + 40;\n    \n    // Solid background\n    ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n    ctx.beginPath(); ctx.roundRect(x, cy_box, w, cardH, 12); ctx.fill();\n\n    // Glowing border\n    ctx.strokeStyle = rc(p.color);\n    ctx.lineWidth = 2.5;\n    ctx.shadowColor = rc(p.color);\n    ctx.shadowBlur = 8;\n    ctx.beginPath(); ctx.roundRect(x, cy_box, w, cardH, 12); ctx.stroke();\n    ctx.shadowBlur = 0;\n\n    // Content\n    ctx.font = '36px sans-serif';\n    ctx.textAlign = 'left'; ctx.textBaseline = 'middle';\n    ctx.fillText(p.icon, x + 25, cy_box + cardH/2);\n\n    ctx.fillStyle = '#ffffff';\n    ctx.font = 'bold 20px sans-serif';\n    ctx.fillText(p.title, x + 80, cy_box + 30);\n\n    ctx.fillStyle = '#22d3ee';\n    ctx.font = '16px sans-serif';\n    ctx.fillText(p.desc, x + 80, cy_box + 62);\n  }\n\n  ctx.restore();\n  return 540;\n} else {\n  const w = Math.min(W - MX * 2, 800);\n  const x = cx - w / 2;\n  const y = cursorY + 20;\n  const cardW = (w - 60) / 4;\n  const cardH = 200;\n\n  const pillars = [\n    { title: \"Tư Duy UI\", icon: \"🧠\", color: \"cyan\", desc: \"Bố cục & Spacing\" },\n    { title: \"AI Design\", icon: \"🪄\", color: \"highlight\", desc: \"Prompt làm đẹp\" },\n    { title: \"Components\", icon: \"🧩\", color: \"green\", desc: \"Thành phần tái dùng\" },\n    { title: \"Lovart Tool\", icon: \"🍌\", color: \"orange\", desc: \"Vẽ vector AI\" }\n  ];\n\n  for (let i = 0; i < pillars.length; i++) {\n    const p = pillars[i];\n    const cx_box = x + i * (cardW + 20);\n\n    // Solid background\n    ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\n    ctx.beginPath(); ctx.roundRect(cx_box, y, cardW, cardH, 12); ctx.fill();\n\n    // Glowing border\n    ctx.strokeStyle = rc(p.color);\n    ctx.lineWidth = 2;\n    ctx.shadowColor = rc(p.color);\n    ctx.shadowBlur = 8;\n    ctx.beginPath(); ctx.roundRect(cx_box, y, cardW, cardH, 12); ctx.stroke();\n    ctx.shadowBlur = 0;\n\n    // Content\n    ctx.font = '48px sans-serif';\n    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n    ctx.fillText(p.icon, cx_box + cardW/2, y + 55);\n\n    ctx.fillStyle = '#ffffff';\n    ctx.font = 'bold 15px sans-serif';\n    ctx.fillText(p.title, cx_box + cardW/2, y + 115);\n\n    ctx.fillStyle = '#22d3ee';\n    ctx.font = '12px sans-serif';\n    ctx.fillText(p.desc, cx_box + cardW/2, y + 150);\n  }\n\n  ctx.restore();\n  return 280;\n}"},
    {"name": "bk_hom_minh_cung", "when": "Hôm nay mình cùng các bạn bóc tách OpenClaw ở cấp độ hàm, tức là nhìn ", "code": "ctx.save();\nconst cx = W / 2;\nconst cy = cursorY + 110;\nconst r = W > H ? 90 : 80;\n\n// Draw scanning HUD rings\nctx.strokeStyle = 'rgba(34, 211, 238, 0.15)';\nctx.lineWidth = 1.5;\nctx.beginPath(); ctx.arc(cx, cy, r, 0, Math.PI * 2); ctx.stroke();\nctx.beginPath(); ctx.arc(cx, cy, r - 25, 0, Math.PI * 2); ctx.stroke();\nctx.beginPath(); ctx.arc(cx, cy, r + 25, 0, Math.PI * 2); ctx.stroke();\n\n// Crosshair ticks\nctx.strokeStyle = 'rgba(34, 211, 238, 0.3)';\nctx.beginPath();\nctx.moveTo(cx - r - 35, cy); ctx.lineTo(cx - r - 15, cy);\nctx.moveTo(cx + r + 15, cy); ctx.lineTo(cx + r + 35, cy);\nctx.moveTo(cx, cy - r - 35); ctx.lineTo(cx, cy - r - 15);\nctx.moveTo(cx, cy + r + 15); ctx.lineTo(cx, cy + r + 35);\nctx.stroke();\n\n// Rotating scanner sweeping line\nconst angle = (time * 1.5) % (Math.PI * 2);\nctx.strokeStyle = 'rgba(34, 211, 238, 0.6)';\nctx.lineWidth = 3;\nctx.beginPath();\nctx.moveTo(cx, cy);\nctx.lineTo(cx + Math.cos(angle) * (r + 20), cy + Math.sin(angle) * (r + 20));\nctx.stroke();\n\n// Sweeping gradient shadow wedge\nctx.fillStyle = 'rgba(34, 211, 238, 0.05)';\nctx.beginPath();\nctx.moveTo(cx, cy);\nctx.arc(cx, cy, r + 20, angle - 0.4, angle);\nctx.closePath();\nctx.fill();\n\n// Function nodes around the circle\nconst nodes = [\n    { name: 'main()', a: -Math.PI / 2, color: 'cyan' },\n    { name: 'init_config()', a: -Math.PI / 6, color: 'green' },\n    { name: 'start_gateway()', a: Math.PI / 6, color: 'highlight' },\n    { name: 'Agent.run()', a: Math.PI * 5 / 6, color: 'yellow' },\n    { name: 'on_message()', a: -Math.PI * 5 / 6, color: 'red' }\n];\n\nnodes.forEach((n, idx) => {\n    const nx = cx + Math.cos(n.a) * (r + 15);\n    const ny = cy + Math.sin(n.a) * (r + 15);\n\n    // Connection line\n    ctx.strokeStyle = 'rgba(255, 255, 255, 0.08)';\n    ctx.lineWidth = 1;\n    ctx.beginPath(); ctx.moveTo(cx, cy); ctx.lineTo(nx, ny); ctx.stroke();\n\n    // Node glow dot\n    const pulse = 1 + 0.15 * Math.sin(time * 5 + idx);\n    ctx.fillStyle = rc(n.color);\n    ctx.shadowColor = rc(n.color);\n    ctx.shadowBlur = 10 * pulse;\n    ctx.beginPath(); ctx.arc(nx, ny, 6 * pulse, 0, Math.PI * 2); ctx.fill();\n    ctx.shadowBlur = 0;\n\n    // Label\n    ctx.fillStyle = '#22d3ee';\n    ctx.font = 'bold 20px monospace';\n    ctx.textAlign = Math.cos(n.a) >= 0 ? 'left' : 'right';\n    ctx.textBaseline = 'middle';\n    const offset = Math.cos(n.a) >= 0 ? 15 : -15;\n    ctx.fillText(n.name, nx + offset, ny);\n});\n\n// Core core hub\nctx.fillStyle = '#22d3ee';\nctx.shadowColor = '#22d3ee';\nctx.shadowBlur = 15;\nctx.beginPath(); ctx.arc(cx, cy, 10, 0, Math.PI * 2); ctx.fill();\nctx.shadowBlur = 0;\n\nctx.restore();"},
    {"name": "bk_tubecreate_xuat_triet", "when": "TubeCreate đề xuất triết lý khác: Pay the navigation cost once, at com", "code": "ctx.save();const cx=W/2,cy=cursorY+420;\nctx.fillStyle=rc('green');ctx.font='bold 28px monospace';ctx.textAlign='center';\nctx.fillText('PARADIGM MỚI',cx,cursorY+55);\nctx.fillStyle='#fff';ctx.font='bold 50px \"Inter\",sans-serif';\nctx.fillText('Compile-Time Knowledge',cx,cursorY+118);\nctx.fillStyle=rc('yellow');ctx.font='bold 30px monospace';\nctx.fillText('\"Pay once. Reuse forever.\"',cx,cursorY+172);\nctx.strokeStyle='rgba(34,197,94,0.3)';ctx.lineWidth=1.5;\nctx.beginPath();ctx.moveTo(MX,cursorY+196);ctx.lineTo(W-MX,cursorY+196);ctx.stroke();\n// Animation\nconst ct=(time*0.28)%1;\nif(ct<0.32){\nconst t=ct/0.32;\nctx.fillStyle='rgba(15,23,42,0.97)';ctx.strokeStyle=rc('cyan');ctx.lineWidth=4;\nctx.save();ctx.shadowColor=rc('cyan');ctx.shadowBlur=20;\nctx.beginPath();ctx.roundRect(cx-140,cy-170,280,400,20);ctx.fill();ctx.stroke();ctx.restore();\nctx.font='84px sans-serif';ctx.textAlign='center';ctx.fillText('📕',cx,cy+60);\nctx.fillStyle=rc('cyan');ctx.font='bold 28px monospace';\nctx.fillText('500+ trang',cx,cy+140);\nctx.fillStyle=rc('yellow');ctx.font='bold 24px monospace';\nctx.fillText('Đang phân tích... '+Math.round(t*100)+'%',cx,cy+180);\n}else if(ct<0.65){\nconst t=(ct-0.32)/0.33;\nfor(let i=0;i<110;i++){const seed=i*0.618*6.28;const r=60+t*220;const px=cx+Math.cos(seed)*r*(0.5+0.5*Math.sin(t*Math.PI+i*0.1));const py=cy+Math.sin(seed)*r*0.65;const hue=(i*3.6+time*80)%360;ctx.fillStyle=`hsla(${hue},90%,65%,${(1-t)*0.9+0.05})`;ctx.beginPath();ctx.arc(px,py,4+t*4,0,Math.PI*2);ctx.fill();}\nctx.fillStyle=rc('yellow');ctx.font='bold 36px monospace';ctx.textAlign='center';\nctx.fillText('⚙ Compiling... '+Math.round(t*100)+'%',cx,cy-170);\n}else{\nconst t2=(ct-0.65)/0.35;const pulse=1+0.06*Math.sin(time*3);\nctx.fillStyle='rgba(5,20,40,0.97)';ctx.strokeStyle=rc('green');ctx.lineWidth=5;\nctx.save();ctx.shadowColor=rc('green');ctx.shadowBlur=32;\nctx.beginPath();ctx.arc(cx,cy,86*pulse,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();\nctx.font='52px sans-serif';ctx.textAlign='center';ctx.globalAlpha=t2;\nctx.fillText('⚡',cx,cy+18);ctx.fillStyle=rc('green');ctx.font='bold 30px monospace';\nctx.fillText('SKILL',cx,cy+62);ctx.globalAlpha=1;\nconst orb=['SKILL.md','chapters/','glossary','patterns','cheatsheet','index'];\nfor(let i=0;i<6;i++){const a=i*Math.PI*2/6+time*0.5;const nx=cx+Math.cos(a)*230;const ny=cy+Math.sin(a)*178;\nctx.strokeStyle='rgba(34,197,94,0.3)';ctx.lineWidth=1.5;ctx.beginPath();ctx.moveTo(cx,cy);ctx.lineTo(nx,ny);ctx.stroke();\nctx.fillStyle='rgba(15,23,42,0.97)';ctx.strokeStyle=rc('green');ctx.lineWidth=2.5;\nctx.save();ctx.shadowColor=rc('green');ctx.shadowBlur=10;ctx.globalAlpha=t2;\nctx.beginPath();ctx.arc(nx,ny,34,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle='rgba(255,255,255,0.9)';ctx.font='bold 19px monospace';ctx.textAlign='center';\nctx.globalAlpha=t2;ctx.fillText(orb[i],nx,ny+7);ctx.globalAlpha=1;}\nctx.fillStyle=rc('green');ctx.font='italic bold 28px serif';ctx.textAlign='center';\nctx.globalAlpha=t2;ctx.fillText('\"Pay once, reuse forever\"',cx,cy+270);ctx.globalAlpha=1;}\nctx.restore();return 1100;"},
    {"name": "bk_cat_ngan_form", "when": "Cắt ngắn form đến mức tối đa. Ba trường là quá đủ: tên, số điện thoại,", "code": "ctx.save();\nconst cx=W/2,cy=cursorY+150;\n// Bad form: many fields | Good form: 3 fields\n// Bad\nctx.fillStyle='rgba(239,68,68,0.08)';ctx.strokeStyle=rc('red');ctx.lineWidth=2;ctx.beginPath();ctx.roundRect(cx-200,cy-95,170,200,12);ctx.fill();ctx.stroke();\nctx.fillStyle=rc('red');ctx.font='bold 12px monospace';ctx.textAlign='center';\nctx.fillText('❌ DÀI 10+ TRƯỜNG',cx-115,cy-75);\nconst badFields=['Họ tên','SĐT','Email','Sinh nhật','Địa chỉ','Phường','Quận','TP','Mã ZIP','Nguồn'];\nbadFields.forEach((f,i)=>{const ry=cy-55+i*16;ctx.fillStyle='rgba(255,255,255,0.06)';ctx.beginPath();ctx.roundRect(cx-185,ry,140,12,3);ctx.fill();ctx.fillStyle='rgba(255,255,255,0.6)';ctx.font='9px monospace';ctx.textAlign='left';ctx.fillText(f,cx-180,ry+9);});\n// VS\nctx.fillStyle=rc('yellow');ctx.font='bold 26px monospace';ctx.textAlign='center';\nctx.fillText('→',cx,cy);\n// Good\nconst pulse=1+0.04*Math.sin(time*3);\nctx.fillStyle='rgba(34,197,94,0.12)';ctx.strokeStyle=rc('green');ctx.lineWidth=3;\nctx.save();ctx.shadowColor=rc('green');ctx.shadowBlur=14*pulse;\nctx.beginPath();ctx.roundRect(cx+30,cy-95,170,200,12);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('green');ctx.font='bold 12px monospace';\nctx.fillText('✓ ĐỦ 3 TRƯỜNG',cx+115,cy-75);\nconst goodFields=[{l:'Tên',i:'👤'},{l:'Số điện thoại',i:'📱'},{l:'Email',i:'✉️'}];\ngoodFields.forEach((f,i)=>{const ry=cy-50+i*32;ctx.fillStyle='rgba(255,255,255,0.06)';ctx.beginPath();ctx.roundRect(cx+45,ry,140,24,4);ctx.fill();ctx.fillStyle='#fff';ctx.font='14px sans-serif';ctx.textAlign='left';ctx.fillText(f.i,cx+52,ry+17);ctx.fillStyle='rgba(255,255,255,0.9)';ctx.font='bold 11px monospace';ctx.fillText(f.l,cx+72,ry+16);});\n// Big BUY button\nctx.fillStyle=rc('green');ctx.beginPath();ctx.roundRect(cx+45,cy+50,140,30,6);ctx.fill();\nctx.fillStyle='#0f172a';ctx.font='bold 13px monospace';ctx.textAlign='center';\nctx.fillText('💳 MUA NGAY',cx+115,cy+70);\nctx.restore();return 380;"},
    {"name": "bk_hay_nhin_vao", "when": "Hãy nhìn vào hiệu ứng Bơm Dữ Liệu. Bên trái, @core như một nhà máy côn", "code": "ctx.save();\nconst cx=W/2,cy=cursorY+150;\n// Left: @core factory\nctx.fillStyle='rgba(5,30,50,0.9)';ctx.strokeStyle=rc('cyan');ctx.lineWidth=2.5;\nctx.save();ctx.shadowColor=rc('cyan');ctx.shadowBlur=12;ctx.beginPath();ctx.roundRect(cx-230,cy-110,170,220,10);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('cyan');ctx.font='bold 11px monospace';ctx.textAlign='center';ctx.fillText('@core',cx-145,cy-90);\n// input files floating in\nconst fileY=(time*30)%220;\nfor(let i=0;i<3;i++){const fy=cy-100+(fileY+i*70)%220;ctx.fillStyle='rgba(56,189,248,0.6)';ctx.font='18px monospace';ctx.textAlign='center';ctx.fillText(['📄','📝','📋'][i],cx-215,fy);}\n// crystals output\nfor(let i=0;i<4;i++){const t=(time*0.5+i*0.25)%1;const phase=t<0.5?t*2:1;const cx2=cx-145+10*Math.sin(time*3+i);const cy2=cy-20+i*22;ctx.fillStyle=`rgba(168,85,247,${0.7+0.3*Math.sin(time*4+i)})`;ctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=8;ctx.beginPath();ctx.moveTo(cx2,cy2-8);ctx.lineTo(cx2+7,cy2);ctx.lineTo(cx2,cy2+8);ctx.lineTo(cx2-7,cy2);ctx.closePath();ctx.fill();ctx.restore();}\n// pipe\nctx.strokeStyle='rgba(168,85,247,0.6)';ctx.lineWidth=8;ctx.lineCap='round';ctx.beginPath();ctx.moveTo(cx-60,cy);ctx.lineTo(cx+60,cy);ctx.stroke();\n// flowing particles in pipe\nfor(let i=0;i<5;i++){const t=((time*0.8)+i*0.2)%1;const px=cx-60+t*120;ctx.fillStyle='rgba(168,85,247,0.9)';ctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=10;ctx.beginPath();ctx.arc(px,cy,4,0,Math.PI*2);ctx.fill();ctx.restore();}\n// Right: @dashboard explosion\nctx.fillStyle='rgba(30,20,5,0.9)';ctx.strokeStyle=rc('yellow');ctx.lineWidth=2.5;\nctx.save();ctx.shadowColor=rc('yellow');ctx.shadowBlur=12;ctx.beginPath();ctx.roundRect(cx+60,cy-110,170,220,10);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle=rc('yellow');ctx.font='bold 11px monospace';ctx.textAlign='center';ctx.fillText('@dashboard',cx+145,cy-90);\n// React component cards\nconst cards=[['auth',cx+95,cy-50,rc('cyan')],['api',cx+175,cy-60,rc('yellow')],['db',cx+145,cy+20,rc('green')]];\nfor(const[name,nx,ny,col] of cards){ctx.fillStyle='rgba(15,23,42,0.9)';ctx.strokeStyle=col;ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(nx-22,ny-12,44,24,4);ctx.fill();ctx.stroke();ctx.fillStyle='#fff';ctx.font='bold 8px monospace';ctx.textAlign='center';ctx.fillText(name,nx,ny+4);ctx.strokeStyle=`rgba(148,163,184,0.3)`;ctx.lineWidth=1;ctx.beginPath();ctx.moveTo(nx,ny+12);ctx.lineTo(cx+145,cy+50);ctx.stroke();}\nctx.restore();return 380;"},
    {"name": "bk_tom_lai_openclaw", "when": "Tóm lại, đến đây OpenClaw của bạn đã có bộ não để tư duy. Bạn có thể c", "code": "ctx.save();\nconst cx = W / 2;\nconst cy = cursorY + 110;\nconst r = 52;\n\nctx.strokeStyle = 'rgba(34, 211, 238, 0.08)';\nctx.lineWidth = 1;\nctx.beginPath();\nctx.arc(cx, cy, r + 40, 0, Math.PI * 2);\nctx.stroke();\n\nconst waveCount = 3;\nfor (let i = 0; i < waveCount; i++) {\n  const waveProg = ((time * 0.12 + i / waveCount) % 1.0);\n  const waveR = r + waveProg * 90;\n  ctx.strokeStyle = `rgba(34, 211, 238, ${0.28 * (1 - waveProg)})`;\n  ctx.lineWidth = 2;\n  ctx.beginPath();\n  ctx.arc(cx, cy, waveR, 0, Math.PI * 2);\n  ctx.stroke();\n}\n\nconst channels = [\n  { name: \"Telegram Bot\", icon: \"✈️\", a: -Math.PI / 2, color: \"cyan\" },\n  { name: \"Zalo API\", icon: \"💬\", a: Math.PI / 6, color: \"highlight\" },\n  { name: \"Discord API\", icon: \"👾\", a: (5 * Math.PI) / 6, color: \"green\" }\n];\n\nchannels.forEach((ch, idx) => {\n  const targetX = cx + Math.cos(ch.a) * 110;\n  const targetY = cy + Math.sin(ch.a) * 110;\n\n  ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';\n  ctx.lineWidth = 2.5;\n  ctx.setLineDash([4, 4]);\n  ctx.beginPath();\n  ctx.moveTo(cx, cy);\n  ctx.lineTo(targetX, targetY);\n  ctx.stroke();\n  ctx.setLineDash([]);\n\n  const pProg = (time * 0.22 + idx * 0.3) % 1.0;\n  const px = cx + (targetX - cx) * pProg;\n  const py = cy + (targetY - cy) * pProg;\n  ctx.fillStyle = rc(ch.color);\n  ctx.shadowColor = rc(ch.color);\n  ctx.shadowBlur = 10;\n  ctx.beginPath();\n  ctx.arc(px, py, 4.5, 0, Math.PI * 2);\n  ctx.fill();\n  ctx.shadowBlur = 0;\n\n  ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';\n  ctx.strokeStyle = rc(ch.color);\n  ctx.lineWidth = 1.5;\n  ctx.beginPath();\n  ctx.roundRect(targetX - 25, targetY - 25, 50, 50, 12);\n  ctx.fill();\n  ctx.stroke();\n\n  ctx.font = '24px sans-serif';\n  ctx.textAlign = 'center';\n  ctx.textBaseline = 'middle';\n  ctx.fillText(ch.icon, targetX, targetY - 2);\n\n  ctx.fillStyle = '#22d3ee';\n  ctx.font = 'bold 13px monospace';\n  ctx.fillText(ch.name, targetX, targetY + 38);\n});\n\nctx.fillStyle = 'rgba(15, 23, 42, 0.95)';\nctx.strokeStyle = '#10b981';\nctx.lineWidth = 3;\nctx.shadowColor = '#10b981';\nctx.shadowBlur = 15;\nctx.beginPath();\nctx.roundRect(cx - 32, cy - 32, 64, 64, 16);\nctx.fill();\nctx.stroke();\nctx.shadowBlur = 0;\n\nconst pulse = 1 + 0.07 * Math.sin(time * 2.2);\nctx.font = `${Math.round(32 * pulse)}px sans-serif`;\nctx.textAlign = 'center';\nctx.textBaseline = 'middle';\nctx.fillText(\"🤖\", cx, cy - 2);\n\nctx.restore();"},
    {"name": "bk_hai_loai_nguon", "when": "Có hai loại nguồn traffic chính trong arbitrage: Nguồn traffic trả tiề", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 140;\nconst isPortrait = H > W;\n\n// Two categories: Paid vs Organic\nconst lx = isPortrait ? cx - 160 : cx - 230;\nconst rx = isPortrait ? cx + 160 : cx + 230;\nconst topY = cy - 80;\n\n// Paid traffic (left)\nconst paidSources = ['FB Ads', 'TikTok', 'Taboola', 'Google'];\nconst paidIcons = ['📱', '🎵', '📰', '🔍'];\nctx.fillStyle = 'rgba(239,68,68,0.08)'; ctx.strokeStyle = rc('red'); ctx.lineWidth = 3;\nctx.beginPath(); ctx.roundRect(lx - (isPortrait ? 130 : 100), topY - 30, isPortrait ? 260 : 200, 260, 14); ctx.fill(); ctx.stroke();\nctx.fillStyle = rc('red'); ctx.font = 'bold 18px monospace'; ctx.textAlign = 'center';\nctx.fillText('💳 TRẢ TIỀN', lx, topY - 8);\npaidSources.forEach((s, i) => {\n  ctx.fillStyle = '#fff'; ctx.font = '18px sans-serif';\n  ctx.fillText(paidIcons[i] + ' ' + s, lx, topY + 30 + i * 40);\n});\n\n// Organic traffic (right)\nconst orgSources = ['SEO Blog', 'YouTube', 'Twitter/X', 'TikTok Organic'];\nconst orgIcons = ['📝', '🎥', '🐦', '🌿'];\nctx.fillStyle = 'rgba(16,185,129,0.08)'; ctx.strokeStyle = rc('green'); ctx.lineWidth = 3;\nctx.beginPath(); ctx.roundRect(rx - (isPortrait ? 130 : 100), topY - 30, isPortrait ? 260 : 200, 260, 14); ctx.fill(); ctx.stroke();\nctx.fillStyle = rc('green'); ctx.font = 'bold 18px monospace';\nctx.fillText('🌿 ORGANIC', rx, topY - 8);\norgSources.forEach((s, i) => {\n  ctx.fillStyle = '#fff'; ctx.font = '18px sans-serif';\n  ctx.fillText(orgIcons[i] + ' ' + s, rx, topY + 30 + i * 40);\n});\n\n// Converge arrow to your site\nif (stepProgress > 0.5) {\n  const siteY = topY + 250;\n  ctx.fillStyle = 'rgba(15,23,42,0.95)'; ctx.strokeStyle = rc('highlight'); ctx.lineWidth = 4;\n  ctx.save(); ctx.shadowColor = rc('highlight'); ctx.shadowBlur = 16;\n  ctx.beginPath(); ctx.roundRect(cx - 90, siteY, 180, 50, 10); ctx.fill(); ctx.stroke();\n  ctx.restore();\n  ctx.fillStyle = '#fff'; ctx.font = 'bold 18px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('🌐 WEBSITE CỦA BẠN', cx, siteY + 25);\n\n  // Converge lines\n  [[lx, topY + 230], [rx, topY + 230]].forEach(([sx, sy]) => {\n    ctx.strokeStyle = rc('yellow'); ctx.lineWidth = 3; ctx.setLineDash([8,5]);\n    ctx.beginPath(); ctx.moveTo(sx, sy); ctx.lineTo(cx, siteY); ctx.stroke();\n    ctx.setLineDash([]);\n  });\n}\n\nctx.restore();\nreturn 380;"},
    {"name": "bk_sau_tim_duoc", "when": "Sau khi tìm được mô hình có Proof of Concept, bước tiếp theo là phân t", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 135;\n\n// Magnifying glass scanning review\nconst scanX = cx + (Math.sin(time * 0.7) * 120);\nconst scanY = cy - 40;\n\n// Review cards background - Bigger fonts, high contrast\nconst reviews = [\n  {x: cx - 220, y: cy - 60, stars: 1, text: 'Too expensive!\\nNo refund policy...', color: 'red'},\n  {x: cx + 20, y: cy - 30, stars: 2, text: 'UI is confusing\\nhard to navigate', color: 'yellow'},\n  {x: cx - 80, y: cy + 70, stars: 1, text: 'No mobile app!\\ndesktop only', color: 'red'},\n];\nreviews.forEach((rv, idx) => {\n  const show = stepProgress > idx * 0.2;\n  ctx.fillStyle = show ? 'rgba(20,20,40,0.9)' : 'rgba(20,20,40,0.3)';\n  ctx.strokeStyle = show ? `rgba(239,68,68,${0.5 + 0.3 * Math.sin(time + idx)})` : 'rgba(255,255,255,0.05)'; ctx.lineWidth = 2;\n  ctx.beginPath(); ctx.roundRect(rv.x - 90, rv.y - 42, 180, 84, 8); ctx.fill(); ctx.stroke();\n  // Stars\n  for (let s = 0; s < 5; s++) {\n    ctx.fillStyle = s < rv.stars ? '#f59e0b' : 'rgba(255,255,255,0.15)';\n    ctx.font = '16px sans-serif'; ctx.textAlign = 'center';\n    ctx.fillText('★', rv.x - 36 + s * 18, rv.y - 20);\n  }\n  ctx.fillStyle = show ? '#ccc' : '#666'; ctx.font = '16px monospace';\n  rv.text.split('\\n').forEach((line, li) => ctx.fillText(line, rv.x, rv.y + li * 22));\n  // Insight tag\n  if (show && stepProgress > idx * 0.2 + 0.3) {\n    ctx.fillStyle = rc('green'); ctx.font = 'bold 18px monospace';\n    ctx.fillText('→ CƠ HỘI!', rv.x + 65, rv.y + 32);\n  }\n});\n\n// Magnifying glass\nctx.strokeStyle = rc('highlight'); ctx.lineWidth = 6;\nctx.beginPath(); ctx.arc(scanX, scanY, 40, 0, Math.PI*2); ctx.stroke();\nctx.strokeStyle = rc('highlight'); ctx.lineWidth = 6; ctx.lineCap = 'round';\nctx.beginPath(); ctx.moveTo(scanX + 28, scanY + 28); ctx.lineTo(scanX + 55, scanY + 55); ctx.stroke();\n// Lens glow\nctx.fillStyle = 'rgba(245,158,11,0.08)';\nctx.beginPath(); ctx.arc(scanX, scanY, 40, 0, Math.PI*2); ctx.fill();\n\n// 3 Golden Questions - High visibility\nif (stepProgress > 0.65) {\n  ctx.fillStyle = rc('yellow'); ctx.font = 'bold 24px sans-serif'; ctx.textAlign = 'center';\n  ctx.fillText('3 Câu Hỏi Vàng khi phỏng vấn user:', cx, cy + 148);\n  ['Điều bực bội nhất?', 'Tính năng mong muốn?', 'Sẽ chuyển sang đối thủ vì?'].forEach((q, i) => {\n    ctx.fillStyle = '#aaa'; ctx.font = '22px monospace';\n    ctx.fillText((i+1) + '. ' + q, cx, cy + 180 + i * 26);\n  });\n}\n\nctx.restore();\nreturn 370;"},
    {"name": "bk_lam_nao_biet", "when": "Nhưng làm thế nào biết micro-niche của bạn đủ lớn để kiếm tiền? Công t", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 140;\n\n// TAM > SAM > SOM drill - clear labels\nconst circles = [\n  {label: 'TAM', sublabel: 'Tổng thị trường', value: '500K người\\n(Tiếng Anh VN)', r: 150, color: 'muted'},\n  {label: 'SAM', sublabel: 'Thị trường phục vụ', value: '50K bác sĩ\\ncần USMLE', r: 95, color: 'cyan'},\n  {label: 'SOM', sublabel: 'Thị trường chiếm được', value: '5K target\\ntháng đầu', r: 45, color: 'green'},\n];\n\nconst drillProg = Math.min(1.0, stepProgress * 1.2);\n\ncircles.forEach((c, idx) => {\n  const show = drillProg > idx * 0.25;\n  if (!show) return;\n  const pulse = (idx === circles.length - 1 && show) ? 1 + 0.1 * Math.sin(time * 3) : 1;\n  ctx.fillStyle = `rgba(15,23,42,${0.1 + idx * 0.15})`;\n  ctx.strokeStyle = show ? (idx === 0 ? '#666' : rc(c.color)) : 'rgba(255,255,255,0.05)';\n  ctx.lineWidth = idx === 2 ? 4 : 2;\n  ctx.save(); if (show && idx === 2) { ctx.shadowColor = rc(c.color); ctx.shadowBlur = 22 * pulse; }\n  ctx.beginPath(); ctx.arc(cx, cy, c.r * pulse, 0, Math.PI*2); ctx.fill(); ctx.stroke();\n  ctx.restore();\n\n  // Labels - clearly positioned outside\n  const la = idx * 0.8 + 0.8;\n  const lr = c.r + 38;\n  const labelX = cx + Math.cos(la) * lr;\n  const labelY = cy + Math.sin(la) * lr;\n  const offX = Math.cos(la) > 0 ? 90 : -90;\n\n  ctx.fillStyle = idx === 0 ? '#aaa' : rc(c.color);\n  ctx.font = `bold ${idx === 2 ? 28 : 24}px monospace`; ctx.textAlign = 'center';\n  ctx.fillText(c.label, labelX + offX, labelY - 16);\n  ctx.fillStyle = '#bbb'; ctx.font = '20px monospace';\n  ctx.fillText(c.sublabel, labelX + offX, labelY + 6);\n  c.value.split('\\n').forEach((line, li) => {\n    ctx.fillStyle = '#999'; ctx.font = '18px monospace';\n    ctx.fillText(line, labelX + offX, labelY + 28 + li * 20);\n  });\n\n  // Connector line\n  ctx.strokeStyle = idx === 0 ? '#555' : rc(c.color); ctx.lineWidth = 1.5; ctx.setLineDash([5,4]);\n  ctx.beginPath(); ctx.moveTo(labelX, labelY); ctx.lineTo(labelX + offX * 0.5, labelY); ctx.stroke();\n  ctx.setLineDash([]);\n});\n\n// Center SOM label\nconst cPulse = 1 + 0.12 * Math.sin(time * 4);\nctx.fillStyle = '#fff'; ctx.save(); ctx.shadowColor = rc('green'); ctx.shadowBlur = 18;\nctx.font = `bold ${Math.round(22 * cPulse)}px monospace`; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\nctx.fillText('SOM', cx, cy);\nctx.restore();\n\n// Revenue math\nif (drillProg > 0.7) {\n  ctx.fillStyle = '#aaffaa'; ctx.font = 'bold 30px sans-serif'; ctx.textBaseline = 'alphabetic'; ctx.textAlign = 'center';\n  ctx.fillText('5K × 10% × 5tr = 2.5 tỷ 🤑', cx, cy + 200);\n}\n\nctx.restore();\nreturn 380;"},
    {"name": "bk_loi_duoc_nhac", "when": "Một trong những lợi thế ít được nhắc đến nhất của micro-niche là Prici", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 135;\nconst w = Math.min(W - 80, 760);\n\nconst generic = {price: 200000, label: 'Sản phẩm\\nchung chung', color: '#aaa'};\nconst niche = {price: 800000, label: 'Micro-Niche\\nchuyên biệt', color: 'green'};\n\nconst isPortrait = H > W;\nconst lx = isPortrait ? cx - 150 : cx - 240;\nconst rx = isPortrait ? cx + 150 : cx + 240;\nconst maxH = 180;\n\n// Bar chart\nconst barW = 100;\nconst priceProg = Math.min(1.0, stepProgress * 1.2);\n\n// Generic bar\nconst gh = maxH * (generic.price / niche.price) * priceProg;\nconst gby = cy + 80 - gh;\nctx.fillStyle = 'rgba(255,255,255,0.06)'; ctx.strokeStyle = '#aaa'; ctx.lineWidth = 2;\nctx.beginPath(); ctx.roundRect(lx - barW/2, gby, barW, gh, {tl:6, tr:6}); ctx.fill(); ctx.stroke();\nctx.fillStyle = '#aaa'; ctx.font = 'bold 22px monospace'; ctx.textAlign = 'center';\nctx.fillText('200K', lx, gby - 10);\ngeneric.label.split('\\n').forEach((l, li) => {\n  ctx.fillStyle = '#aaa'; ctx.font = 'bold 18px monospace';\n  ctx.fillText(l, lx, cy + 100 + li * 24);\n});\n\n// Niche bar (taller, glowing)\nconst nh = maxH * priceProg;\nconst nby = cy + 80 - nh;\nconst grad = ctx.createLinearGradient(0, nby, 0, cy + 80);\ngrad.addColorStop(0, rc('green')); grad.addColorStop(1, 'rgba(16,185,129,0.1)');\nctx.fillStyle = grad; ctx.strokeStyle = rc('green'); ctx.lineWidth = 3;\nctx.save(); ctx.shadowColor = rc('green'); ctx.shadowBlur = 18;\nctx.beginPath(); ctx.roundRect(rx - barW/2, nby, barW, nh, {tl:6, tr:6}); ctx.fill(); ctx.stroke();\nctx.restore();\nctx.fillStyle = rc('green'); ctx.font = 'bold 26px monospace';\nctx.fillText('800K', rx, nby - 10);\nniche.label.split('\\n').forEach((l, li) => {\n  ctx.fillStyle = rc('green'); ctx.font = 'bold 18px monospace';\n  ctx.fillText(l, rx, cy + 100 + li * 24);\n});\n\n// Multiplier badge\nif (priceProg > 0.6) {\n  const mx = cx, my = cy - 40;\n  ctx.fillStyle = rc('yellow'); ctx.save(); ctx.shadowColor = rc('yellow'); ctx.shadowBlur = 16;\n  ctx.font = 'bold 36px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('4×', mx, my);\n  ctx.restore();\n  ctx.fillStyle = rc('yellow'); ctx.font = 'bold 20px sans-serif';\n  ctx.fillText('cao hơn vẫn bán được', mx, my + 26);\n}\n\n// Baseline\nctx.strokeStyle = 'rgba(255,255,255,0.1)'; ctx.lineWidth = 2;\nctx.beginPath(); ctx.moveTo(lx - 80, cy + 80); ctx.lineTo(rx + 80, cy + 80); ctx.stroke();\n\nctx.restore();\nreturn 370;"},
    {"name": "bk_nguoi_thuong_lam", "when": "Người ta thường lầm tưởng rằng xây dựng tự động hóa phải cực kỳ phức t", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 135;\n\n// No-code workflow with animated connections\nconst nodes = [\n    {x: cx - 180, y: cy - 20, label: '📋\\nFORM', color: 'cyan', icon: '📝'},\n    {x: cx, y: cy - 20, label: '⚙️\\nMAKE', color: 'yellow', icon: '🔧'},\n    {x: cx + 180, y: cy - 20, label: '✉️\\nEMAIL', color: 'green', icon: '📧'}\n];\n\nconst radius = 50;\n\n// Draw animated data flow lines\nfor (let i = 0; i < nodes.length - 1; i++) {\n    const n1 = nodes[i];\n    const n2 = nodes[i + 1];\n    \n    // Flow particles\n    for (let j = 0; j < 3; j++) {\n        const t = (time * 0.6 + j * 0.3 + i * 0.5) % 1.0;\n        const px = n1.x + (n2.x - n1.x) * t;\n        const py = n1.y + (n2.y - n1.y) * t + Math.sin(t * Math.PI * 2) * 15;\n        \n        ctx.fillStyle = rc(nodes[i + 1].color);\n        ctx.save();\n        ctx.shadowColor = rc(nodes[i + 1].color);\n        ctx.shadowBlur = 10;\n        ctx.beginPath();\n        ctx.arc(px, py, 5, 0, Math.PI * 2);\n        ctx.fill();\n        ctx.restore();\n    }\n    \n    // Connection line\n    ctx.strokeStyle = 'rgba(255,255,255,0.1)';\n    ctx.lineWidth = 3;\n    ctx.setLineDash([10, 5]);\n    ctx.beginPath();\n    ctx.moveTo(n1.x + radius, n1.y);\n    ctx.lineTo(n2.x - radius, n2.y);\n    ctx.stroke();\n    ctx.setLineDash([]);\n}\n\n// Draw nodes\nnodes.forEach((node, idx) => {\n    const pulse = 1 + 0.08 * Math.sin(time * 2.5 + idx * 1.2);\n    \n    // Node circle with glow\n    ctx.fillStyle = 'rgba(15,23,42,0.95)';\n    ctx.strokeStyle = rc(node.color);\n    ctx.lineWidth = 4;\n    ctx.save();\n    ctx.shadowColor = rc(node.color);\n    ctx.shadowBlur = 20 * pulse;\n    ctx.beginPath();\n    ctx.arc(node.x, node.y, radius * pulse, 0, Math.PI * 2);\n    ctx.fill();\n    ctx.stroke();\n    ctx.restore();\n    \n    // Icon\n    ctx.fillStyle = '#fff';\n    ctx.font = '32px sans-serif';\n    ctx.textAlign = 'center';\n    ctx.fillText(node.icon, node.x, node.y + 10);\n    \n    // Label below\n    ctx.fillStyle = rc(node.color);\n    ctx.font = 'bold 14px monospace';\n    const lines = node.label.split('\\n');\n    lines.forEach((line, i) => {\n        ctx.fillText(line, node.x, node.y + radius + 25 + i * 18);\n    });\n});\n\n// Title\nctx.fillStyle = rc('yellow');\nctx.font = 'bold 20px monospace';\nctx.textAlign = 'center';\nctx.save();\nctx.shadowColor = rc('yellow');\nctx.shadowBlur = 10;\nctx.fillText('🚀 ZERO CODE - FULL POWER', cx, cy - 90);\nctx.restore();\n\nctx.restore();\nreturn 380;"},
    {"name": "bk_chien_luoc_thu", "when": "Chiến lược thứ tư: Semantic Deduplication. Trước khi gửi batch file ch", "code": "ctx.save();\nconst cx=W/2,cy=cursorY+175;\n// Similar files detected, one analyzed, other gets copy\nconst f1={x:cx-120,y:cy-80,name:'userUtils.ts',analyzed:true};\nconst f2={x:cx+120,y:cy-80,name:'adminUtils.ts',analyzed:false};\n// similarity badge\nconst simPulse=1+0.06*Math.sin(time*3);ctx.fillStyle='rgba(168,85,247,0.15)';ctx.strokeStyle='#a855f7';ctx.lineWidth=3;\nctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=20*simPulse;\nctx.beginPath();ctx.roundRect(cx-85,cy-105,170,36,18);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle='#a855f7';ctx.font='bold 16px monospace';ctx.textAlign='center';\nctx.fillText('🔁 92% tương đồng',cx,cy-81);\n// file 1: analyzed\nconst p1=1+0.05*Math.sin(time*2.5);ctx.fillStyle='rgba(34,197,94,0.12)';ctx.strokeStyle=rc('green');ctx.lineWidth=3;\nctx.save();ctx.shadowColor=rc('green');ctx.shadowBlur=18*p1;ctx.beginPath();ctx.roundRect(f1.x-75,f1.y-36,150,72,12);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle='#fff';ctx.font='bold 28px sans-serif';ctx.textAlign='center';ctx.fillText('🔬',f1.x,f1.y-4);\nctx.fillStyle=rc('green');ctx.font='bold 14px monospace';ctx.fillText(f1.name,f1.x,f1.y+18);\nctx.fillStyle='rgba(34,197,94,0.8)';ctx.font='13px monospace';ctx.fillText('✓ Phân tích đầy đủ',f1.x,f1.y+35);\n// arrow copy\nconst t=((time*0.8))%1;const px=f1.x+90+(f2.x-f1.x-180)*t;\nctx.strokeStyle='rgba(168,85,247,0.5)';ctx.lineWidth=2.5;ctx.beginPath();ctx.moveTo(f1.x+75,f1.y);ctx.lineTo(f2.x-75,f2.y);ctx.stroke();\nctx.fillStyle='#a855f7';ctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=12;ctx.beginPath();ctx.arc(px,cy-80,7,0,Math.PI*2);ctx.fill();ctx.restore();\nctx.fillStyle='rgba(168,85,247,0.8)';ctx.font='bold 14px monospace';ctx.textAlign='center';ctx.fillText('copy label →',cx,cy-60);\n// file 2: copy\nctx.fillStyle='rgba(168,85,247,0.1)';ctx.strokeStyle='#a855f7';ctx.lineWidth=3;\nctx.save();ctx.shadowColor='#a855f7';ctx.shadowBlur=14;ctx.beginPath();ctx.roundRect(f2.x-75,f2.y-36,150,72,12);ctx.fill();ctx.stroke();ctx.restore();\nctx.fillStyle='#fff';ctx.font='bold 28px sans-serif';ctx.textAlign='center';ctx.fillText('📋',f2.x,f2.y-4);\nctx.fillStyle='#a855f7';ctx.font='bold 14px monospace';ctx.fillText(f2.name,f2.x,f2.y+18);\nctx.fillStyle='rgba(168,85,247,0.8)';ctx.font='13px monospace';ctx.fillText('0 token dùng',f2.x,f2.y+35);\nctx.fillStyle=rc('yellow');ctx.font='bold 18px serif';ctx.textAlign='center';\nctx.fillText('Tiết kiệm 40% token boilerplate',cx,cy+80);\nctx.restore();return 380;"},
    {"name": "bk_hay_bat_dau", "when": "Hãy bắt đầu bằng một quan sát đơn giản nhưng đắt giá. Trong codebase t", "code": "ctx.save();\nconst cx=W/2,cy=cursorY+175;\n// two dense clusters with thin bridges\nconst leftC={x:cx-130,y:cy};\nconst rightC={x:cx+130,y:cy};\nconst leftNodes=[];const rightNodes=[];\nfor(let i=0;i<5;i++){const a=(i/5)*Math.PI*2+time*0.3;leftNodes.push({x:leftC.x+Math.cos(a)*55,y:leftC.y+Math.sin(a)*55});}\nfor(let i=0;i<5;i++){const a=(i/5)*Math.PI*2-time*0.3;rightNodes.push({x:rightC.x+Math.cos(a)*55,y:rightC.y+Math.sin(a)*55});}\n// dense edges within clusters\nctx.strokeStyle=`rgba(56,189,248,${0.4+0.2*Math.sin(time*2)})`;ctx.lineWidth=2;ctx.beginPath();for(let i=0;i<leftNodes.length;i++)for(let j=i+1;j<leftNodes.length;j++){ctx.moveTo(leftNodes[i].x,leftNodes[i].y);ctx.lineTo(leftNodes[j].x,leftNodes[j].y);}ctx.stroke();\nctx.strokeStyle=`rgba(34,197,94,${0.4+0.2*Math.sin(time*2)})`;ctx.lineWidth=2;ctx.beginPath();for(let i=0;i<rightNodes.length;i++)for(let j=i+1;j<rightNodes.length;j++){ctx.moveTo(rightNodes[i].x,rightNodes[i].y);ctx.lineTo(rightNodes[j].x,rightNodes[j].y);}ctx.stroke();\n// thin bridges (just 2)\nconst bridges=[[1,1],[3,2]];\nfor(const b of bridges){const a=leftNodes[b[0]],c=rightNodes[b[1]];ctx.strokeStyle=rc('red');ctx.lineWidth=2.5;ctx.save();ctx.shadowColor=rc('red');ctx.shadowBlur=10;ctx.setLineDash([5,4]);ctx.beginPath();ctx.moveTo(a.x,a.y);ctx.lineTo(c.x,c.y);ctx.stroke();ctx.setLineDash([]);ctx.restore();const t=(time*0.7)%1;const px=a.x+(c.x-a.x)*t,py=a.y+(c.y-a.y)*t;ctx.fillStyle=rc('red');ctx.beginPath();ctx.arc(px,py,5,0,Math.PI*2);ctx.fill();}\n// nodes\nfor(const n of leftNodes){const pulse=1+0.05*Math.sin(time*2.5);ctx.fillStyle='rgba(15,23,42,0.95)';ctx.strokeStyle=rc('cyan');ctx.lineWidth=2.5;ctx.save();ctx.shadowColor=rc('cyan');ctx.shadowBlur=12*pulse;ctx.beginPath();ctx.arc(n.x,n.y,16,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();}\nfor(const n of rightNodes){const pulse=1+0.05*Math.sin(time*2.5);ctx.fillStyle='rgba(15,23,42,0.95)';ctx.strokeStyle=rc('green');ctx.lineWidth=2.5;ctx.save();ctx.shadowColor=rc('green');ctx.shadowBlur=12*pulse;ctx.beginPath();ctx.arc(n.x,n.y,16,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.restore();}\nctx.fillStyle=rc('cyan');ctx.font='bold 18px monospace';ctx.textAlign='center';ctx.fillText('Cụm 1: 10 cạnh',leftC.x,leftC.y-95);\nctx.fillStyle=rc('green');ctx.font='bold 18px monospace';ctx.fillText('Cụm 2: 10 cạnh',rightC.x,rightC.y-95);\nctx.fillStyle=rc('red');ctx.font='bold 16px monospace';ctx.fillText('↔ Cầu nối: chỉ 2 cạnh',cx,cy+110);\nctx.restore();return 380;"},
    {"name": "bk_che_cot_loi", "when": "Cơ chế cốt lõi là Data Replication — nhân bản dữ liệu. Khi bạn thực hi", "code": "ctx.save();\nconst cx = W / 2, cy = cursorY + 150;\n\n// Write request from user\nconst userX = cx, userY = cy - 120;\nctx.fillStyle = 'rgba(15,23,42,0.9)'; ctx.strokeStyle = '#fbbf24'; ctx.lineWidth = 3;\nctx.beginPath(); ctx.roundRect(userX - 55, userY - 20, 110, 42, 8); ctx.fill(); ctx.stroke();\nctx.fillStyle = '#ffffff'; ctx.font = '14px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\nctx.fillText('📱 +500,000 VNĐ', userX, userY);\n\n// Primary node\nconst primaryX = cx, primaryY = cy - 20;\nif (stepProgress > 0.2) {\n  ctx.strokeStyle = '#6366f1'; ctx.lineWidth = 2; ctx.lineDashOffset = -time * 20; ctx.setLineDash([5, 3]);\n  ctx.beginPath(); ctx.moveTo(userX, userY + 22); ctx.lineTo(primaryX, primaryY - 28); ctx.stroke(); ctx.setLineDash([]);\n  ctx.fillStyle = 'rgba(15,23,42,0.9)'; ctx.strokeStyle = '#6366f1'; ctx.lineWidth = 4;\n  ctx.save(); ctx.shadowColor = '#6366f1'; ctx.shadowBlur = 16;\n  ctx.beginPath(); ctx.roundRect(primaryX - 55, primaryY - 28, 110, 52, 10); ctx.fill(); ctx.stroke(); ctx.restore();\n  ctx.fillStyle = '#a78bfa'; ctx.font = 'bold 13px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('🏢 Primary', primaryX, primaryY - 8);\n  ctx.fillStyle = '#10b981'; ctx.font = 'bold 11px monospace';\n  ctx.fillText('Node (Leader)', primaryX, primaryY + 10);\n}\n\n// Replica nodes\nconst replicas = [\n  {x: cx - 140, y: cy + 80, label: '🇻🇳 Replica', sub: 'Hà Nội', color: '#22d3ee'},\n  {x: cx, y: cy + 90, label: '🇸🇬 Replica', sub: 'Singapore', color: '#10b981'},\n  {x: cx + 140, y: cy + 80, label: '🇯🇵 Replica', sub: 'Tokyo', color: '#f97316'},\n];\nreplicas.forEach((r, i) => {\n  const show = stepProgress > 0.4 + i * 0.15;\n  if (!show) return;\n  // Arrow from primary\n  const copyT = Math.min(1, (stepProgress - 0.4 - i * 0.15) / 0.2);\n  const arrowX = primaryX + (r.x - primaryX) * copyT;\n  const arrowY = primaryY + 12 + (r.y - primaryY - 28) * copyT;\n  ctx.fillStyle = r.color;\n  ctx.save(); ctx.shadowColor = r.color; ctx.shadowBlur = 8;\n  ctx.beginPath(); ctx.arc(arrowX, arrowY, 5, 0, Math.PI * 2); ctx.fill(); ctx.restore();\n\n  ctx.fillStyle = 'rgba(15,23,42,0.9)'; ctx.strokeStyle = r.color; ctx.lineWidth = 3;\n  ctx.save(); ctx.shadowColor = r.color; ctx.shadowBlur = 10;\n  ctx.beginPath(); ctx.roundRect(r.x - 55, r.y - 28, 110, 52, 8); ctx.fill(); ctx.stroke(); ctx.restore();\n  ctx.fillStyle = r.color; ctx.font = 'bold 12px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText(r.label, r.x, r.y - 8);\n  ctx.fillStyle = '#94a3b8'; ctx.font = '10px monospace';\n  ctx.fillText(r.sub, r.x, r.y + 10);\n});\n\n// Confirm badge\nif (stepProgress > 0.9) {\n  ctx.fillStyle = '#10b981'; ctx.font = 'bold 14px monospace'; ctx.textAlign = 'center';\n  ctx.fillText('✅ 3/3 Confirmed → GD Thành Công!', cx, cy + 135);\n}\n\nctx.restore();\nreturn 300;"},
    {"name": "bk_mat_thuat_escrow", "when": "Về mặt kỹ thuật, Escrow là một trạng thái đặc biệt trong cơ sở dữ liệu", "code": "ctx.save();\nconst cx = W/2, cy = cursorY + 140;\n\n// Table header\nconst cols = ['escrow_id', 'order_id', 'buyer', 'seller', 'amount', 'status'];\nconst colW = 90;\nconst tblW = cols.length * colW;\ntblX = cx - tblW/2; tblY = cy - 100;\n\nctx.fillStyle = '#1e293b'; ctx.strokeStyle = '#fbbf24'; ctx.lineWidth = 2;\nctx.beginPath(); ctx.roundRect(tblX, tblY, tblW, 36, [6,6,0,0]); ctx.fill(); ctx.stroke();\ncols.forEach((c, i) => {\n  ctx.fillStyle = '#fbbf24'; ctx.font = 'bold 9px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText(c, tblX + colW*i + colW/2, tblY + 18);\n});\n\n// Data row with animated status\nconst statuses = ['PENDING', 'HOLDING', 'COMPLETED'];\nconst statusColors = ['#94a3b8', '#fbbf24', '#10b981'];\nconst curStat = stepProgress < 0.3 ? 0 : stepProgress < 0.7 ? 1 : 2;\nconst row = ['ESC-001', 'ORD-482', 'u_4f2a', 'u_8c3d', '150,000đ', statuses[curStat]];\n\nctx.fillStyle = 'rgba(15,23,42,0.9)'; ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;\nctx.beginPath(); ctx.roundRect(tblX, tblY+36, tblW, 40, [0,0,6,6]); ctx.fill(); ctx.stroke();\nrow.forEach((cell, ci) => {\n  const isStatus = ci === 5;\n  ctx.fillStyle = isStatus ? statusColors[curStat] : '#cbd5e1';\n  ctx.font = isStatus ? 'bold 9px monospace' : '9px monospace';\n  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText(cell, tblX + colW*ci + colW/2, tblY + 56);\n});\n\n// Status flow\nconst statFlow = statuses.map((s, i) => ({s, c: statusColors[i]}));\nstatFlow.forEach((sf, i) => {\n  const fx = cx - 120 + i * 120, fy = cy + 40;\n  const isActive = i === curStat;\n  ctx.fillStyle = isActive ? `${sf.c}25` : 'rgba(30,41,59,0.8)';\n  ctx.strokeStyle = isActive ? sf.c : '#334155'; ctx.lineWidth = isActive ? 3 : 1;\n  if (isActive) { ctx.save(); ctx.shadowColor = sf.c; ctx.shadowBlur = 12; }\n  ctx.beginPath(); ctx.roundRect(fx - 50, fy - 18, 100, 36, 8); ctx.fill(); ctx.stroke();\n  if (isActive) ctx.restore();\n  ctx.fillStyle = isActive ? sf.c : '#475569'; ctx.font = 'bold 10px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText(sf.s, fx, fy);\n  if (i < 2) {\n    ctx.fillStyle = '#475569'; ctx.font = '12px monospace';\n    ctx.fillText('→', fx + 60, fy);\n  }\n});\n\nctx.restore();\nreturn 280;"},
    {"name": "bk_hieu_tai_sao", "when": "Để hiểu tại sao, hãy đặt câu hỏi ngược lại: Nếu Apple hay Google cho b", "code": "ctx.save();\nconst cx = W/2, cy = cursorY + 140;\n\n// Fake apps scenario\nconst fakeApps = [\n  {x: cx - 200, y: cy - 60, icon: '🏦', name: 'Giả Vietcombank', color: '#ef4444'},\n  {x: cx, y: cy - 60, icon: '💳', name: 'Giả MoMo', color: '#ef4444'},\n  {x: cx + 200, y: cy - 60, icon: '💉', name: 'Giả Bộ Y Tế', color: '#ef4444'},\n];\n\nfakeApps.forEach((app, i) => {\n  const show = stepProgress > i * 0.2;\n  if (!show) return;\n  const shake = stepProgress > 0.6 ? Math.sin(time * 15 + i * 2) * 3 : 0;\n  ctx.save(); ctx.translate(shake, 0);\n  ctx.fillStyle = 'rgba(239,68,68,0.15)'; ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;\n  ctx.save(); ctx.shadowColor = '#ef4444'; ctx.shadowBlur = 12;\n  ctx.beginPath(); ctx.roundRect(app.x - 48, app.y - 48, 96, 96, 16); ctx.fill(); ctx.stroke(); ctx.restore();\n  ctx.fillStyle = '#ffffff'; ctx.font = '30px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText(app.icon, app.x, app.y - 14);\n  ctx.fillStyle = '#ef4444'; ctx.font = 'bold 8px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'top';\n  app.name.split(' ').forEach((word, wi) => ctx.fillText(word, app.x, app.y + 30 + wi * 12));\n  ctx.restore();\n});\n\n// Victim arrows down\nif (stepProgress > 0.5) {\n  fakeApps.forEach((app, i) => {\n    ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2; ctx.setLineDash([4,3]);\n    ctx.lineDashOffset = -time * 10;\n    ctx.beginPath(); ctx.moveTo(app.x, app.y + 50); ctx.lineTo(app.x, cy + 90); ctx.stroke(); ctx.setLineDash([]);\n  });\n}\n\n// User victim\nif (stepProgress > 0.55) {\n  ctx.fillStyle = '#ffffff'; ctx.font = '28px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';\n  ctx.fillText('😱', cx, cy + 105);\n  ctx.fillStyle = '#fbbf24'; ctx.font = 'bold 11px monospace';\n  ctx.fillText('Người dùng mất tiền!', cx, cy + 128);\n}\n\n// Big warning\nif (stepProgress > 0.75) {\n  const wPulse = 0.7 + 0.3 * Math.sin(time * 4);\n  ctx.fillStyle = `rgba(239,68,68,${wPulse})`; ctx.font = 'bold 14px monospace'; ctx.textAlign = 'center';\n  ctx.fillText('⚠️ App Store phải là PHÁO ĐÀI pháp lý!', cx, cy + 155);\n}\n\nctx.restore();\nreturn 280;"}]
